// --- Coincheck Client ---
class CoincheckClient {
  constructor(accessKey, secretKey) {
    this.accessKey = accessKey;
    this.secretKey = secretKey;
    this.baseUrl = "https://coincheck.com";
  }

  _sign(nonce, url, body = "") {
    const message = `${nonce}${url}${body}`;
    return crypto.createHmac("sha256", this.secretKey).update(message).digest("hex");
  }

  _headers(url, body = "") {
    const nonce = Date.now().toString();
    return {
      "ACCESS-KEY": this.accessKey,
      "ACCESS-NONCE": nonce,
      "ACCESS-SIGNATURE": this._sign(nonce, url, body),
      "Content-Type": "application/json",
    };
  }

  async getAccounts() {
    const http = getAxios();
    const url = `${this.baseUrl}/api/accounts/balance`;
    const response = await http.get(url, {
      headers: this._headers(url),
      timeout: 10000,
    });
    const data = response.data || {};
    const currencies = ["btc", "eth", "xrp", "ltc", "bch", "mona", "xlm", "qtum", "bat", "iost", "enj", "plt", "sand", "dot", "flr", "fnct", "dai", "wbtc", "avax", "shib", "matic"];
    const result = [];
    for (const c of currencies) {
      const balance = parseFloat(data[c] || "0");
      const reserved = parseFloat(data[`${c}_reserved`] || "0");
      if (balance > 0 || reserved > 0) {
        result.push({ currency: c.toUpperCase(), balance: String(balance), locked: String(reserved), avg_buy_price: "0" });
      }
    }
    const jpy = parseFloat(data.jpy || "0");
    if (jpy > 0) result.push({ currency: "JPY", balance: String(jpy), locked: String(parseFloat(data.jpy_reserved || "0")), avg_buy_price: "0" });
    return result;
  }

  async getTickers() {
    const http = getAxios();
    const response = await http.get(`${this.baseUrl}/api/rate/all`, { timeout: 10000 });
    const data = response.data || {};
    return Object.entries(data).map(([pair, rate]) => ({
      market: `JPY-${pair.replace("_jpy", "").toUpperCase()}`,
      trade_price: parseFloat(rate || "0"),
      _baseCurrency: "JPY",
    }));
  }
}

// --- Coinone Client ---
class CoinoneClient {
  constructor(accessKey, secretKey) {
    this.accessKey = accessKey;
    this.secretKey = secretKey;
    this.baseUrl = "https://api.coinone.co.kr";
  }

  _sign(payload) {
    const encoded = Buffer.from(JSON.stringify(payload)).toString("base64");
    const sig = crypto.createHmac("sha512", this.secretKey.toUpperCase()).update(encoded).digest("hex");
    return { encoded, sig };
  }

  async getAccounts() {
    const http = getAxios();
    const payload = { access_token: this.accessKey, nonce: Date.now() };
    const { encoded, sig } = this._sign(payload);
    const response = await http.post(`${this.baseUrl}/v2.1/account/balance/all`, encoded, {
      headers: {
        "Content-Type": "application/json",
        "X-COINONE-PAYLOAD": encoded,
        "X-COINONE-SIGNATURE": sig,
      },
      timeout: 10000,
    });
    const balances = response.data?.balances || {};
    return Object.entries(balances)
      .filter(([, v]) => parseFloat(v?.available || "0") > 0)
      .map(([currency, v]) => ({
        currency: currency.toUpperCase(),
        balance: v.available || "0",
        locked: String((parseFloat(v.balance || "0") - parseFloat(v.available || "0")).toFixed(8)),
        avg_buy_price: "0",
      }));
  }

  async getTickers() {
    const http = getAxios();
    const response = await http.get(`${this.baseUrl}/public/v2/ticker_new/KRW`, { timeout: 10000 });
    const tickers = response.data?.tickers || [];
    return tickers.map(t => ({
      market: `KRW-${t.target_currency}`,
      trade_price: parseFloat(t.last || "0"),
      _baseCurrency: "KRW",
    }));
  }
}

// --- Crypto.com Client ---
class CryptocomClient {
  constructor(accessKey, secretKey, passphrase) {
    this.accessKey = accessKey;
    this.secretKey = secretKey;
    this.passphrase = passphrase; // not used in v2 but kept for compatibility
    this.baseUrl = "https://api.crypto.com/exchange/v1";
  }

  _sign(method, id, params, nonce) {
    const sortedParams = params ? Object.keys(params).sort().reduce((acc, key) => { acc[key] = params[key]; return acc; }, {}) : {};
    const paramString = Object.entries(sortedParams).map(([k, v]) => `${k}${v}`).join("");
    const sigPayload = `${method}${id}${this.accessKey}${paramString}${nonce}`;
    return crypto.createHmac("sha256", this.secretKey).update(sigPayload).digest("hex");
  }

  async getAccounts() {
    const http = getAxios();
    const id = Date.now();
    const nonce = Date.now();
    const method = "private/user-balance";
    const sig = this._sign(method, id, {}, nonce);
    const response = await http.post(`${this.baseUrl}/${method}`, {
      id, method, api_key: this.accessKey, params: {}, sig, nonce,
    }, { timeout: 10000 });
    const positions = response.data?.result?.data?.[0]?.position_balances || [];
    return positions
      .filter(p => parseFloat(p.quantity) > 0)
      .map(p => ({
        currency: p.instrument_name?.replace("USD_", "") || p.instrument_name,
        balance: String(parseFloat(p.quantity) - parseFloat(p.reserved_qty || "0")),
        locked: p.reserved_qty || "0",
        avg_buy_price: "0",
      }));
  }

  async getTickers() {
    const http = getAxios();
    const response = await http.get("https://api.crypto.com/exchange/v1/public/get-tickers", { timeout: 10000 });
    const data = response.data?.result?.data || [];
    return data
      .filter(t => t.i?.endsWith("_USDT"))
      .map(t => ({
        market: `USDT-${t.i.replace("_USDT", "")}`,
        trade_price: parseFloat(t.a || "0"),
        _baseCurrency: "USDT",
      }));
  }
}

// =============================================================================
// EXCHANGE CLIENT FACTORY
// =============================================================================

/**
 * Create an exchange client based on exchange name
 * @param {string} exchange Exchange identifier
 * @param {string} accessKey API access key
 * @param {string} secretKey API secret key
 * @param {string|null} passphrase API passphrase (Bitget, OKX, KuCoin)
 * @return {object} Exchange client instance
 */
function createExchangeClient(exchange, accessKey, secretKey, passphrase = null) {
  switch (exchange) {
    case "upbit": return new UpbitClient(accessKey, secretKey);
    case "bithumb": return new BithumbClient(accessKey, secretKey);
    case "binance": return new BinanceClient(accessKey, secretKey);
    case "bybit": return new BybitClient(accessKey, secretKey);
    case "bitget": return new BitgetClient(accessKey, secretKey, passphrase);
    case "okx": return new OkxClient(accessKey, secretKey, passphrase);
    case "kucoin": return new KucoinClient(accessKey, secretKey, passphrase);
    case "mexc": return new MexcClient(accessKey, secretKey);
    case "bitkub": return new BitkubClient2(accessKey, secretKey);
    case "coinbase": return new CoinbaseClient(accessKey, secretKey);
    case "bitflyer": return new BitflyerClient(accessKey, secretKey);
    case "gmo": return new GmoClient(accessKey, secretKey);
    case "coincheck": return new CoincheckClient(accessKey, secretKey);
    case "coinone": return new CoinoneClient(accessKey, secretKey);
    case "cryptocom": return new CryptocomClient(accessKey, secretKey, passphrase);
    default: throw new Error(`Unsupported exchange: ${exchange}`);
  }
}

/**
 * Check if exchange requires a passphrase
 * @param {string} exchange
 * @return {boolean}
 */
function exchangeRequiresPassphrase(exchange) {
  return ["bitget", "okx", "kucoin"].includes(exchange);
}

// =============================================================================
// VALIDATE CEX API KEY (supports all exchanges)
// =============================================================================

/**
 * Validate a CEX API key by attempting a balance query
 * @param {string} exchange Exchange identifier
 * @param {string} accessKey
 * @param {string} secretKey
 * @param {string|null} passphrase
 * @return {Promise<{success: boolean, error?: string}>}
 */
async function validateCexApiKey(exchange, accessKey, secretKey, passphrase = null) {
  try {
    const client = createExchangeClient(exchange, accessKey, secretKey, passphrase);
    await client.getAccounts();
    return { success: true };
  } catch (error) {
    const status = error.response?.status;
    const msg = error.response?.data?.error?.message ||
      error.response?.data?.msg ||
      error.response?.data?.message ||
      error.message;
    if (status === 401 || status === 403) {
      return { success: false, error: "Invalid API key, secret, or passphrase." };
    }
    return { success: false, error: `Validation failed: ${msg}` };
  }
}

// =============================================================================
// PORTFOLIO SYNC ENGINE
// =============================================================================

/**
 * Perform portfolio sync for a single credential
 * @param {string} uid - Firebase user ID
 * @param {string} credentialId - Credential document ID
 * @return {Promise<object>} Snapshot data
 */
async function performCexSync(uid, credentialId) {
  const credDoc = await db.doc(`users/${uid}/cex_credentials/${credentialId}`).get();
  if (!credDoc.exists) throw new Error("Credential not found.");
  const cred = credDoc.data();

  // Decrypt keys
  const accessKey = cexDecrypt(
    cred.encryptedAccessKey, cred.accessKeyIv, cred.accessKeyAuthTag,
  );
  const secretKey = cexDecrypt(
    cred.encryptedSecretKey, cred.secretKeyIv, cred.secretKeyAuthTag,
  );

  // Decrypt passphrase if present
  let passphrase = null;
  if (cred.encryptedPassphrase) {
    passphrase = cexDecrypt(
      cred.encryptedPassphrase, cred.passphraseIv, cred.passphraseAuthTag,
    );
  }

  // Create exchange client via factory
  const client = createExchangeClient(cred.exchange, accessKey, secretKey, passphrase);
  const capabilities = EXCHANGE_CAPABILITIES[cred.exchange] || { spot: true, futures: false, margin: false, baseCurrency: "KRW" };
  const baseCurrency = capabilities.baseCurrency;

  const startTime = Date.now();

  // 1. Fetch exchange rates
  const rates = await getExchangeRates();
  const USD_KRW_RATE = rates.USDT_KRW || 1400;
  const THB_KRW_RATE = rates.THB_KRW || 40;
  const FIAT_USD_KRW_RATE = rates.USD_KRW || 1380;
  const JPY_KRW_RATE = rates.JPY_KRW || 9.5;

  // 2. Fetch balances
  const accounts = await client.getAccounts();

  // 3. Filter non-zero assets
  const nonZeroAssets = accounts.filter((a) =>
    parseFloat(a.balance || "0") > 0 || parseFloat(a.locked || "0") > 0,
  );

  // 4. Fetch tickers
  const stablecoins = ["KRW", "USDT", "USDC", "BUSD", "DAI", "THB", "USD", "JPY"];
  const tickerSymbols = nonZeroAssets
    .filter((a) => !stablecoins.includes(a.currency.toUpperCase()))
    .map((a) => {
      if (baseCurrency === "KRW") return `KRW-${a.currency}`;
      if (baseCurrency === "THB") return `THB-${a.currency}`;
      if (baseCurrency === "USD") return `USD-${a.currency}`;
      if (baseCurrency === "JPY") return `JPY-${a.currency}`;
      return `USDT-${a.currency}`;
    });

  let tickers = [];
  if (tickerSymbols.length > 0) {
    try {
      tickers = await client.getTickers(tickerSymbols);
    } catch (tickerErr) {
      console.warn(`[CEX] Ticker fetch partial failure:`, tickerErr.message);
    }
  }

  const tickerMap = {};
  tickers.forEach((t) => {
    const marketStr = t.market || "";
    let currency;
    if (baseCurrency === "KRW") {
      currency = marketStr.replace("KRW-", "");
    } else if (baseCurrency === "THB") {
      currency = marketStr.replace("THB-", "");
    } else if (baseCurrency === "USD") {
      currency = marketStr.replace("USD-", "");
    } else if (baseCurrency === "JPY") {
      currency = marketStr.replace("JPY-", "");
    } else {
      currency = marketStr.replace("USDT-", "");
    }
    tickerMap[currency] = t;
  });

  // 5. Build asset list with multi-currency support
  let totalValueKrw = 0;
  const assets = nonZeroAssets.map((a) => {
    const balance = parseFloat(a.balance || "0");
    const locked = parseFloat(a.locked || "0");
    const avgBuyPrice = parseFloat(a.avg_buy_price || a.average_purchase_price || "0");
    const totalBalance = balance + locked;

    let currentPriceKrw = 0;
    const currencyUpper = a.currency.toUpperCase();

    if (currencyUpper === "KRW") {
      currentPriceKrw = 1;
    } else if (currencyUpper === "USDT" || currencyUpper === "USDC" || currencyUpper === "BUSD" || currencyUpper === "DAI") {
      currentPriceKrw = USD_KRW_RATE;
    } else if (currencyUpper === "THB") {
      currentPriceKrw = THB_KRW_RATE;
    } else if (currencyUpper === "USD") {
      currentPriceKrw = FIAT_USD_KRW_RATE;
    } else if (currencyUpper === "JPY") {
      currentPriceKrw = JPY_KRW_RATE;
    } else if (tickerMap[a.currency]) {
      const tickerPrice = tickerMap[a.currency].trade_price ||
        tickerMap[a.currency].closing_price || 0;
      // Convert ticker price to KRW based on base currency
      if (baseCurrency === "KRW") {
        currentPriceKrw = tickerPrice;
      } else if (baseCurrency === "THB") {
        currentPriceKrw = tickerPrice * THB_KRW_RATE;
      } else if (baseCurrency === "USD") {
        currentPriceKrw = tickerPrice * FIAT_USD_KRW_RATE;
      } else if (baseCurrency === "JPY") {
        currentPriceKrw = tickerPrice * JPY_KRW_RATE;
      } else {
        // USDT base
        currentPriceKrw = tickerPrice * USD_KRW_RATE;
      }
    }

    const valueKrw = totalBalance * currentPriceKrw;
    const valueUsd = valueKrw / USD_KRW_RATE;

    // For KRW-based exchanges, avgBuyPrice is in KRW
    // For USDT-based exchanges, avgBuyPrice is in USDT (convert to KRW)
    let avgBuyPriceKrw = avgBuyPrice;
    if (baseCurrency === "USDT" && avgBuyPrice > 0) {
      avgBuyPriceKrw = avgBuyPrice * USD_KRW_RATE;
    } else if (baseCurrency === "THB" && avgBuyPrice > 0) {
      avgBuyPriceKrw = avgBuyPrice * THB_KRW_RATE;
    } else if (baseCurrency === "USD" && avgBuyPrice > 0) {
      avgBuyPriceKrw = avgBuyPrice * FIAT_USD_KRW_RATE;
    } else if (baseCurrency === "JPY" && avgBuyPrice > 0) {
      avgBuyPriceKrw = avgBuyPrice * JPY_KRW_RATE;
    }

    const costBasis = totalBalance * avgBuyPriceKrw;
    const profitLoss = stablecoins.includes(currencyUpper) ? 0 : (valueKrw - costBasis);
    const profitLossPercent = (!stablecoins.includes(currencyUpper) && costBasis > 0) ?
      ((valueKrw - costBasis) / costBasis) * 100 : 0;

    totalValueKrw += valueKrw;

    return {
      currency: a.currency,
      balance: totalBalance,
      locked,
      avgBuyPrice: avgBuyPriceKrw,
      currentPrice: currentPriceKrw,
      currentPriceUsd: currentPriceKrw / USD_KRW_RATE,
      valueKrw,
      valueUsd,
      profitLoss,
      profitLossPercent,
      allocationPercent: 0,
    };
  });

  // Calculate allocation
  assets.forEach((a) => {
    a.allocationPercent = totalValueKrw > 0 ?
      (a.valueKrw / totalValueKrw) * 100 : 0;
  });

  // Sort by value descending
  assets.sort((a, b) => b.valueKrw - a.valueKrw);

  const totalProfitLoss = assets
    .filter((a) => !stablecoins.includes(a.currency.toUpperCase()))
    .reduce((sum, a) => sum + a.profitLoss, 0);
  const totalCostBasis = assets
    .filter((a) => !stablecoins.includes(a.currency.toUpperCase()))
    .reduce((sum, a) => sum + (a.balance * a.avgBuyPrice), 0);

  // 6. Fetch Futures data (if supported)
  let futuresPositions = [];
  let futuresBalance = null;
  if (capabilities.futures && typeof client.getFuturesPositions === "function") {
    try {
      const rawPositions = await client.getFuturesPositions();
      futuresPositions = rawPositions.map((p) => ({
        symbol: p.symbol || p.instId || p.pair || "",
        side: p.positionSide || p.side || p.posSide || "BOTH",
        size: parseFloat(p.positionAmt || p.size || p.pos || p.total || "0"),
        entryPrice: parseFloat(p.entryPrice || p.avgPrice || p.avgCost || "0"),
        markPrice: parseFloat(p.markPrice || p.mark_price || "0"),
        unrealizedPnl: parseFloat(p.unRealizedProfit || p.unrealisedPnl || p.upl || p.unrealizedPnl || "0"),
        leverage: parseFloat(p.leverage || "1"),
        marginMode: p.marginType || p.tradeMode || p.marginMode || "cross",
      }));
      console.log(`[CEX] Fetched ${futuresPositions.length} futures positions for ${cred.exchange}`);
    } catch (futErr) {
      console.warn(`[CEX] Futures position fetch failed for ${cred.exchange}:`, futErr.message);
    }

    if (typeof client.getFuturesBalance === "function") {
      try {
        futuresBalance = await client.getFuturesBalance();
      } catch (futBalErr) {
        console.warn(`[CEX] Futures balance fetch failed for ${cred.exchange}:`, futBalErr.message);
      }
    }
  }

  // 7. Save snapshot (overwrite per credentialId)
  const snapshotData = {
    exchange: cred.exchange,
    credentialId,
    assets,
    totalValueKrw,
    totalValueUsd: totalValueKrw / USD_KRW_RATE,
    totalProfitLoss,
    totalProfitLossPercent: totalCostBasis > 0 ?
      (totalProfitLoss / totalCostBasis) * 100 : 0,
    capabilities,
    futuresPositions,
    futuresBalance,
    snapshotAt: admin.firestore.FieldValue.serverTimestamp(),
    syncDurationMs: Date.now() - startTime,
  };

  await db.doc(`users/${uid}/cex_snapshots/${credentialId}`).set(snapshotData);

  // 8. Update credential status
  await credDoc.ref.update({
    lastSyncAt: admin.firestore.FieldValue.serverTimestamp(),
    lastSyncStatus: "success",
    status: "active",
    statusMessage: "",
  });

  return snapshotData;
}

