// ADMIN CEX STATISTICS (onCall)
// =============================================================================

/**
 * Get CEX portfolio usage statistics for admin dashboard.
 * Requires admin role.
 */
exports.getAdminCexStats = onCall({
  ...cexFunctionConfig,
}, async (request) => {
  if (!request.auth) {
    throw new HttpsError("unauthenticated", "Login required.");
  }
  const uid = request.auth.uid;

  // Verify admin role
  const userEmail = request.auth.token?.email;
  if (!userEmail) {
    throw new HttpsError("permission-denied", "Admin access required.");
  }
  const adminDoc = await db.collection("users").doc(userEmail.toLowerCase()).get();
  if (!adminDoc.exists || adminDoc.data().role !== "admin") {
    throw new HttpsError("permission-denied", "Admin access required.");
  }

  console.log(`[AdminCEX] Fetching CEX statistics for admin ${userEmail}`);

  try {
    // 1. Fetch ALL users who have cex_credentials subcollection
    const usersSnap = await db.collection("users").get();
    const userList = [];

    for (const userDoc of usersSnap.docs) {
      const credSnap = await db.collection(`users/${userDoc.id}/cex_credentials`).get();
      if (credSnap.empty) continue;

      const userData = userDoc.data();
      const credentials = [];

      for (const credDoc of credSnap.docs) {
        const cred = credDoc.data();
        credentials.push({
          id: credDoc.id,
          exchange: cred.exchange,
          label: cred.label || "",
          status: cred.status || "unknown",
          registeredAt: cred.registeredAt?.toDate?.()?.toISOString() || null,
          lastSyncAt: cred.lastSyncAt?.toDate?.()?.toISOString() || null,
          lastSyncStatus: cred.lastSyncStatus || "never",
        });
      }

      // Fetch the latest snapshot for portfolio value
      const snapshotSnap = await db.collection(`users/${userDoc.id}/cex_snapshots`).get();
      let totalValueKrw = 0;
      let totalValueUsd = 0;
      let assetCount = 0;
      let lastSyncTime = null;
      const snapshotAssets = [];

      for (const snapDoc of snapshotSnap.docs) {
        const snap = snapDoc.data();
        totalValueKrw += snap.totalValueKrw || 0;
        totalValueUsd += snap.totalValueUsd || 0;
        const snapTime = snap.snapshotAt?.toDate?.();
        if (snapTime && (!lastSyncTime || snapTime > lastSyncTime)) {
          lastSyncTime = snapTime;
        }
        if (snap.assets && Array.isArray(snap.assets)) {
          assetCount += snap.assets.filter((a) => a.currency !== "KRW").length;
          snap.assets.forEach((a) => snapshotAssets.push(a));
        }
      }

      // Fetch quant agents if subcollection exists
      const quantAgents = [];
      try {
        const quantSnap = await db.collection(`users/${userDoc.id}/quant_agents`).get();
        quantSnap.forEach((qDoc) => {
          const q = qDoc.data();
          quantAgents.push({
            name: q.name || "Agent",
            strategy: q.strategyName || q.strategyTemplateId || "Custom",
            status: q.status || "unknown",
            assets: q.selectedAssets || [],
            startedAt: q.createdAt?.toDate?.()?.toISOString() || q.createdAt || null,
          });
        });
      } catch (_) { /* no quant_agents subcollection */ }

      const exchanges = [...new Set(credentials.map((c) => c.exchange))];
      const multiExchange = exchanges.length >= 2;
      const quantActiveAgents = quantAgents.filter((a) => a.status === "active");
      const quantStatus = quantActiveAgents.length > 0 ? "active" : (quantAgents.length > 0 ? "paused" : "none");

      // Activity status based on last sync
      const now30d = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
      const now7d = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
      let activityStatus = "at_risk";
      if (lastSyncTime && lastSyncTime >= now7d) activityStatus = "active";
      else if (lastSyncTime && lastSyncTime >= now30d) activityStatus = "idle";

      // Sync count in last 30 days (count credentials synced recently)
      const syncCount30d = credentials.filter((c) => {
        if (!c.lastSyncAt) return false;
        return new Date(c.lastSyncAt) >= now30d;
      }).length;

      userList.push({
        email: userDoc.id,
        name: userData.name || "",
        walletAddress: userData.walletAddress || "",
        credentials,
        exchangeCount: credentials.length,
        exchanges,
        multiExchange,
        totalValueKrw,
        totalValueUsd,
        assetCount,
        lastSync: lastSyncTime?.toISOString() || null,
        registeredAt: credentials[0]?.registeredAt || null,
        status: credentials.some((c) => c.status === "active") ? "active" : "inactive",
        assets: snapshotAssets,
        quantStatus,
        quantAgents,
        activityStatus,
        syncCount30d,
      });
    }

    // 2. Compute aggregate statistics
    const totalUsers = userList.length;
    const activeUsers = userList.filter((u) => u.status === "active").length;
    const totalCredentials = userList.reduce((sum, u) => sum + u.exchangeCount, 0);
    const totalAumKrw = userList.reduce((sum, u) => sum + u.totalValueKrw, 0);
    const totalAumUsd = userList.reduce((sum, u) => sum + u.totalValueUsd, 0);

    // Exchange breakdown
    const exchangeBreakdown = {};
    userList.forEach((u) => {
      u.credentials.forEach((c) => {
        if (!exchangeBreakdown[c.exchange]) {
          exchangeBreakdown[c.exchange] = { connections: 0, active: 0 };
        }
        exchangeBreakdown[c.exchange].connections++;
        if (c.status === "active") exchangeBreakdown[c.exchange].active++;
      });
    });

    // Exchange AUM
    const exchangeAum = {};
    userList.forEach((u) => {
      u.assets.forEach((a) => {
        // Aggregate AUM by exchange from credentials
      });
      u.credentials.forEach((c) => {
        if (!exchangeAum[c.exchange]) exchangeAum[c.exchange] = 0;
      });
    });

    // Top coins across all users
    const coinMap = {};
    userList.forEach((u) => {
      u.assets.forEach((a) => {
        if (a.currency === "KRW") return;
        if (!coinMap[a.currency]) {
          coinMap[a.currency] = { symbol: a.currency, holders: 0, totalValueKrw: 0, totalBalance: 0 };
        }
        coinMap[a.currency].totalValueKrw += a.valueKrw || 0;
        coinMap[a.currency].totalBalance += a.balance || 0;
      });
    });
    // Count unique holders per coin
    userList.forEach((u) => {
      const seenCoins = new Set();
      u.assets.forEach((a) => {
        if (a.currency !== "KRW" && !seenCoins.has(a.currency)) {
          seenCoins.add(a.currency);
          if (coinMap[a.currency]) coinMap[a.currency].holders++;
        }
      });
    });
    const topCoins = Object.values(coinMap)
      .sort((a, b) => b.totalValueKrw - a.totalValueKrw)
      .slice(0, 20);

    // Asset size distribution
    const sizeDistribution = {
      under1m: 0, // < 1,000,000 KRW
      m1to5m: 0, // 1M ~ 5M
      m5to10m: 0, // 5M ~ 10M
      m10to50m: 0, // 10M ~ 50M
      m50to100m: 0, // 50M ~ 100M
      over100m: 0, // > 100M
    };
    userList.forEach((u) => {
      const v = u.totalValueKrw;
      if (v < 1000000) sizeDistribution.under1m++;
      else if (v < 5000000) sizeDistribution.m1to5m++;
      else if (v < 10000000) sizeDistribution.m5to10m++;
      else if (v < 50000000) sizeDistribution.m10to50m++;
      else if (v < 100000000) sizeDistribution.m50to100m++;
      else sizeDistribution.over100m++;
    });

    // Recent registrations (last 7 days)
    const now = new Date();
    const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    const recentRegistrations = userList.filter((u) => {
      if (!u.registeredAt) return false;
      return new Date(u.registeredAt) >= weekAgo;
    }).length;

    // Today's registrations
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const todayRegistrations = userList.filter((u) => {
      if (!u.registeredAt) return false;
      return new Date(u.registeredAt) >= todayStart;
    }).length;

    // ── New aggregate stats ──
    const multiExchangeUsers = userList.filter((u) => u.multiExchange).length;
    const quantActiveUsers = userList.filter((u) => u.quantStatus === "active").length;
    const weeklyActiveUsers = userList.filter((u) => u.activityStatus === "active").length;
    const monthlyActiveUsers = userList.filter((u) => u.activityStatus !== "at_risk").length;
    const atRiskUsers = userList.filter((u) => u.activityStatus === "at_risk").length;

    // Strategy usage breakdown
    const strategyMap = {};
    userList.forEach((u) => {
      u.quantAgents.forEach((a) => {
        if (!strategyMap[a.strategy]) strategyMap[a.strategy] = { name: a.strategy, users: 0, active: 0 };
        strategyMap[a.strategy].users++;
        if (a.status === "active") strategyMap[a.strategy].active++;
      });
    });
    const strategyUsage = Object.values(strategyMap).sort((a, b) => b.users - a.users);

    // Strip assets from user list to reduce payload size
    const usersSummary = userList.map((u) => ({
      email: u.email,
      name: u.name,
      walletAddress: u.walletAddress,
      exchanges: u.exchanges,
      exchangeCount: u.exchangeCount,
      credentials: u.credentials,
      totalValueKrw: u.totalValueKrw,
      totalValueUsd: u.totalValueUsd,
      assetCount: u.assetCount,
      lastSync: u.lastSync,
      registeredAt: u.registeredAt,
      status: u.status,
      multiExchange: u.multiExchange,
      quantStatus: u.quantStatus,
      quantAgents: u.quantAgents,
      activityStatus: u.activityStatus,
      syncCount30d: u.syncCount30d,
    }));

    return {
      overview: {
        totalUsers,
        activeUsers,
        inactiveUsers: totalUsers - activeUsers,
        totalCredentials,
        totalAumKrw,
        totalAumUsd,
        recentRegistrations,
        todayRegistrations,
        multiExchangeUsers,
        quantActiveUsers,
        weeklyActiveUsers,
        monthlyActiveUsers,
        atRiskUsers,
      },
      exchangeBreakdown,
      topCoins,
      sizeDistribution,
      strategyUsage,
      users: usersSummary,
    };
  } catch (err) {
    console.error("[AdminCEX] Failed to get stats:", err);
    throw new HttpsError("internal", "Failed to fetch CEX statistics.");
  }
});

// =============================================================================
// BACKFILL RP - One-time admin function to retroactively award RP
// =============================================================================
const RP_PER_REFERRAL_BF = 10;
const RP_LEVELUP_BONUS_BF = 100;
const LEVELUP_INTERVAL_BF = 10;

function calcLevelFromRefs(count) {
  return Math.min(Math.floor((1 + Math.sqrt(1 + 8 * count)) / 2), 100);
}

exports.backfillRP = onRequest({ cors: true, invoker: "public", timeoutSeconds: 300 }, async (req, res) => {
  res.set("Access-Control-Allow-Origin", "*");
  res.set("Access-Control-Allow-Methods", "POST, OPTIONS");
  res.set("Access-Control-Allow-Headers", "Content-Type");

  if (req.method === "OPTIONS") return res.status(204).send("");
  if (req.method !== "POST") return res.status(405).json({ error: "Method not allowed" });

  // Simple admin protection
  const { adminKey, dryRun } = req.body;
  if (adminKey !== "visionchain-backfill-2026") {
    return res.status(403).json({ error: "Unauthorized" });
  }

  try {
    const usersSnapshot = await db.collection("users").get();
    console.log(`[RP Backfill] Total users: ${usersSnapshot.size}`);

    let processed = 0;
    let awarded = 0;
    let skipped = 0;
    let totalRPAwarded = 0;
    const details = [];

    for (const userDoc of usersSnapshot.docs) {
      const userData = userDoc.data();
      const email = userDoc.id;
      const referralCount = userData.referralCount || 0;

      if (referralCount <= 0) {
        skipped++;
        continue;
      }

      processed++;

      // Calculate expected referral RP
      const referralRP = referralCount * RP_PER_REFERRAL_BF;

      // Calculate level & level-up bonuses
      const currentLevel = calcLevelFromRefs(referralCount);
      let levelupRP = 0;
      for (let lvl = 1; lvl <= currentLevel; lvl++) {
        if (lvl % LEVELUP_INTERVAL_BF === 0) {
          levelupRP += RP_LEVELUP_BONUS_BF;
        }
      }

      const expectedTotalRP = referralRP + levelupRP;

      // Check existing RP
      const rpDocSnap = await db.collection("user_reward_points").doc(email).get();
      const existingRP = rpDocSnap.exists ? (rpDocSnap.data().totalRP || 0) : 0;
      const existingAvailable = rpDocSnap.exists ? (rpDocSnap.data().availableRP || 0) : 0;

      const rpToAward = expectedTotalRP - existingRP;

      if (rpToAward <= 0) {
        skipped++;
        details.push({ email, referrals: referralCount, level: currentLevel, existing: existingRP, expected: expectedTotalRP, awarded: 0, status: "SKIP" });
        continue;
      }

      const backfillReferralRP = Math.max(0, referralRP - existingRP);
      const backfillLevelupRP = rpToAward - Math.max(0, backfillReferralRP);

      if (!dryRun) {
        const now = new Date().toISOString();

        // Add referral RP history
        if (backfillReferralRP > 0) {
          await db.collection("rp_history").add({
            userId: email,
            type: "referral",
            amount: backfillReferralRP,
            source: `Backfill: ${referralCount} referrals`,
            timestamp: now,
          });
        }

        // Add level-up RP history
        if (backfillLevelupRP > 0) {
          await db.collection("rp_history").add({
            userId: email,
            type: "levelup",
            amount: backfillLevelupRP,
            source: `Backfill: Level milestones up to LVL ${currentLevel}`,
            timestamp: now,
          });
        }

        // Update user_reward_points
        if (rpDocSnap.exists) {
          await db.collection("user_reward_points").doc(email).update({
            totalRP: existingRP + rpToAward,
            availableRP: existingAvailable + rpToAward,
            updatedAt: now,
          });
        } else {
          await db.collection("user_reward_points").doc(email).set({
            userId: email,
            totalRP: rpToAward,
            claimedRP: 0,
            availableRP: rpToAward,
            createdAt: now,
            updatedAt: now,
          });
        }
      }

      awarded++;
      totalRPAwarded += rpToAward;
      details.push({
        email,
        referrals: referralCount,
        level: currentLevel,
        existing: existingRP,
        expected: expectedTotalRP,
        awarded: rpToAward,
        refRP: backfillReferralRP,
        lvlRP: backfillLevelupRP,
        status: dryRun ? "WOULD_AWARD" : "AWARDED",
      });

      console.log(`[RP Backfill] ${email}: ${referralCount} refs, LVL ${currentLevel}, +${rpToAward} RP`);
    }

    console.log(`[RP Backfill] Complete: processed=${processed}, awarded=${awarded}, skipped=${skipped}, totalRP=${totalRPAwarded}`);

    return res.status(200).json({
      success: true,
      dryRun: !!dryRun,
      summary: { processed, awarded, skipped, totalRPAwarded },
      details,
    });
  } catch (err) {
    console.error("[RP Backfill] Failed:", err);
    return res.status(500).json({ error: err.message || "Backfill failed" });
  }
});

// =============================================================================
// AGENT GATEWAY - AI Agent Onboarding & Interaction API
// =============================================================================
// Unified endpoint for AI agents from Moltbook, OpenClaw, etc.
// Actions: register, balance, transfer, referral, leaderboard, profile
// =============================================================================

const AGENT_FAUCET_AMOUNT = "100"; // 100 VCN initial funding

/**
 * Generate a unique API key for an agent
 * @return {string} API key prefixed with vcn_
 */
function generateAgentApiKey() {
  return "vcn_" + crypto.randomBytes(24).toString("hex");
}

/**
 * Generate a referral code for an agent
 * @param {string} agentName - Agent name
 * @return {string} Referral code
 */
function generateAgentReferralCode(agentName) {
  const suffix = crypto.randomBytes(3).toString("hex").toUpperCase();
  const prefix = agentName.replace(/[^a-zA-Z0-9]/g, "").slice(0, 8).toUpperCase();
  return `AGENT_${prefix}_${suffix}`;
}

/**
 * Authenticate agent by API key
 * @param {string} apiKey - Agent API key
 * @return {object|null} Agent data or null
 */
async function authenticateAgent(apiKey) {
  if (!apiKey || !apiKey.startsWith("vcn_")) return null;
  const snap = await db.collection("agents")
    .where("apiKey", "==", apiKey)
    .limit(1)
    .get();
  if (snap.empty) return null;
  const doc = snap.docs[0];
  return { id: doc.id, ...doc.data() };
}

/**
 * Authenticate a Firebase user via ID token for Agent Gateway.
 * Returns a user-context object compatible with agent context.
 * @param {string} idToken - Firebase ID token
 * @returns {Promise<object|null>} User context or null
 */
// Secondary Firebase Admin for cross-project token verification (staging <-> production)
let prodAdminApp = null;
function getProdAdmin() {
  if (!prodAdminApp) {
    const currentProject = process.env.GCLOUD_PROJECT || process.env.GCP_PROJECT || "";
    const prodProjectId = "visionchain-d19ed";
    if (currentProject === prodProjectId) return null; // Already production
    try {
      prodAdminApp = admin.initializeApp({ projectId: prodProjectId }, "prod-auth");
    } catch (e) {
      if (e.code === "app/duplicate-app") {
        prodAdminApp = admin.app("prod-auth");
      }
    }
  }
  return prodAdminApp;
}

async function authenticateFirebaseUser(idToken) {
  try {
    let decoded;
    try {
      decoded = await admin.auth().verifyIdToken(idToken);
    } catch (primaryErr) {
      // If audience mismatch, try production Firebase Auth
      if (primaryErr.code === "auth/argument-error" || primaryErr.message?.includes("audience")) {
        const prodApp = getProdAdmin();
        if (prodApp) {
          decoded = await prodApp.auth().verifyIdToken(idToken);
          console.log("[Agent Gateway] Token verified via production Firebase Auth fallback");
        } else {
          throw primaryErr;
        }
      } else {
        throw primaryErr;
      }
    }
    const uid = decoded.uid;
    const email = decoded.email || "";

    // Look up user doc to get walletAddress
    const userDoc = await db.collection("users").doc(uid).get();
    if (!userDoc.exists) {
      // Try by email
      const emailSnap = await db.collection("users")
        .where("email", "==", email.toLowerCase())
        .limit(1)
        .get();
      if (emailSnap.empty) return null;
      const userData = emailSnap.docs[0].data();
      return {
        id: emailSnap.docs[0].id,
        _isUser: true,
        uid: uid,
        email: email.toLowerCase(),
        walletAddress: userData.walletAddress || "",
        displayName: userData.displayName || email.split("@")[0],
      };
    }

    const userData = userDoc.data();
    return {
      id: uid,
      _isUser: true,
      uid: uid,
      email: (userData.email || email).toLowerCase(),
      walletAddress: userData.walletAddress || "",
      displayName: userData.displayName || email.split("@")[0],
    };
  } catch (err) {
    console.warn("[Agent Gateway] Firebase auth failed:", err.message);
    return null;
  }
}

let _gwPricingCache = null;
let _gwPricingCacheAt = 0;

// ── RP Config: Reads per-action RP amounts from Firestore config/rp_rewards ──
const RP_DEFAULTS = {
  referral: 10, levelup: 100,
  agent_transfer_send: 5, agent_transfer_batch: 5,
  agent_staking_deposit: 20, agent_staking_unstake: 5,
  agent_staking_claim: 10, agent_staking_withdraw: 10,
  agent_staking_compound: 25, agent_bridge_initiate: 15,
  agent_nft_mint: 30, agent_referral_inviter: 50, agent_referral_invitee: 25,
  mobile_node_daily: 5,
  referral_rp_tier1_rate: 0.10,
  referral_rp_tier2_rate: 0.02,
};
let _rpCfg = null;
let _rpCfgAt = 0;
async function getRPConfig() {
  if (_rpCfg && Date.now() - _rpCfgAt < 5 * 60 * 1000) return _rpCfg;
  try {
    const snap = await admin.firestore().collection("config").doc("rp_rewards").get();
    _rpCfg = snap.exists ? { ...RP_DEFAULTS, ...snap.data() } : { ...RP_DEFAULTS };
    _rpCfgAt = Date.now();
    return _rpCfg;
  } catch (e) {
    console.warn("[RP] Config load failed:", e.message);
    return { ...RP_DEFAULTS };
  }
}

/**
 * Server-side RP award with referral propagation (mirrors client addRewardPoints).
 * Awards RP to a user and propagates to Tier 1 & Tier 2 referrers.
 * @param {string} email - User email
 * @param {number} amount - RP amount
 * @param {string} type - RP action type
 * @param {string} source - Description
 * @param {object} rpCfg - RP config (from getRPConfig)
 */
async function serverAddRewardPoints(email, amount, type, source, rpCfg) {
  if (!email || amount <= 0) return;
  const db2 = admin.firestore();
  const now = new Date().toISOString();
  try {
    // 1. Award RP to user
    const rpRef = db2.collection("user_reward_points").doc(email);
    const rpSnap = await rpRef.get();
    if (rpSnap.exists) {
      await rpRef.update({
        totalRP: admin.firestore.FieldValue.increment(amount),
        availableRP: admin.firestore.FieldValue.increment(amount),
        updatedAt: now,
      });
    } else {
      await rpRef.set({
        userId: email, totalRP: amount, claimedRP: 0, availableRP: amount,
        createdAt: now, updatedAt: now,
      });
    }
    // Log history
    await db2.collection("rp_history").add({
      userId: email, type, amount, source, timestamp: now,
    });

    // 2. Referral propagation (skip for referral-derived types to prevent loops)
    const SKIP_TYPES = ["referral_tier1_rp", "referral_tier2_rp", "referral", "levelup"];
    if (SKIP_TYPES.includes(type)) return;

    const tier1Rate = rpCfg.referral_rp_tier1_rate || 0.10;
    const tier2Rate = rpCfg.referral_rp_tier2_rate || 0.02;

    // Find user's referrer
    const usersSnap = await db2.collection("users")
      .where("email", "==", email.toLowerCase())
      .limit(1)
      .get();
    if (usersSnap.empty) return;
    const userData = usersSnap.docs[0].data();
    const referredBy = userData.referredBy;
    if (!referredBy) return;

    // Tier 1: direct referrer
    const tier1Amount = Math.floor(amount * tier1Rate);
    if (tier1Amount > 0) {
      const t1Ref = db2.collection("user_reward_points").doc(referredBy);
      const t1Snap = await t1Ref.get();
      if (t1Snap.exists) {
        await t1Ref.update({
          totalRP: admin.firestore.FieldValue.increment(tier1Amount),
          availableRP: admin.firestore.FieldValue.increment(tier1Amount),
          updatedAt: now,
        });
      } else {
        await t1Ref.set({
          userId: referredBy, totalRP: tier1Amount, claimedRP: 0, availableRP: tier1Amount,
          createdAt: now, updatedAt: now,
        });
      }
      await db2.collection("rp_history").add({
        userId: referredBy, type: "referral_tier1_rp", amount: tier1Amount,
        source: `Tier1 ${Math.round(tier1Rate * 100)}% from ${email}: ${source}`,
        timestamp: now,
      });

      // Tier 2: grand referrer
      const t1UserSnap = await db2.collection("users")
        .where("email", "==", referredBy.toLowerCase())
        .limit(1)
        .get();
      if (!t1UserSnap.empty) {
        const t1UserData = t1UserSnap.docs[0].data();
        const grandReferrer = t1UserData.referredBy;
        if (grandReferrer && grandReferrer !== email) {
          const tier2Amount = Math.floor(amount * tier2Rate);
          if (tier2Amount > 0) {
            const t2Ref = db2.collection("user_reward_points").doc(grandReferrer);
            const t2Snap = await t2Ref.get();
            if (t2Snap.exists) {
              await t2Ref.update({
                totalRP: admin.firestore.FieldValue.increment(tier2Amount),
                availableRP: admin.firestore.FieldValue.increment(tier2Amount),
                updatedAt: now,
              });
            } else {
              await t2Ref.set({
                userId: grandReferrer, totalRP: tier2Amount, claimedRP: 0, availableRP: tier2Amount,
                createdAt: now, updatedAt: now,
              });
            }
            await db2.collection("rp_history").add({
              userId: grandReferrer, type: "referral_tier2_rp", amount: tier2Amount,
              source: `Tier2 ${Math.round(tier2Rate * 100)}% from ${email}: ${source}`,
              timestamp: now,
            });
          }
        }
      }
    }
  } catch (e) {
    console.warn("[RP] serverAddRewardPoints failed:", e.message);
  }
}


