// =============================================================================
// Separated into tradingEngine.js for maintainability

const { runMicroRoundEngine } = require("./tradingEngine");

/**
 * TRADING ENGINE - Micro-Round Architecture
 * Runs every 1 minute, executes ~25 micro-rounds (~2s each)
 */
exports.tradingEngine = onSchedule({
  schedule: "every 1 minutes",
  timeoutSeconds: 55,
  memory: "512MiB",
}, async () => {
  const db = admin.firestore();
  try {
    await runMicroRoundEngine(admin, db, getApiKeyFromFirestore);
  } catch (err) {
    console.error("[TradingEngine] Fatal:", err);
    throw err;
  }
});

/**
 * TRADING ARENA API - HTTP endpoint for frontend interactions
 */
exports.tradingArenaAPI = onRequest({ cors: true, invoker: "public" }, async (req, res) => {
  const db = admin.firestore();
  const DEX_PAIR = "VCN-USDT";
  const { action } = req.body || req.query || {};

  try {
    switch (action) {
      case "getMarket": {
        const snap = await db.doc(`dex/market/data/${DEX_PAIR}`).get();
        return res.json({ success: true, market: snap.exists ? snap.data() : null });
      }
      case "getOrderBook": {
        // Primary: read pre-computed snapshot (fast, no index needed)
        const obSnap = await db.doc(`dex/orderbook/data/${DEX_PAIR}`).get();
        if (obSnap.exists) {
          const ob = obSnap.data();
          const isFull = req.body?.full === true;
          return res.json({
            success: true,
            bids: isFull ? (ob.bids || []) : (ob.bids || []).slice(0, 15),
            asks: isFull ? (ob.asks || []) : (ob.asks || []).slice(0, 15),
            lastPrice: ob.lastPrice,
            spreadPercent: ob.spreadPercent,
          });
        }
        // Fallback: query orders collection (no orderBy to avoid composite index)
        const ordersSnap = await db.collection("dex/orders/list")
          .where("status", "in", ["open", "partial"])
          .limit(200).get();
        const bids = []; const asks = [];
        ordersSnap.forEach((doc) => {
          const o = doc.data();
          const entry = { price: o.price, amount: o.remainingAmount || o.amount, agentId: o.agentId };
          if (o.side === "buy") bids.push(entry); else asks.push(entry);
        });
        bids.sort((a, b) => b.price - a.price);
        asks.sort((a, b) => a.price - b.price);
        return res.json({ success: true, bids: bids.slice(0, 15), asks: asks.slice(0, 15) });
      }
      case "getRecentTrades": {
        const limit = Math.min(parseInt(req.body?.limit || "50"), 100);
        const snap = await db.collection("dex/trades/list").orderBy("timestamp", "desc").limit(limit).get();
        const trades = [];
        snap.forEach((doc) => trades.push(doc.data()));
        return res.json({ success: true, trades });
      }
      case "getCandles": {
        const interval = req.body?.interval || "1h";
        const limit = Math.min(parseInt(req.body?.limit || "100"), 500);
        const snap = await db.collection(`dex/candles/${interval}`).orderBy("t", "desc").limit(limit).get();
        const candles = [];
        snap.forEach((doc) => candles.push(doc.data()));
        candles.reverse();
        return res.json({ success: true, candles, interval });
      }
      case "createAgent": {
        const { uid, name, preset, prompt, riskLevel } = req.body;
        if (!uid || !name) return res.status(400).json({ success: false, error: "Missing uid or name" });
        const existingSnap = await db.collection("dex/agents/list").where("ownerUid", "==", uid).where("role", "==", "trader").get();
        if (existingSnap.size >= 3) return res.status(400).json({ success: false, error: "Maximum 3 agents per user" });
        const marketSnap = await db.doc(`dex/market/data/${DEX_PAIR}`).get();
        const currentPrice = marketSnap.exists ? marketSnap.data().lastPrice || 0.10 : 0.10;
        const initialValue = 10000 + 100000 * currentPrice;
        const agentId = `agent-${uid.substr(0, 8)}-${Date.now().toString(36)}`;
        await db.doc(`dex/agents/list/${agentId}`).set({
          id: agentId, ownerUid: uid, name, role: "trader",
          strategy: { preset: preset || "custom", prompt: (prompt || "").substring(0, 2000), riskLevel: Math.max(1, Math.min(10, parseInt(riskLevel) || 5)), tradingFrequency: "medium", maxPositionPercent: 30 },
          balances: { USDT: 10000, VCN: 100000 },
          performance: { initialValueUSDT: initialValue, currentValueUSDT: initialValue, totalPnL: 0, totalPnLPercent: 0, winCount: 0, lossCount: 0, totalTrades: 0, bestTrade: 0, worstTrade: 0, maxDrawdown: 0 },
          recentTrades: [], status: "active", lastTradeAt: null,
          createdAt: admin.firestore.Timestamp.now(), updatedAt: admin.firestore.Timestamp.now(),
        });
        return res.json({ success: true, agentId });
      }
      case "getMyAgents": {
        const { uid } = req.body;
        if (!uid) return res.status(400).json({ success: false, error: "Missing uid" });
        const snap = await db.collection("dex/agents/list").where("ownerUid", "==", uid).get();
        const myAgents = [];
        snap.forEach((doc) => myAgents.push(doc.data()));
        return res.json({ success: true, agents: myAgents });
      }
      case "getLeaderboard": {
        const limit = Math.min(parseInt(req.body?.limit || "50"), 100);
        const snap = await db.collection("dex/agents/list").where("role", "==", "trader").get();
        const agents = [];
        snap.forEach((doc) => {
          const a = doc.data();
          agents.push({
            agentId: a.id, agentName: a.name, ownerUid: a.ownerUid,
            strategyPreset: a.strategy?.preset,
            pnlPercent: a.performance?.totalPnLPercent || 0,
            pnlAbsolute: a.performance?.totalPnL || 0,
            winRate: a.performance?.totalTrades > 0 ?
              (a.performance.winCount / a.performance.totalTrades) * 100 : 0,
            totalTrades: a.performance?.totalTrades || 0,
          });
        });
        agents.sort((a, b) => b.pnlPercent - a.pnlPercent);
        agents.forEach((a, i) => {
          a.rank = i + 1;
        });
        return res.json({ success: true, leaderboard: agents.slice(0, limit) });
      }
      case "updateAgent": {
        const { uid, agentId, prompt: newPrompt, riskLevel: newRisk, status: newStatus } = req.body;
        if (!uid || !agentId) return res.status(400).json({ success: false, error: "Missing params" });
        const agentRef = db.doc(`dex/agents/list/${agentId}`);
        const agentSnap = await agentRef.get();
        if (!agentSnap.exists) return res.status(404).json({ success: false, error: "Agent not found" });
        if (agentSnap.data().ownerUid !== uid) return res.status(403).json({ success: false, error: "Not owner" });
        const updates = { updatedAt: admin.firestore.Timestamp.now() };
        if (newPrompt !== undefined) updates["strategy.prompt"] = newPrompt.substring(0, 2000);
        if (newRisk !== undefined) updates["strategy.riskLevel"] = Math.max(1, Math.min(10, parseInt(newRisk)));
        if (newStatus && ["active", "paused", "stopped"].includes(newStatus)) updates.status = newStatus;
        await agentRef.update(updates);
        return res.json({ success: true });
      }
      case "deleteAgent": {
        const { uid, agentId: delId } = req.body;
        if (!uid || !delId) return res.status(400).json({ success: false, error: "Missing params" });
        const ref = db.doc(`dex/agents/list/${delId}`);
        const snap = await ref.get();
        if (!snap.exists) return res.status(404).json({ success: false, error: "Not found" });
        if (snap.data().ownerUid !== uid) return res.status(403).json({ success: false, error: "Not owner" });
        if (snap.data().role === "market_maker") return res.status(403).json({ success: false, error: "Cannot delete Trading" });
        await ref.delete();
        return res.json({ success: true });
      }
      case "getAgentHistory": {
        const { agentId: histId } = req.body;
        if (!histId) return res.status(400).json({ success: false, error: "Missing agentId" });
        const limit = Math.min(parseInt(req.body?.limit || "50"), 200);
        const makerSnap = await db.collection("dex/trades/list").where("makerAgentId", "==", histId).orderBy("timestamp", "desc").limit(limit).get();
        const takerSnap = await db.collection("dex/trades/list").where("takerAgentId", "==", histId).orderBy("timestamp", "desc").limit(limit).get();
        const history = [];
        makerSnap.forEach((doc) => history.push({ ...doc.data(), myRole: "maker" }));
        takerSnap.forEach((doc) => history.push({ ...doc.data(), myRole: "taker" }));
        history.sort((a, b) => (b.timestamp?._seconds || 0) - (a.timestamp?._seconds || 0));
        return res.json({ success: true, history: history.slice(0, limit) });
      }
      case "getMMAgents": {
        const mmSnap = await db.collection("dex/agents/list").where("role", "==", "market_maker").get();
        const tradingAgents = [];
        mmSnap.forEach((d) => tradingAgents.push(d.data()));
        const mktSnap = await db.doc(`dex/market/data/${DEX_PAIR}`).get();
        const mktData = mktSnap.exists ? mktSnap.data() : {};
        const settSnap = await db.doc("dex/config/trading-settings/current").get();
        const settData = settSnap.exists ? settSnap.data() : {};

        // --- Fetch Actual Orderbook Stats ---
        const obSnap = await db.doc(`dex/orderbook/data/${DEX_PAIR}`).get();
        const obStats = { bidsCount: 0, asksCount: 0, bidsVol: 0, asksVol: 0 };
        if (obSnap.exists) {
          const ob = obSnap.data();
          obStats.bidsCount = (ob.bids || []).length;
          obStats.asksCount = (ob.asks || []).length;
          obStats.bidsVol = (ob.bids || []).reduce((sum, o) => sum + (o.amount || 0), 0);
          obStats.asksVol = (ob.asks || []).reduce((sum, o) => sum + (o.amount || 0), 0);
        }

        // --- Fetch Top Retail Agents as "Whales" ---
        const retailSnap = await db.collection("dex/agents/list").where("role", "==", "trader").orderBy("balances.VCN", "desc").limit(10).get();
        const topWhales = [];
        retailSnap.forEach((d) => topWhales.push(d.data()));

        return res.json({
          success: true,
          agents: tradingAgents,
          market: mktData,
          settings: settData,
          orderbookStats: obStats,
          whales: topWhales,
        });
      }
      case "getEngineStatus": {
        const roundSnap = await db.doc("dex/settings/config/roundCounter").get();
        const current = roundSnap.exists ? roundSnap.data().current || 0 : 0;
        let lastRound = null;
        if (current > 0) {
          const logSnap = await db.doc(`dex/rounds/log/${current}`).get(); lastRound = logSnap.exists ? logSnap.data() : null;
        }
        const settingsSnap = await db.doc("dex/settings/config/main").get();
        return res.json({ success: true, roundNumber: current, lastRound, settings: settingsSnap.exists ? settingsSnap.data() : {} });
      }
      case "initEngine": {
        // Check if Trading agents exist specifically
        const mmCheck = await db.doc("dex/agents/list/trading-alpha").get();
        const tradersExist = !(await db.collection("dex/agents/list").limit(1).get()).empty;
        if (mmCheck.exists && !req.body.force) {
          return res.json({ success: false, error: "Already initialized" });
        }
        const IP = 0.10;
        const SYS = "SYSTEM_ADMIN";
        const now = admin.firestore.Timestamp.now();
        const wb = db.batch();
        // Trading Alpha (bullish)
        wb.set(db.doc("dex/agents/list/trading-alpha"), {
          id: "trading-alpha", ownerUid: SYS, name: "Trading Alpha",
          role: "market_maker",
          strategy: {
            preset: "trading_bull", riskLevel: 3,
            tradingFrequency: "high", maxPositionPercent: 5,
          },
          tradingConfig: {
            basePrice: IP, spreadPercent: 0.5,
            priceRangePercent: 20, trendBias: 0.3, trendSpeed: 0.03,
            layerCount: 5, layerSpacing: 0.3, inventoryTarget: 0.5,
          },
          balances: { USDT: 500000, VCN: 5000000 },
          performance: {
            initialValueUSDT: 500000 + 5000000 * IP,
            currentValueUSDT: 500000 + 5000000 * IP,
            totalPnL: 0, totalPnLPercent: 0,
            winCount: 0, lossCount: 0, totalTrades: 0,
            bestTrade: 0, worstTrade: 0, maxDrawdown: 0,
          },
          recentTrades: [], status: "active", lastTradeAt: null,
          createdAt: now, updatedAt: now,
        });
        // Trading Beta (bearish)
        wb.set(db.doc("dex/agents/list/trading-beta"), {
          id: "trading-beta", ownerUid: SYS, name: "Trading Beta",
          role: "market_maker",
          strategy: {
            preset: "trading_bear", riskLevel: 3,
            tradingFrequency: "high", maxPositionPercent: 5,
          },
          tradingConfig: {
            basePrice: IP, spreadPercent: 0.5,
            priceRangePercent: 20, trendBias: -0.2, trendSpeed: 0.03,
            layerCount: 5, layerSpacing: 0.3, inventoryTarget: 0.5,
          },
          balances: { USDT: 500000, VCN: 5000000 },
          performance: {
            initialValueUSDT: 500000 + 5000000 * IP,
            currentValueUSDT: 500000 + 5000000 * IP,
            totalPnL: 0, totalPnLPercent: 0,
            winCount: 0, lossCount: 0, totalTrades: 0,
            bestTrade: 0, worstTrade: 0, maxDrawdown: 0,
          },
          recentTrades: [], status: "active", lastTradeAt: null,
          createdAt: now, updatedAt: now,
        });
        // 10 preset agents
        const presets = [
          { id: "momentum", name: "TrendFollower", risk: 7, maxPos: 50 },
          { id: "value", name: "ValueHunter", risk: 3, maxPos: 30 },
          { id: "scalper", name: "QuickScalper", risk: 5, maxPos: 10 },
          { id: "contrarian", name: "ContrarianBot", risk: 6, maxPos: 40 },
          { id: "grid", name: "GridMaster", risk: 3, maxPos: 10 },
          { id: "breakout", name: "BreakoutKing", risk: 8, maxPos: 60 },
          { id: "twap", name: "SteadyTWAP", risk: 2, maxPos: 5 },
          { id: "sentiment", name: "NewsSentinel", risk: 5, maxPos: 30 },
          { id: "random", name: "RandomWalker", risk: 5, maxPos: 15 },
          { id: "dca", name: "DCABuilder", risk: 2, maxPos: 2 },
        ];
        const iv = 10000 + 100000 * IP;
        for (const p of presets) {
          wb.set(db.doc(`dex/agents/list/default-${p.id}`), {
            id: `default-${p.id}`, ownerUid: SYS, name: p.name,
            role: "trader",
            strategy: {
              preset: p.id, riskLevel: p.risk,
              tradingFrequency: "medium",
              maxPositionPercent: p.maxPos,
            },
            balances: { USDT: 10000, VCN: 100000 },
            performance: {
              initialValueUSDT: iv, currentValueUSDT: iv,
              totalPnL: 0, totalPnLPercent: 0,
              winCount: 0, lossCount: 0, totalTrades: 0,
              bestTrade: 0, worstTrade: 0, maxDrawdown: 0,
            },
            recentTrades: [], status: "active", lastTradeAt: null,
            createdAt: now, updatedAt: now,
          });
        }
        // Market state
        wb.set(db.doc(`dex/market/data/${DEX_PAIR}`), {
          pair: DEX_PAIR, lastPrice: IP, previousPrice: IP,
          change24h: 0, changePercent24h: 0,
          high24h: IP, low24h: IP,
          volume24h: 0, quoteVolume24h: 0, trades24h: 0,
          bestBid: 0, bestAsk: 0, spread: 0, spreadPercent: 0,
          openOrders: 0, activeAgents: 12, totalAgents: 12,
          updatedAt: now,
        });
        // Engine settings
        wb.set(db.doc("dex/settings/config/main"), {
          paused: false, initialPrice: IP,
          maxPriceChangePerRound: 0.03,
          createdAt: now,
        });
        wb.set(db.doc("dex/settings/config/roundCounter"), {
          current: 0,
        });
        await wb.commit();
        return res.json({
          success: true,
          message: "Engine initialized: 2 Trading + 10 preset agents",
        });
      }
      case "getUserDexBalance": {
        const { uid } = req.body;
        if (!uid) return res.status(400).json({ success: false, error: "Missing uid" });
        const balRef = db.doc(`dex/userBalances/list/${uid}`);
        const balSnap = await balRef.get();
        if (balSnap.exists) {
          return res.json({ success: true, ...balSnap.data() });
        }
        // Initialize new user balance
        const initBal = { uid, USDT: 10000, VCN: 100000, createdAt: admin.firestore.Timestamp.now() };
        await balRef.set(initBal);
        return res.json({ success: true, ...initBal });
      }
      case "placeUserOrder": {
        const { uid, side, orderType, amount, price: limitPrice } = req.body;
        if (!uid) return res.status(400).json({ success: false, error: "Missing uid" });
        if (!["buy", "sell"].includes(side)) return res.status(400).json({ success: false, error: "Invalid side" });
        if (!["market", "limit"].includes(orderType)) return res.status(400).json({ success: false, error: "Invalid orderType" });
        const amt = parseFloat(amount);
        if (!amt || amt < 100) return res.status(400).json({ success: false, error: "Min order 100 VCN" });

        // Check if direct trading is enabled
        const cfgSnap = await db.doc("dex/settings/config/main").get();
        const cfg = cfgSnap.exists ? cfgSnap.data() : {};
        if (cfg.directTradingEnabled === false) {
          return res.status(403).json({ success: false, error: "Direct trading is currently disabled" });
        }

        // Get user balance
        const balRef = db.doc(`dex/userBalances/list/${uid}`);
        const balSnap = await balRef.get();
        if (!balSnap.exists) return res.status(400).json({ success: false, error: "No balance found. Visit DEX first." });
        const bal = balSnap.data();

        // Get market data
        const mktSnap = await db.doc(`dex/market/data/${DEX_PAIR}`).get();
        const mkt = mktSnap.exists ? mktSnap.data() : {};
        const currentPrice = mkt.lastPrice || 0.10;

        // Get order book snapshot
        const obSnap = await db.doc(`dex/orderbook/data/${DEX_PAIR}`).get();
        const ob = obSnap.exists ? obSnap.data() : { bids: [], asks: [] };

        let execPrice = 0;
        let execAmount = amt;
        const takerFeeRate = 0.0005; // 0.05%
        const makerFeeRate = 0.0002; // 0.02%

        if (orderType === "market") {
          // Market order: execute against best price
          if (side === "buy") {
            execPrice = ob.asks && ob.asks.length > 0 ? ob.asks[0].price : currentPrice;
            const totalCost = execAmount * execPrice;
            const fee = totalCost * takerFeeRate;
            if (bal.USDT < totalCost + fee) {
              // Adjust amount to what user can afford
              execAmount = Math.floor((bal.USDT * 0.999) / (execPrice * (1 + takerFeeRate)));
              if (execAmount < 100) return res.status(400).json({ success: false, error: `Insufficient USDT. Need ${(amt * execPrice).toFixed(2)}, have ${bal.USDT.toFixed(2)}` });
            }
            const finalCost = execAmount * execPrice;
            const finalFee = finalCost * takerFeeRate;
            await balRef.update({ USDT: bal.USDT - finalCost - finalFee, VCN: bal.VCN + execAmount });
          } else {
            execPrice = ob.bids && ob.bids.length > 0 ? ob.bids[0].price : currentPrice;
            if (bal.VCN < execAmount) {
              execAmount = Math.floor(bal.VCN);
              if (execAmount < 100) return res.status(400).json({ success: false, error: `Insufficient VCN. Need ${amt}, have ${Math.floor(bal.VCN)}` });
            }
            const totalProceeds = execAmount * execPrice;
            const fee = totalProceeds * takerFeeRate;
            await balRef.update({ VCN: bal.VCN - execAmount, USDT: bal.USDT + totalProceeds - fee });
          }
        } else {
          // Limit order: check if crosses, otherwise save as pending
          const lp = parseFloat(limitPrice);
          if (!lp || lp <= 0) return res.status(400).json({ success: false, error: "Invalid limit price" });
          const bestAsk = ob.asks && ob.asks.length > 0 ? ob.asks[0].price : Infinity;
          const bestBid = ob.bids && ob.bids.length > 0 ? ob.bids[0].price : 0;

          if (side === "buy" && lp >= bestAsk) {
            // Crosses: execute like market at best ask
            execPrice = bestAsk;
            const totalCost = execAmount * execPrice;
            const fee = totalCost * takerFeeRate;
            if (bal.USDT < totalCost + fee) return res.status(400).json({ success: false, error: "Insufficient USDT" });
            await balRef.update({ USDT: bal.USDT - totalCost - fee, VCN: bal.VCN + execAmount });
          } else if (side === "sell" && lp <= bestBid) {
            // Crosses: execute like market at best bid
            execPrice = bestBid;
            if (bal.VCN < execAmount) return res.status(400).json({ success: false, error: "Insufficient VCN" });
            const totalProceeds = execAmount * execPrice;
            const fee = totalProceeds * takerFeeRate;
            await balRef.update({ VCN: bal.VCN - execAmount, USDT: bal.USDT + totalProceeds - fee });
          } else {
            // Does not cross: place as pending limit order
            if (side === "buy") {
              const totalCost = execAmount * lp;
              if (bal.USDT < totalCost) return res.status(400).json({ success: false, error: "Insufficient USDT for limit order" });
              // Lock funds
              await balRef.update({ USDT: bal.USDT - totalCost });
            } else {
              if (bal.VCN < execAmount) return res.status(400).json({ success: false, error: "Insufficient VCN for limit order" });
              await balRef.update({ VCN: bal.VCN - execAmount });
            }

            const orderId = `user-${uid.substr(0, 8)}-${Date.now().toString(36)}`;
            await db.doc(`dex/orders/list/${orderId}`).set({
              id: orderId, ownerUid: uid, agentId: `user-${uid}`, pair: DEX_PAIR,
              side, type: "limit", role: "pending",
              price: lp, amount: execAmount, filledAmount: 0, remainingAmount: execAmount,
              status: "open", fee: 0, feeRate: makerFeeRate, reasoning: "User limit order",
              expiresAt: admin.firestore.Timestamp.fromMillis(Date.now() + 3600000),
              createdAt: admin.firestore.Timestamp.now(),
            });

            // Get updated balance
            const updBal = (await balRef.get()).data();
            return res.json({
              success: true, status: "pending", orderId,
              message: `Limit ${side} order placed: ${execAmount} VCN @ ${lp}`,
              balance: { USDT: updBal.USDT, VCN: updBal.VCN },
            });
          }
        }

        // Record trade for market/crossing limit
        const tradeId = `user-t-${Date.now().toString(36)}-${Math.random().toString(36).substr(2, 4)}`;
        const fee = execAmount * execPrice * takerFeeRate;
        await db.doc(`dex/trades/list/${tradeId}`).set({
          id: tradeId, pair: DEX_PAIR, price: execPrice, amount: execAmount,
          total: execAmount * execPrice, takerSide: side,
          makerAgentId: "orderbook", makerUid: "system",
          makerOrderId: "ob-match", makerFee: 0,
          takerAgentId: `user-${uid}`, takerUid: uid,
          takerOrderId: tradeId, takerFee: fee,
          reasoning: `User ${orderType} ${side}`,
          timestamp: admin.firestore.Timestamp.now(),
        });

        // Get updated balance
        const updatedBal = (await balRef.get()).data();
        return res.json({
          success: true, status: "filled",
          price: execPrice, amount: execAmount,
          total: execAmount * execPrice, fee,
          balance: { USDT: updatedBal.USDT, VCN: updatedBal.VCN },
        });
      }
      case "getUserOrders": {
        const { uid } = req.body;
        if (!uid) return res.status(400).json({ success: false, error: "Missing uid" });
        const limit = Math.min(parseInt(req.body?.limit || "20"), 50);

        // Open orders
        const openSnap = await db.collection("dex/orders/list")
          .where("ownerUid", "==", uid)
          .where("status", "in", ["open", "partial"])
          .limit(limit).get();
        const openOrders = [];
        openSnap.forEach((d) => openOrders.push(d.data()));

        // Recent trades
        const tradesSnap = await db.collection("dex/trades/list")
          .where("takerUid", "==", uid)
          .orderBy("timestamp", "desc").limit(limit).get();
        const recentTrades = [];
        tradesSnap.forEach((d) => recentTrades.push(d.data()));

        return res.json({ success: true, openOrders, recentTrades });
      }
      case "cancelUserOrder": {
        const { uid, orderId } = req.body;
        if (!uid || !orderId) return res.status(400).json({ success: false, error: "Missing params" });
        const orderRef = db.doc(`dex/orders/list/${orderId}`);
        const orderSnap = await orderRef.get();
        if (!orderSnap.exists) return res.status(404).json({ success: false, error: "Order not found" });
        const order = orderSnap.data();
        if (order.ownerUid !== uid) return res.status(403).json({ success: false, error: "Not owner" });
        if (order.status !== "open" && order.status !== "partial") return res.status(400).json({ success: false, error: "Order not open" });

        // Refund locked balance
        const balRef = db.doc(`dex/userBalances/list/${uid}`);
        const balSnap = await balRef.get();
        if (balSnap.exists) {
          const bal = balSnap.data();
          const remaining = order.remainingAmount || order.amount;
          if (order.side === "buy") {
            await balRef.update({ USDT: (bal.USDT || 0) + remaining * order.price });
          } else {
            await balRef.update({ VCN: (bal.VCN || 0) + remaining });
          }
        }
        await orderRef.update({ status: "cancelled" });
        const updBal = (await balRef.get()).data();
        return res.json({ success: true, balance: { USDT: updBal.USDT, VCN: updBal.VCN } });
      }
      case "executeMarketAction": {
        const { side, type, amount, targetPrice } = req.body;
        if (!side) return res.status(400).json({ success: false, error: "Missing side" });
        const id = `action-${Date.now().toString(36)}`;
        await db.doc(`dex/config/trading-actions/${id}`).set({
          id, executedAt: admin.firestore.Timestamp.now(),
          side, type: type || side, amount: parseFloat(amount || 0), targetPrice: parseFloat(targetPrice || 0),
          status: "pending", createdBy: "TradingAdmin",
        });
        return res.json({ success: true, actionId: id, message: "Action request registered for execution." });
      }
      case "getAnalyticsHistory": {
        const limit = Math.min(parseInt(req.body?.limit || "30"), 100);
        const snap = await db.collection("dex/analytics/pnl_history")
          .orderBy("timestamp", "desc")
          .limit(limit)
          .get();
        const history = [];
        snap.forEach((doc) => history.push(doc.data()));
        return res.json({ success: true, history: history.reverse() });
      }
      default:
        return res.status(400).json({ success: false, error: `Unknown action: ${action}` });
    }
  } catch (err) {
    console.error("[TradingArenaAPI] Error:", err);
    return res.status(500).json({ success: false, error: err.message });
  }
});

