// Base configuration
const DEFAULT_DISK_BASE_GB = 10;
const DEFAULT_DISK_BASE_PRICE = 5;
const DEFAULT_DISK_ADD_GB = 10;
const DEFAULT_DISK_ADD_PRICE = 3;
const DEFAULT_DISK_MAX_GB = 50;

async function getDiskPricing() {
  const doc = await db.collection("settings").doc("diskPricing").get();
  if (doc.exists) {
    return {
      baseGb: DEFAULT_DISK_BASE_GB,
      basePrice: DEFAULT_DISK_BASE_PRICE,
      addGb: DEFAULT_DISK_ADD_GB,
      addPrice: DEFAULT_DISK_ADD_PRICE,
      maxGb: DEFAULT_DISK_MAX_GB,
      ...doc.data(),
    };
  }
  return {
    baseGb: DEFAULT_DISK_BASE_GB,
    basePrice: DEFAULT_DISK_BASE_PRICE,
    addGb: DEFAULT_DISK_ADD_GB,
    addPrice: DEFAULT_DISK_ADD_PRICE,
    maxGb: DEFAULT_DISK_MAX_GB,
  };
}

function calcDiskPrice(gb, pricing) {
  if (gb <= pricing.baseGb) return pricing.basePrice;
  const extraGb = gb - pricing.baseGb;
  const tiers = Math.ceil(extraGb / pricing.addGb);
  return pricing.basePrice + (tiers * pricing.addPrice);
}

/**
 * Permanently deletes all disk files and metadata for a user
 * @param {string} email User email
 */
async function deleteUserDiskData(email) {
  console.log(`[Disk] Permanently deleting all data for ${email}`);

  // 1. Delete from Firebase Storage
  const bucket = admin.storage().bucket();
  const folderPath = `disk/${email}/`;
  try {
    await bucket.deleteFiles({ prefix: folderPath });
  } catch (e) {
    console.warn(`[Disk] Storage deletion failed/skipped for ${email}:`, e.message);
  }

  // 2. Delete from Firestore
  const userRef = db.collection("users").doc(email);
  const filesSnapshot = await userRef.collection("disk_files").get();
  const foldersSnapshot = await userRef.collection("disk_folders").get();

  const batch = db.batch();
  filesSnapshot.docs.forEach((d) => batch.delete(d.ref));
  foldersSnapshot.docs.forEach((d) => batch.delete(d.ref));
  await batch.commit();

  console.log(`[Disk] Deleted ${filesSnapshot.size} files and ${foldersSnapshot.size} folders for ${email}`);
}

// Subscribe or update capacity
exports.diskSubscribe = onCall({ cors: true, secrets: ["VCN_EXECUTOR_PK"] }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { gb, signature, deadline, owner } = request.data;

  const pricing = await getDiskPricing();

  if (!gb || gb < pricing.baseGb || gb > pricing.maxGb) {
    throw new HttpsError("invalid-argument", `Requested capacity must be between ${pricing.baseGb}GB and ${pricing.maxGb}GB`);
  }

  const price = calcDiskPrice(gb, pricing);
  const provider = new ethers.JsonRpcProvider(RPC_URL);
  const executorWallet = new ethers.Wallet(VCN_EXECUTOR_PK, provider);
  const tokenContract = new ethers.Contract(VCN_TOKEN_ADDRESS, VCN_TOKEN_ABI, executorWallet);

  // Get user's wallet address from their profile
  const userDoc = await db.collection("users").doc(email).get();
  if (!userDoc.exists || !userDoc.data().walletAddress) {
    throw new HttpsError("failed-precondition", "Wallet address not found for user.");
  }
  const userAddress = owner || userDoc.data().walletAddress;
  const priceWei = ethers.parseEther(price.toString());

  // === Gasless Payment via Permit (EIP-2612) ===
  if (signature && deadline) {
    // Execute Permit: Executor pays gas, user signs off-chain
    try {
      const sig = ethers.Signature.from(signature);
      console.log(`[Disk] Executing permit for ${price} VCN from ${userAddress}...`);
      const permitTx = await tokenContract.permit(
        userAddress,
        executorWallet.address,
        priceWei,
        deadline,
        sig.v,
        sig.r,
        sig.s,
      );
      await permitTx.wait();
      console.log(`[Disk] Permit confirmed: ${permitTx.hash}`);
    } catch (permitErr) {
      console.error("[Disk] Permit failed:", permitErr.message);
      throw new HttpsError("failed-precondition", `Permit failed: ${permitErr.reason || permitErr.message}`);
    }
  } else {
    // Fallback: check existing allowance (legacy)
    const allowance = await tokenContract.allowance(userAddress, executorWallet.address);
    if (allowance < priceWei) {
      throw new HttpsError("failed-precondition", "insufficient_allowance");
    }
  }

  // Deduct the first month price right now if it's a new subscription or upgrade
  const currentSubDoc = await db.collection("disk_subscriptions").doc(email).get();
  const currentSub = currentSubDoc.exists ? currentSubDoc.data() : null;

  try {
    const tx = await tokenContract.transferFrom(userAddress, executorWallet.address, priceWei);
    await tx.wait(); // Wait for confirmation
  } catch (err) {
    console.error("[Disk] Initial payment failed:", err.message);
    throw new HttpsError("internal", "Payment failed: " + err.message);
  }

  const nowMs = Date.now();
  const cycleEnd = nowMs + 30 * 24 * 60 * 60 * 1000; // +30 days

  await db.collection("disk_subscriptions").doc(email).set({
    email,
    status: "active",
    subscribedGb: gb,
    priceVcn: price,
    currentCycleStart: nowMs,
    currentCycleEnd: cycleEnd,
    autoRenew: true,
    cancelAtPeriodEnd: false,
    overdueSince: null,
    updatedAt: nowMs,
  });

  // Send Email
  const title = currentSub ? "Vision Disk Capacity Updated" : "Welcome to Vision Disk";
  const body = `
    ${emailComponents.sectionTitle(title)}
    ${emailComponents.infoCard([
    ["Subscription", `${gb} GB Storage`, true],
    ["Monthly Fee", `${price} VCN`, true],
    ["Next Billing", new Date(cycleEnd).toLocaleDateString(), false],
  ])}
    ${emailComponents.subtitle("Thank you for using our decentralized storage network.")}
  `;
  await sendSecurityEmail(email, title, emailBaseLayout(body, "Your Vision Disk subscription is active"));

  return { success: true, gb, price, cycleEnd };
});

exports.diskCancelSubscription = onCall({ cors: true }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();

  const subRef = db.collection("disk_subscriptions").doc(email);
  const doc = await subRef.get();
  if (!doc.exists) throw new HttpsError("not-found", "Subscription not found.");

  await subRef.update({ cancelAtPeriodEnd: true, autoRenew: false, updatedAt: Date.now() });

  // Send Cancel Email
  const body = `
    ${emailComponents.sectionTitle("Subscription Canceled", "#ef4444")}
    ${emailComponents.subtitle("Your Vision Disk subscription has been canceled. You can continue using it until the end of your current billing period.")}
    ${emailComponents.infoCard([
    ["Access Ends On", new Date(doc.data().currentCycleEnd).toLocaleDateString(), true],
  ], "#ef4444")}
  `;
  await sendSecurityEmail(email, "Vision Disk Subscription Canceled", emailBaseLayout(body, "Subscription cancellation confirmed"));

  return { success: true };
});

exports.purchasePublishedFile = onCall({ cors: true, secrets: ["VCN_EXECUTOR_PK", "EMAIL_USER", "EMAIL_APP_PASSWORD"] }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const buyerEmail = request.auth.token.email.toLowerCase();
  const { fileId, signature, deadline, owner } = request.data;

  if (!fileId) throw new HttpsError("invalid-argument", "fileId required.");

  const marketRef = db.collection("published_materials").doc(fileId);
  const marketSnap = await marketRef.get();

  if (!marketSnap.exists) throw new HttpsError("not-found", "Material not found in market.");
  const item = marketSnap.data();

  if (!item.isPublished) throw new HttpsError("failed-precondition", "File is no longer public.");
  const priceVcn = item.priceVcn || 0;
  const publisherEmail = item.publisherEmail;

  if (buyerEmail === publisherEmail) {
    return { success: true, downloadURL: item.downloadURL };
  }

  // Check if already purchased
  const purchaseRef = db.collection("users").doc(buyerEmail).collection("purchased_files").doc(fileId);
  const purchaseSnap = await purchaseRef.get();
  if (purchaseSnap.exists) {
    return { success: true, downloadURL: item.downloadURL };
  }

  // Handle Payment via Paymaster
  const provider = new ethers.JsonRpcProvider(RPC_URL);
  const executorWallet = new ethers.Wallet(VCN_EXECUTOR_PK, provider);
  const token = new ethers.Contract(VCN_TOKEN_ADDRESS, VCN_TOKEN_ABI, executorWallet);

  const buyerDoc = await db.collection("users").doc(buyerEmail).get();
  const publisherDoc = await db.collection("users").doc(publisherEmail).get();

  if (!buyerDoc.exists || !buyerDoc.data().walletAddress) throw new HttpsError("failed-precondition", "Buyer wallet not linked.");
  if (!publisherDoc.exists || !publisherDoc.data().walletAddress) throw new HttpsError("failed-precondition", "Publisher wallet not found.");

  const buyerAddress = owner || buyerDoc.data().walletAddress;
  const publisherAddress = publisherDoc.data().walletAddress;

  const amountWei = ethers.parseUnits(priceVcn.toString(), 18);

  // Split calculations: 30% platform fee, 70% to publisher
  const platformFee = (amountWei * 30n) / 100n;
  const publisherAmount = amountWei - platformFee;

  try {
    // === Gasless Payment via Permit (EIP-2612) ===
    if (signature && deadline) {
      // Execute Permit: Executor pays gas, buyer signs off-chain
      try {
        const sig = ethers.Signature.from(signature);
        console.log(`[DiskPurchase] Executing permit for ${priceVcn} VCN from ${buyerAddress}...`);
        const startNonce = await provider.getTransactionCount(executorWallet.address, "pending");
        const permitTx = await token.permit(
          buyerAddress,
          executorWallet.address,
          amountWei,
          deadline,
          sig.v,
          sig.r,
          sig.s,
          { nonce: startNonce },
        );
        await permitTx.wait();
        console.log(`[DiskPurchase] Permit confirmed: ${permitTx.hash}`);
      } catch (permitErr) {
        console.error("[DiskPurchase] Permit failed:", permitErr.message);
        throw new HttpsError("failed-precondition", `Permit failed: ${permitErr.reason || permitErr.message}`);
      }
    } else {
      // Fallback: check existing allowance (legacy)
      const allowance = await token.allowance(buyerAddress, executorWallet.address);
      if (allowance < amountWei) throw new HttpsError("failed-precondition", "insufficient_allowance");
    }

    // Transfer full price from buyer to executor
    const nonce1 = await provider.getTransactionCount(executorWallet.address, "pending");
    const tx1 = await token.transferFrom(buyerAddress, executorWallet.address, amountWei, { nonce: nonce1 });
    await tx1.wait();
    console.log(`[DiskPurchase] Collected ${priceVcn} VCN from buyer: ${tx1.hash}`);

    // Transfer publisher's share (70%) from executor to publisher
    if (publisherAmount > 0n) {
      const nonce2 = await provider.getTransactionCount(executorWallet.address, "pending");
      const tx2 = await token.transfer(publisherAddress, publisherAmount, { nonce: nonce2 });
      await tx2.wait();
      console.log(`[DiskPurchase] Paid ${ethers.formatUnits(publisherAmount, 18)} VCN to publisher: ${tx2.hash}`);
    }

    // Record purchase
    await purchaseRef.set({
      fileId,
      purchasedAt: Date.now(),
      priceVcn,
      publisherEmail,
      txHash: tx1.hash,
    });

    await marketRef.update({
      purchaseCount: admin.firestore.FieldValue.increment(1),
    });

    // Notify publisher via email
    const body = `
      ${emailComponents.sectionTitle("New Sale on Vision Disk!")}
      ${emailComponents.infoCard([
      ["Item", item.name, true],
      ["Price", `${priceVcn} VCN`, true],
      ["Earnings (70%)", `${ethers.formatUnits(publisherAmount, 18)} VCN`, true],
    ])}
    `;
    await sendSecurityEmail(publisherEmail, "Vision Disk Sale Notification", emailBaseLayout(body, `You just sold ${item.name}!`));

    return { success: true, downloadURL: item.downloadURL };
  } catch (err) {
    console.error("[DiskPurchase] Payment failed:", err);
    throw new HttpsError("internal", "Purchase failed: " + err.message);
  }
});

// ── Cleanup old staging chunks after nodes have replicated them ──
exports.cleanupStagingChunks = onSchedule({ schedule: "every 24 hours" }, async () => {
  console.log("[ChunkCleanup] Starting daily staging_chunks cleanup");
  const cutoff = Date.now() - (7 * 24 * 60 * 60 * 1000); // 7 days ago
  let deleted = 0;
  let skipped = 0;

  try {
    // Find old staging chunks
    const stagingSnap = await db.collection("staging_chunks")
      .where("created_at", "<", cutoff)
      .limit(500)
      .get();

    if (stagingSnap.empty) {
      console.log("[ChunkCleanup] No old staging chunks to clean up");
      return;
    }

    const batch = db.batch();

    for (const chunkDoc of stagingSnap.docs) {
      const hash = chunkDoc.id;

      // Check if chunk has been replicated to enough nodes
      const holdersSnap = await db.collection("chunk_registry").doc(hash)
        .collection("holders").where("status", "==", "active").get();

      if (holdersSnap.size >= 2) {
        // Safe to delete from staging - enough replicas exist
        batch.delete(chunkDoc.ref);
        deleted++;
      } else {
        skipped++;
      }
    }

    if (deleted > 0) {
      await batch.commit();
    }

    console.log(`[ChunkCleanup] Done: deleted ${deleted}, skipped ${skipped} (insufficient replicas)`);
  } catch (err) {
    console.error("[ChunkCleanup] Error:", err.message);
  }
});

// Daily Cron Job for Disk Subscriptions
exports.diskDailyBilling = onSchedule({ schedule: "every 24 hours", secrets: ["VCN_EXECUTOR_PK", "EMAIL_USER", "EMAIL_APP_PASSWORD"] }, async (_event) => {
  console.log("[DiskBilling] Starting daily cron job");
  const nowMs = Date.now();
  const provider = new ethers.JsonRpcProvider(RPC_URL);
  const executorWallet = new ethers.Wallet(VCN_EXECUTOR_PK, provider);
  const tokenContract = new ethers.Contract(VCN_TOKEN_ADDRESS, ERC20_ABI, executorWallet);

  const snapshot = await db.collection("disk_subscriptions").get();
  const pricing = await getDiskPricing();

  for (const docSnapshot of snapshot.docs) {
    const sub = docSnapshot.data();
    const email = sub.email;

    try {
      // 1. Check if cycle ended
      if (nowMs > sub.currentCycleEnd && (sub.status === "active" || sub.status === "grace_period")) {
        // If cancelAtPeriodEnd was requested, it officially expires now
        if (sub.cancelAtPeriodEnd) {
          await db.collection("disk_subscriptions").doc(email).update({
            status: "expired",
            overdueSince: nowMs,
          });
          continue;
        }

        // Try to charge for renewal
        const userDoc = await db.collection("users").doc(email).get();
        if (!userDoc.exists || !userDoc.data().walletAddress) continue;
        const userAddress = userDoc.data().walletAddress;
        const price = calcDiskPrice(sub.subscribedGb, pricing);

        try {
          // Attempt payment
          const balance = await tokenContract.balanceOf(userAddress);
          const allowance = await tokenContract.allowance(userAddress, executorWallet.address);
          if (balance < ethers.parseEther(price.toString()) || allowance < ethers.parseEther(price.toString())) {
            throw new Error("Insufficient balance or allowance");
          }

          const tx = await tokenContract.transferFrom(userAddress, executorWallet.address, ethers.parseEther(price.toString()));
          await tx.wait();

          // Success - renew
          const nextEnd = nowMs + 30 * 24 * 60 * 60 * 1000;
          await db.collection("disk_subscriptions").doc(email).update({
            currentCycleStart: nowMs,
            currentCycleEnd: nextEnd,
            status: "active",
            overdueSince: null,
          });

          // Send success email
          const body = `${emailComponents.sectionTitle("Subscription Renewed", "#22d3ee")}
          ${emailComponents.subtitle(`Your ${sub.subscribedGb}GB Vision Disk plan was successfully renewed.`)}
          ${emailComponents.infoCard([
            ["Monthly Charge", `${price} VCN`, true],
            ["Next Billing", new Date(nextEnd).toLocaleDateString(), false],
          ])}`;
          await sendSecurityEmail(email, "Vision Disk Renewed", emailBaseLayout(body, "Renewal successful"));
        } catch (paymentErr) {
          console.warn(`[DiskBilling] Failed to charge ${email}: ${paymentErr.message}`);
          // Mark overdue
          if (sub.status !== "overdue") {
            await db.collection("disk_subscriptions").doc(email).update({
              status: "overdue",
              overdueSince: nowMs,
            });
            // Overdue email
            const body = `
               ${emailComponents.subtitle("We couldn't process the VCN payment for your Vision Disk subscription. Uploads are now blocked.")}
               ${emailComponents.alertBox("Please ensure you have sufficient VCN balance and allowance within 3 days to avoid cancellation.", "warning")}
             `;
            await sendSecurityEmail(email, "Vision Disk Payment Failed", emailBaseLayout(body, "Action Required for Vision Disk"));
          }
        }
      }

      // 2. Handle Overdues & Deletions
      if (sub.status === "overdue" || sub.status === "expired") {
        const daysOverdue = Math.floor((nowMs - (sub.overdueSince || sub.currentCycleEnd)) / (24 * 60 * 60 * 1000));

        if (daysOverdue === 3 && sub.status === "overdue") {
          // Cancel subscription after 3 days
          await db.collection("disk_subscriptions").doc(email).update({ status: "canceled" });
          const body = `${emailComponents.sectionTitle("Subscription Canceled", "#ef4444")}
            ${emailComponents.subtitle("Your subscription was canceled due to unpaid balance. You have 4 remaining days to download your files before permanent deletion.")}`;
          await sendSecurityEmail(email, "Vision Disk Canceled", emailBaseLayout(body, "Subscription canceled"));
        } else if (daysOverdue === 6 && sub.status !== "pending_delete") {
          // 6th day warning
          const body = `${emailComponents.sectionTitle("Data Deletion Tomorrow", "#ef4444")}
             ${emailComponents.alertBox("All your Vision Disk data will be permanently deleted tomorrow due to an inactive subscription. Please download your files immediately.", "warning")}`;
          await sendSecurityEmail(email, "Vision Disk Data Deletion Warning", emailBaseLayout(body, "Final Warning"));
        } else if (daysOverdue >= 7 && sub.status !== "deleted") {
          // Delete data
          const body = `${emailComponents.sectionTitle("Data Deleted", "#ef4444")}
            ${emailComponents.subtitle("Your Vision Disk data has been permanently deleted as your subscription remained inactive.")}`;
          await sendSecurityEmail(email, "Vision Disk Data Deleted", emailBaseLayout(body, "Data deletion complete"));

          await deleteUserDiskData(email);
          await db.collection("disk_subscriptions").doc(email).update({ status: "deleted" });
        }
      }
    } catch (docErr) {
      console.error(`[DiskBilling] Error processing ${email}: `, docErr);
    }
  }
});

// =====================================================
// DISTRIBUTED STORAGE - Upload / Download via Vision Nodes
// =====================================================

const CHUNK_SIZE = 256 * 1024; // 256KB - matches vision-node chunkManager

function sha256Hex(buffer) {
  const crypto = require("crypto");
  return crypto.createHash("sha256").update(buffer).digest("hex");
}

function computeMerkleRoot(hashes) {
  const crypto = require("crypto");
  if (hashes.length === 0) return sha256Hex(Buffer.alloc(0));
  if (hashes.length === 1) return hashes[0];
  let level = [...hashes];
  while (level.length > 1) {
    const next = [];
    for (let i = 0; i < level.length; i += 2) {
      if (i + 1 < level.length) {
        const combined = level[i] + level[i + 1];
        next.push(crypto.createHash("sha256").update(Buffer.from(combined, "hex")).digest("hex"));
      } else {
        next.push(level[i]);
      }
    }
    level = next;
  }
  return level[0];
}

function chunkBuffer(data) {
  const chunks = [];
  const infos = [];
  let offset = 0;
  while (offset < data.length) {
    const end = Math.min(offset + CHUNK_SIZE, data.length);
    const chunk = data.subarray(offset, end);
    const hash = sha256Hex(chunk);
    chunks.push(Buffer.from(chunk));
    infos.push({ index: chunks.length - 1, hash, size: chunk.length, offset });
    offset = end;
  }
  const merkleRoot = computeMerkleRoot(infos.map((c) => c.hash));
  return { chunks, infos, merkleRoot, totalSize: data.length };
}

/**
 * diskUploadPart - Upload a part of a large file for multipart upload.
 * Client splits large files into ~3MB parts and sends each via this function.
 * Parts are stored temporarily in Firestore and assembled during diskUpload.
 */
exports.diskUploadPart = onCall({ cors: true, maxInstances: 20, timeoutSeconds: 60, memory: "512MiB" }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const { uploadSessionId, partIndex, totalParts, partData } = request.data;

  if (!uploadSessionId || partIndex === undefined || !totalParts || !partData) {
    throw new HttpsError("invalid-argument", "uploadSessionId, partIndex, totalParts, and partData are required.");
  }

  // Store part in Firestore
  const partRef = db.collection("disk_upload_sessions").doc(uploadSessionId)
    .collection("parts").doc(String(partIndex));

  await partRef.set({
    index: partIndex,
    data: partData, // base64 encoded part
    size: Buffer.from(partData, "base64").length,
    created_at: Date.now(),
  });

  return { success: true, partIndex, totalParts };
});

/**
 * diskUpload - Upload file to distributed storage
 * Receives file as base64, chunks it, stages chunks in Firestore,
 * registers in chunk_registry for Vision Nodes to pull.
 * Supports: direct base64, temp Storage path, or multipart upload session.
 */
exports.diskUpload = onCall({ cors: true, maxInstances: 10, timeoutSeconds: 540, memory: "2GiB", secrets: ["EMAIL_USER", "EMAIL_APP_PASSWORD"] }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { fileData, tempStoragePath, uploadSessionId, fileName, fileType, folder, fileSize, thumbnail, preserveOriginal, isEncrypted, salt, iv } = request.data;

  if (!fileData && !tempStoragePath && !uploadSessionId) {
    throw new HttpsError("invalid-argument", "fileData, tempStoragePath, or uploadSessionId is required.");
  }
  if (!fileName) {
    throw new HttpsError("invalid-argument", "fileName is required.");
  }

  // Check subscription
  const subDoc = await db.collection("disk_subscriptions").doc(email).get();
  if (!subDoc.exists || !["active", "grace_period"].includes(subDoc.data().status)) {
    throw new HttpsError("failed-precondition", "Active disk subscription required.");
  }

  // Get file buffer from one of three sources
  let buffer;
  if (uploadSessionId) {
    // Multipart upload: assemble from parts stored in Firestore
    try {
      const partsSnap = await db.collection("disk_upload_sessions").doc(uploadSessionId)
        .collection("parts").orderBy("index").get();

      if (partsSnap.empty) {
        throw new HttpsError("not-found", "No upload parts found for session " + uploadSessionId);
      }

      const partBuffers = partsSnap.docs.map(d => Buffer.from(d.data().data, "base64"));
      buffer = Buffer.concat(partBuffers);

      // Clean up session parts (fire-and-forget)
      const cleanupBatch = db.batch();
      partsSnap.docs.forEach(d => cleanupBatch.delete(d.ref));
      cleanupBatch.delete(db.collection("disk_upload_sessions").doc(uploadSessionId));
      cleanupBatch.commit().catch(() => { });

      console.log(`[Disk] Assembled ${partsSnap.size} parts for session ${uploadSessionId}: ${buffer.length} bytes`);
    } catch (sessionErr) {
      if (sessionErr instanceof HttpsError) throw sessionErr;
      throw new HttpsError("internal", "Failed to assemble multipart upload: " + sessionErr.message);
    }
  } else if (tempStoragePath) {
    // Large file: read from Firebase Storage temp path (legacy support)
    try {
      const tempFile = admin.storage().bucket().file(tempStoragePath);
      const [fileBuffer] = await tempFile.download();
      buffer = fileBuffer;
      tempFile.delete().catch(() => { });
    } catch (storageErr) {
      throw new HttpsError("internal", "Failed to read temp file from storage: " + storageErr.message);
    }
  } else {
    buffer = Buffer.from(fileData, "base64");
  }

  const maxFileSize = 500 * 1024 * 1024; // 500MB per file
  if (buffer.length > maxFileSize) {
    throw new HttpsError("invalid-argument", `File exceeds ${maxFileSize / (1024 * 1024)}MB limit.`);
  }

  // Verify received data matches expected size (detect base64 truncation)
  if (fileSize && Math.abs(buffer.length - fileSize) > 1024) {
    throw new HttpsError("data-loss",
      `File data truncated during upload. Expected ${fileSize} bytes but received ${buffer.length} bytes. ` +
      `File may be too large for direct base64 upload. Please try again.`
    );
  }

  // Check usage vs limit
  const sub = subDoc.data();
  const limitBytes = sub.subscribedGb * 1024 * 1024 * 1024;
  const usageSnap = await db.collection("users").doc(email).collection("disk_files").get();
  const currentUsage = usageSnap.docs.reduce((sum, d) => sum + (d.data().size || 0), 0);
  if (currentUsage + buffer.length > limitBytes) {
    throw new HttpsError("resource-exhausted", "Storage limit exceeded.");
  }

  const ext = fileName.split(".").pop()?.toLowerCase() || "";
  const category = getFileCategoryServer(fileType || "application/octet-stream");
  const fileId = `${Date.now()}_${fileName.replace(/[^a-zA-Z0-9._\-() ]/g, "_")}`;
  const now = new Date().toISOString();
  const targetFolder = folder || "/";

  // AI Abstract for document files
  let fileAbstract = "";
  const docTypes = ["pdf", "document", "word", "text/", "sheet", "excel", "csv", "presentation"];
  const isDocument = docTypes.some((t) => (fileType || "").includes(t)) || ["pdf", "doc", "docx", "txt", "md", "csv", "xlsx", "pptx"].includes(ext);

  if (isDocument && buffer.length < 5 * 1024 * 1024) { // Only for docs < 5MB
    try {
      const textPreview = buffer.toString("utf8").substring(0, 3000).replace(/[^\x20-\x7E\n\rㄱ-힣가-힣]/g, "");
      if (textPreview.trim().length > 50) {
        const deepseekKey = process.env.DEEPSEEK_API_KEY || "";
        if (deepseekKey) {
          const axios = require("axios");
          const resp = await axios.post("https://api.deepseek.com/chat/completions", {
            model: "deepseek-chat",
            messages: [
              { role: "system", content: "You are a concise document summarizer. Generate a 100-200 character abstract/summary of the document. Respond with ONLY the abstract text, nothing else." },
              { role: "user", content: `Summarize this document (filename: ${fileName}):\n\n${textPreview}` },
            ],
            temperature: 0.3,
            max_tokens: 100,
          }, { headers: { Authorization: `Bearer ${deepseekKey}` }, timeout: 10000 });

          fileAbstract = resp.data?.choices?.[0]?.message?.content?.trim() || "";
          if (fileAbstract.length > 300) fileAbstract = fileAbstract.substring(0, 297) + "...";
        }
      }
    } catch (aiErr) {
      console.warn("[Disk] AI abstract generation failed (non-blocking):", aiErr.message);
    }
  }
  // ── Video Transcoding (when not preserveOriginal) ──
  let finalBuffer = buffer;
  let finalFileName = fileName;
  let finalFileType = fileType || "application/octet-stream";
  let optimizationMeta = {};

  const isVideo = (finalFileType || "").startsWith("video/");
  const videoExt = fileName.split(".").pop()?.toLowerCase() || "";
  const webPlayableFormats = ["mp4", "webm", "ogg"];
  const needsTranscode = isVideo && !preserveOriginal && buffer.length <= 100 * 1024 * 1024; // Only transcode under 100MB

  if (needsTranscode) {
    try {
      const ffmpegInstaller = require("@ffmpeg-installer/ffmpeg");
      const ffmpeg = require("fluent-ffmpeg");
      ffmpeg.setFfmpegPath(ffmpegInstaller.path);
      const os = require("os");
      const path = require("path");
      const fs = require("fs");

      const tmpDir = os.tmpdir();
      const inputPath = path.join(tmpDir, `input_${Date.now()}.${videoExt || "mp4"}`);
      const outputPath = path.join(tmpDir, `output_${Date.now()}.mp4`);

      fs.writeFileSync(inputPath, buffer);

      // Transcode to H.264/MP4
      await new Promise((resolve, reject) => {
        ffmpeg(inputPath)
          .outputOptions([
            "-c:v libx264",
            "-preset fast",
            "-crf 23",
            "-c:a aac",
            "-b:a 192k",
            "-movflags +faststart",
            "-vf scale='min(1920,iw)':'-2'",  // Max 1080p width
            "-max_muxing_queue_size 1024",
          ])
          .output(outputPath)
          .on("end", resolve)
          .on("error", reject)
          .run();
      });

      const transcodedBuffer = fs.readFileSync(outputPath);
      const originalSize = buffer.length;

      console.log(`[Disk] Transcoded ${fileName}: ${(originalSize / 1024 / 1024).toFixed(1)}MB → ${(transcodedBuffer.length / 1024 / 1024).toFixed(1)}MB`);

      optimizationMeta = {
        optimized: true,
        originalType: finalFileType,
        originalSize,
        originalExtension: videoExt,
      };

      finalBuffer = transcodedBuffer;
      finalFileName = fileName.replace(/\.[^.]+$/, ".mp4");
      finalFileType = "video/mp4";

      // Cleanup temp files
      try { fs.unlinkSync(inputPath); } catch (e) { /* ignore */ }
      try { fs.unlinkSync(outputPath); } catch (e) { /* ignore */ }
    } catch (transcodeErr) {
      console.warn(`[Disk] Transcoding failed (using original): ${transcodeErr.message}`);
      // Continue with original buffer if transcoding fails
    }
  }

  // Record preserveOriginal flag
  if (preserveOriginal) {
    optimizationMeta = { preserveOriginal: true };
  }

  // ── Try Distributed Storage (Primary) ──
  try {
    const result = chunkBuffer(finalBuffer);
    const cid = `vcn://${result.merkleRoot}`;
    const fileKey = `file_${Date.now()}_${require("crypto").randomBytes(4).toString("hex")}`;

    // Stage chunks in Firestore + register in chunk_registry
    const BATCH_LIMIT = 400;
    let batchOps = db.batch();
    let opCount = 0;

    for (let i = 0; i < result.chunks.length; i++) {
      const chunkInfo = result.infos[i];
      const chunkData64 = result.chunks[i].toString("base64");

      const stagingRef = db.collection("staging_chunks").doc(chunkInfo.hash);
      batchOps.set(stagingRef, {
        hash: chunkInfo.hash,
        data: chunkData64,
        file_key: fileKey,
        index: chunkInfo.index,
        size: chunkInfo.size,
        owner_email: email,
        created_at: Date.now(),
        replicas: 0,
        status: "pending",
      });
      opCount++;

      const registryRef = db.collection("chunk_registry").doc(chunkInfo.hash);
      batchOps.set(registryRef, {
        hash: chunkInfo.hash,
        file_key: fileKey,
        size: chunkInfo.size,
        index: chunkInfo.index,
        updated_at: Date.now(),
      }, { merge: true });
      opCount++;

      if (opCount >= BATCH_LIMIT) {
        await batchOps.commit();
        batchOps = db.batch();
        opCount = 0;
      }
    }

    // Save file metadata
    // ── Server-Side Thumbnail Generation & Storage ──
    let thumbnailURL = "";
    try {
      const bucket = admin.storage().bucket();
      const thumbPath = `disk_thumbnails/${email}/${fileId}.webp`;
      const thumbFile = bucket.file(thumbPath);

      if (fileType && fileType.startsWith("image/")) {
        // Generate thumbnail from image using sharp
        const sharp = require("sharp");
        const thumbBuffer = await sharp(buffer)
          .resize(400, 400, { fit: "inside", withoutEnlargement: true })
          .webp({ quality: 75 })
          .toBuffer();
        await thumbFile.save(thumbBuffer, { contentType: "image/webp" });
        const [signedUrl] = await thumbFile.getSignedUrl({ action: "read", expires: "2030-01-01" });
        thumbnailURL = signedUrl;
        console.log(`[Disk] Generated image thumbnail: ${thumbPath} (${thumbBuffer.length} bytes)`);
      } else if (fileType && fileType.startsWith("video/") && thumbnail) {
        // For video: save client-provided base64 thumbnail to Storage
        const base64Match = thumbnail.match(/^data:([^;]+);base64,(.+)$/);
        if (base64Match) {
          const thumbBuffer = Buffer.from(base64Match[2], "base64");
          const thumbContentType = base64Match[1] || "image/webp";
          await thumbFile.save(thumbBuffer, { contentType: thumbContentType });
          const [signedUrl] = await thumbFile.getSignedUrl({ action: "read", expires: "2030-01-01" });
          thumbnailURL = signedUrl;
          console.log(`[Disk] Saved video thumbnail: ${thumbPath} (${thumbBuffer.length} bytes)`);
        }
      }
    } catch (thumbErr) {
      console.warn("[Disk] Thumbnail generation/upload failed (non-blocking):", thumbErr.message);
      // thumbnailURL stays empty, fallback to client base64
    }

    const fileMetadata = {
      id: fileId,
      name: finalFileName,
      size: finalBuffer.length,
      type: finalFileType,
      folder: targetFolder,
      storagePath: `distributed://${cid}`,
      storageType: "distributed",
      downloadURL: "",
      cid,
      fileKey,
      merkleRoot: result.merkleRoot,
      chunkCount: result.chunks.length,
      chunkHashes: result.infos.map((c) => c.hash),
      createdAt: now,
      updatedAt: now,
      category,
      extension: finalFileName.split(".").pop()?.toLowerCase() || ext,
      replicationStatus: "staging",
      targetReplicas: 3,
      currentReplicas: 0,
      thumbnail: thumbnail || "",
      thumbnailURL,
      abstract: fileAbstract,
      // Encryption metadata
      isEncrypted: isEncrypted || false,
      salt: salt || "",
      iv: iv || "",
      ...optimizationMeta,
    };

    const fileRef = db.collection("users").doc(email).collection("disk_files").doc(fileId);
    batchOps.set(fileRef, fileMetadata);
    opCount++;

    if (opCount > 0) {
      await batchOps.commit();
    }

    console.log(`[Disk] Uploaded ${fileName} -> ${fileKey} (${result.chunks.length} chunks, ${buffer.length} bytes, CID: ${cid})`);

    return {
      success: true,
      fileId,
      fileKey,
      cid,
      merkleRoot: result.merkleRoot,
      chunkCount: result.chunks.length,
      totalSize: buffer.length,
      storageType: "distributed",
      abstract: fileAbstract,
      thumbnailURL,
    };
  } catch (distributedErr) {
    // ── Fallback: Firebase Storage ──
    console.error("[Disk] Distributed storage FAILED, using Firebase Storage fallback:", distributedErr.message);

    try {
      const storagePath = `disk/${email}${targetFolder === "/" ? "" : targetFolder}/${fileId}`;
      const bucket = admin.storage().bucket();
      const file = bucket.file(storagePath);
      await file.save(buffer, { contentType: fileType || "application/octet-stream" });

      // Get signed URL (valid 7 days)
      const [signedUrl] = await file.getSignedUrl({ action: "read", expires: Date.now() + 7 * 24 * 60 * 60 * 1000 });

      const fileMetadata = {
        id: fileId,
        name: fileName,
        size: buffer.length,
        type: fileType || "application/octet-stream",
        folder: targetFolder,
        storagePath,
        storageType: "cloud",
        downloadURL: signedUrl,
        createdAt: now,
        updatedAt: now,
        category,
        extension: ext,
        thumbnail: thumbnail || "",
        abstract: fileAbstract,
        fallbackReason: distributedErr.message,
      };

      await db.collection("users").doc(email).collection("disk_files").doc(fileId).set(fileMetadata);

      // ── ALERT: Send admin notification about fallback ──
      try {
        const adminEmails = ["sangky94@gmail.com"];
        for (const adminEmail of adminEmails) {
          const body = `
            <div style="font-family: monospace; padding: 20px; background: #1a1a2e; color: #e0e0e0; border-radius: 12px;">
              <h2 style="color: #ff6b6b; margin-bottom: 16px;">Disk Storage Fallback Alert</h2>
              <p>Distributed storage failed and Firebase Storage was used as fallback.</p>
              <table style="width: 100%; border-collapse: collapse; margin-top: 12px;">
                <tr><td style="padding: 8px; border-bottom: 1px solid #333; color: #888;">User</td><td style="padding: 8px; border-bottom: 1px solid #333;">${email}</td></tr>
                <tr><td style="padding: 8px; border-bottom: 1px solid #333; color: #888;">File</td><td style="padding: 8px; border-bottom: 1px solid #333;">${fileName}</td></tr>
                <tr><td style="padding: 8px; border-bottom: 1px solid #333; color: #888;">Size</td><td style="padding: 8px; border-bottom: 1px solid #333;">${(buffer.length / 1024 / 1024).toFixed(2)} MB</td></tr>
                <tr><td style="padding: 8px; border-bottom: 1px solid #333; color: #888;">Error</td><td style="padding: 8px; border-bottom: 1px solid #333; color: #ff6b6b;">${distributedErr.message}</td></tr>
                <tr><td style="padding: 8px; color: #888;">Time</td><td style="padding: 8px;">${now}</td></tr>
              </table>
            </div>
          `;
          await sendSecurityEmail(adminEmail, "[ALERT] Disk Storage Fallback Triggered", body);
        }
      } catch (emailErr) {
        console.error("[Disk] Failed to send admin fallback alert:", emailErr.message);
      }

      console.log(`[Disk] FALLBACK: ${fileName} saved to Firebase Storage for ${email}`);

      return {
        success: true,
        fileId,
        fileKey: "",
        cid: "",
        merkleRoot: "",
        chunkCount: 0,
        totalSize: buffer.length,
        storageType: "cloud",
        abstract: fileAbstract,
      };
    } catch (fallbackErr) {
      console.error("[Disk] Even fallback storage failed:", fallbackErr.message);
      throw new HttpsError("internal", "Upload failed: " + distributedErr.message);
    }
  }
});

function getFileCategoryServer(mimeType) {
  if (mimeType.startsWith("image/")) return "image";
  if (mimeType.startsWith("video/")) return "video";
  if (mimeType.startsWith("audio/")) return "audio";
  if (mimeType.includes("pdf")) return "pdf";
  if (mimeType.includes("document") || mimeType.includes("word")) return "document";
  if (mimeType.includes("sheet") || mimeType.includes("excel") || mimeType.includes("csv")) return "spreadsheet";
  if (mimeType.includes("presentation") || mimeType.includes("powerpoint")) return "presentation";
  if (mimeType.includes("zip") || mimeType.includes("rar") || mimeType.includes("tar") || mimeType.includes("compress")) return "archive";
  if (mimeType.includes("text/")) return "text";
  return "other";
}

/**
 * diskDownload - Download file from distributed storage
 * Retrieves chunks from staging or from Vision Nodes, reassembles.
 */
exports.diskDownload = onCall({ cors: true, maxInstances: 10, timeoutSeconds: 120, memory: "512MiB" }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { fileId } = request.data;

  if (!fileId) {
    throw new HttpsError("invalid-argument", "fileId is required.");
  }

  // Get file metadata
  const fileDoc = await db.collection("users").doc(email).collection("disk_files").doc(fileId).get();
  if (!fileDoc.exists) {
    throw new HttpsError("not-found", "File not found.");
  }

  const fileMeta = fileDoc.data();

  // ── Handle Cloud Storage (Fallback) ──
  if (fileMeta.storageType === "cloud") {
    try {
      const bucket = admin.storage().bucket();
      const file = bucket.file(fileMeta.storagePath);
      const [buffer] = await file.download();
      return {
        success: true,
        fileData: buffer.toString("base64"),
        fileName: fileMeta.name,
        fileType: fileMeta.type,
        size: buffer.length,
        storageType: "cloud",
      };
    } catch (err) {
      console.error("[DiskDownload] Fallback file fetch failed:", err);
      throw new HttpsError("internal", "Failed to retrieve fallback file: " + err.message);
    }
  }

  // ── Handle Distributed Storage ──
  const chunkHashes = fileMeta.chunkHashes || [];
  if (chunkHashes.length === 0) {
    throw new HttpsError("internal", "File has no chunks.");
  }

  // Retrieve chunks in parallel for maximum speed
  const chunkPromises = chunkHashes.map(async (hash) => {
    const stagingDoc = await db.collection("staging_chunks").doc(hash).get();
    if (stagingDoc.exists && stagingDoc.data().data) {
      return Buffer.from(stagingDoc.data().data, "base64");
    }
    throw new HttpsError("unavailable", `Chunk ${hash.slice(0, 16)}... not yet available on network.`);
  });

  const orderedChunks = await Promise.all(chunkPromises);

  // Reassemble
  const assembled = Buffer.concat(orderedChunks);

  // Verify merkle root
  const computedRoot = computeMerkleRoot(chunkHashes);
  if (fileMeta.merkleRoot && computedRoot !== fileMeta.merkleRoot) {
    throw new HttpsError("data-loss", "Data integrity check failed: Merkle root mismatch.");
  }

  return {
    success: true,
    fileData: assembled.toString("base64"),
    fileName: fileMeta.name,
    fileType: fileMeta.type,
    size: assembled.length,
    cid: fileMeta.cid,
    storageType: fileMeta.storageType || "distributed",
  };
});

/**
 * diskDelete - Delete file from distributed storage
 */
exports.diskDelete = onCall({ cors: true }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { fileId } = request.data;

  if (!fileId) {
    throw new HttpsError("invalid-argument", "fileId is required.");
  }

  const fileDoc = await db.collection("users").doc(email).collection("disk_files").doc(fileId).get();
  if (!fileDoc.exists) {
    throw new HttpsError("not-found", "File not found.");
  }

  const fileMeta = fileDoc.data();

  // ── Auto-unpublish: remove from global market if published ──
  if (fileMeta.isPublished) {
    try {
      await db.collection("published_materials").doc(fileId).delete();
      console.log(`[DiskDelete] Auto-unpublished file ${fileId} from market`);
    } catch (unpubErr) {
      console.warn("[DiskDelete] Failed to auto-unpublish (non-blocking):", unpubErr.message);
    }
  }

  if (fileMeta.storageType === "cloud") {
    try {
      const bucket = admin.storage().bucket();
      const file = bucket.file(fileMeta.storagePath);
      await file.delete().catch((e) => console.warn("[DiskDelete] Storage file delete failed (maybe already gone):", e.message));
    } catch (err) {
      console.error("[DiskDelete] Cloud delete failed:", err);
    }
    await fileDoc.ref.delete();
    return { success: true, mode: "cloud" };
  }

  const chunkHashes = fileMeta.chunkHashes || [];

  // Delete staging chunks
  const batch = db.batch();
  for (const hash of chunkHashes) {
    batch.delete(db.collection("staging_chunks").doc(hash));
    batch.delete(db.collection("chunk_registry").doc(hash));
  }
  // Delete file metadata
  batch.delete(fileDoc.ref);
  await batch.commit();

  console.log(`[Disk] Deleted ${fileMeta.name} (${chunkHashes.length} chunks)`);

  return { success: true, deletedChunks: chunkHashes.length };
});

/**
 * diskGetChunk - Retrieve a single chunk by hash.
 * This is used for granular/prioritized fetching.
 */
exports.diskGetChunk = onCall({ cors: true, maxInstances: 30, timeoutSeconds: 30, memory: "256MiB" }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const { chunkHash } = request.data;
  if (!chunkHash) throw new HttpsError("invalid-argument", "chunkHash is required.");

  // For now, chunks are in staging_chunks
  const stagingDoc = await db.collection("staging_chunks").doc(chunkHash).get();
  if (stagingDoc.exists && stagingDoc.data().data) {
    return { success: true, chunkHash, data: stagingDoc.data().data }; // base64
  }

  // Fallback check in global registry (if exists)
  const regDoc = await db.collection("chunk_registry").doc(chunkHash).get();
  if (!regDoc.exists) {
    throw new HttpsError("not-found", "Chunk not found on network.");
  }

  // If we had P2P node fetch logic, it would go here.
  throw new HttpsError("unavailable", "Chunk is currently being replicated to nodes.");
});

// ─── Admin Market Moderation ─────────────────────────────────────────────────

/**
 * adminRemoveMarketItem - Admin forcefully removes a published item from the market.
 * Also logs the violation and optionally auto-bans the publisher.
 */
exports.adminRemoveMarketItem = onCall({ cors: true }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const adminEmail = request.auth.token.email?.toLowerCase();
  if (!adminEmail) throw new HttpsError("permission-denied", "Admin access required.");

  // Verify admin role
  const adminDoc = await db.collection("users").doc(adminEmail).get();
  if (!adminDoc.exists || adminDoc.data().role !== "admin") {
    throw new HttpsError("permission-denied", "Admin access required.");
  }

  const { fileId, reason, autoBan } = request.data;
  if (!fileId) throw new HttpsError("invalid-argument", "fileId is required.");
  if (!reason) throw new HttpsError("invalid-argument", "reason is required.");

  // 1. Get the published item metadata
  const marketDoc = await db.collection("published_materials").doc(fileId).get();
  if (!marketDoc.exists) {
    throw new HttpsError("not-found", "Published item not found in market.");
  }
  const itemData = marketDoc.data();
  const publisherEmail = (itemData.publisherEmail || "").toLowerCase();

  // 2. Remove from published_materials
  await db.collection("published_materials").doc(fileId).delete();

  // 3. Update original file's isPublished flag (if the file still exists)
  if (publisherEmail) {
    try {
      const fileRef = db.collection("users").doc(publisherEmail).collection("disk_files").doc(fileId);
      const fileDoc = await fileRef.get();
      if (fileDoc.exists) {
        await fileRef.update({
          isPublished: false,
          priceVcn: 0,
          adminRemoved: true,
          adminRemovedAt: new Date().toISOString(),
          adminRemovedBy: adminEmail,
          adminRemoveReason: reason,
        });
      }
    } catch (err) {
      console.warn("[AdminMarket] Failed to update original file:", err.message);
    }
  }

  // 4. Log the violation
  const now = new Date().toISOString();
  const violationRef = db.collection("market_violations").doc();
  await violationRef.set({
    id: violationRef.id,
    fileId,
    fileName: itemData.name || "Unknown",
    fileType: itemData.type || "",
    publisherEmail,
    reason,
    action: "removed",
    adminEmail,
    createdAt: now,
  });

  // 5. Increment user's violation count
  if (publisherEmail) {
    const banRef = db.collection("publish_bans").doc(publisherEmail);
    const banDoc = await banRef.get();
    if (banDoc.exists) {
      await banRef.update({
        violationCount: (banDoc.data().violationCount || 0) + 1,
        lastViolationAt: now,
        lastViolationReason: reason,
      });
    } else {
      await banRef.set({
        email: publisherEmail,
        isBanned: false,
        violationCount: 1,
        lastViolationAt: now,
        lastViolationReason: reason,
        createdAt: now,
      });
    }
  }

  // 6. Auto-ban if requested
  if (autoBan && publisherEmail) {
    const banRef = db.collection("publish_bans").doc(publisherEmail);
    await banRef.update({
      isBanned: true,
      bannedAt: now,
      bannedBy: adminEmail,
      banReason: reason,
      banType: "permanent",
    });

    // Also remove ALL other published items from this user
    const userItems = await db.collection("published_materials")
      .where("publisherEmail", "==", publisherEmail)
      .get();

    const batch = db.batch();
    let removedCount = 0;
    for (const doc of userItems.docs) {
      batch.delete(doc.ref);
      removedCount++;

      // Log each removal
      const vRef = db.collection("market_violations").doc();
      batch.set(vRef, {
        id: vRef.id,
        fileId: doc.id,
        fileName: doc.data().name || "Unknown",
        fileType: doc.data().type || "",
        publisherEmail,
        reason: `Auto-removed: publisher banned (${reason})`,
        action: "auto_removed_ban",
        adminEmail,
        createdAt: now,
      });
    }
    if (removedCount > 0) {
      await batch.commit();
    }

    console.log(`[AdminMarket] Banned ${publisherEmail} and removed ${removedCount} additional items`);
  }

  console.log(`[AdminMarket] Removed item ${fileId} by admin ${adminEmail}. Reason: ${reason}`);

  return {
    success: true,
    fileId,
    publisherEmail,
    reason,
    autoBanned: autoBan || false,
  };
});

/**
 * adminBanPublisher - Admin bans or unbans a user from publishing to the market.
 */
exports.adminBanPublisher = onCall({ cors: true }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const adminEmail = request.auth.token.email?.toLowerCase();
  if (!adminEmail) throw new HttpsError("permission-denied", "Admin access required.");

  const adminDoc = await db.collection("users").doc(adminEmail).get();
  if (!adminDoc.exists || adminDoc.data().role !== "admin") {
    throw new HttpsError("permission-denied", "Admin access required.");
  }

  const { targetEmail, action, reason } = request.data;
  if (!targetEmail) throw new HttpsError("invalid-argument", "targetEmail is required.");
  if (!["ban", "unban"].includes(action)) throw new HttpsError("invalid-argument", "action must be 'ban' or 'unban'.");

  const now = new Date().toISOString();
  const banRef = db.collection("publish_bans").doc(targetEmail.toLowerCase());
  const banDoc = await banRef.get();

  if (action === "ban") {
    if (banDoc.exists) {
      await banRef.update({
        isBanned: true,
        bannedAt: now,
        bannedBy: adminEmail,
        banReason: reason || "Admin decision",
        banType: "permanent",
      });
    } else {
      await banRef.set({
        email: targetEmail.toLowerCase(),
        isBanned: true,
        bannedAt: now,
        bannedBy: adminEmail,
        banReason: reason || "Admin decision",
        banType: "permanent",
        violationCount: 0,
        createdAt: now,
      });
    }

    // Remove all published items from this user
    const userItems = await db.collection("published_materials")
      .where("publisherEmail", "==", targetEmail.toLowerCase())
      .get();

    if (!userItems.empty) {
      const batch = db.batch();
      userItems.docs.forEach(doc => batch.delete(doc.ref));
      await batch.commit();
      console.log(`[AdminMarket] Removed ${userItems.size} published items from banned user ${targetEmail}`);
    }

    console.log(`[AdminMarket] Banned ${targetEmail} from publishing by ${adminEmail}`);
  } else {
    // Unban
    if (banDoc.exists) {
      await banRef.update({
        isBanned: false,
        unbannedAt: now,
        unbannedBy: adminEmail,
      });
    }
    console.log(`[AdminMarket] Unbanned ${targetEmail} by ${adminEmail}`);
  }

  return { success: true, targetEmail: targetEmail.toLowerCase(), action };
});

/**
 * adminGetMarketModeration - Get market moderation data for admin dashboard.
 * Returns: published items list, banned users, violation history.
 */
exports.adminGetMarketModeration = onCall({ cors: true }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const adminEmail = request.auth.token.email?.toLowerCase();
  if (!adminEmail) throw new HttpsError("permission-denied", "Admin access required.");

  const adminDoc = await db.collection("users").doc(adminEmail).get();
  if (!adminDoc.exists || adminDoc.data().role !== "admin") {
    throw new HttpsError("permission-denied", "Admin access required.");
  }

  // 1. Get all published items
  const publishedSnap = await db.collection("published_materials")
    .orderBy("publishedAt", "desc")
    .limit(200)
    .get();

  const publishedItems = publishedSnap.docs.map(doc => ({
    id: doc.id,
    ...doc.data(),
  }));

  // 2. Get banned users
  const bansSnap = await db.collection("publish_bans")
    .where("isBanned", "==", true)
    .get();

  const bannedUsers = bansSnap.docs.map(doc => ({
    email: doc.id,
    ...doc.data(),
  }));

  // 3. Get recent violations
  const violationsSnap = await db.collection("market_violations")
    .orderBy("createdAt", "desc")
    .limit(50)
    .get();

  const violations = violationsSnap.docs.map(doc => doc.data());

  // 4. Stats
  const allBansSnap = await db.collection("publish_bans").get();
  const totalViolations = allBansSnap.docs.reduce((sum, doc) => sum + (doc.data().violationCount || 0), 0);

  return {
    success: true,
    publishedItems,
    bannedUsers,
    violations,
    stats: {
      totalPublished: publishedItems.length,
      totalBanned: bannedUsers.length,
      totalViolations,
    },
  };
});

/**
 * aiRequestIndexing - Request AI indexing for a file
 * Creates an IndexJob and marks the file as queued for processing.
 * Actual processing (parse/chunk/embed) will be implemented in Phase 2-3.
 */
exports.aiRequestIndexing = onCall({ cors: true, maxInstances: 10, timeoutSeconds: 30 }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { fileId, modelTarget = "both", force = false } = request.data || {};

  if (!fileId) throw new HttpsError("invalid-argument", "fileId is required.");
  if (!["openai", "gemini", "both"].includes(modelTarget)) {
    throw new HttpsError("invalid-argument", "modelTarget must be 'openai', 'gemini', or 'both'.");
  }

  // Verify file exists
  const fileRef = db.collection("users").doc(email).collection("disk_files").doc(fileId);
  const fileSnap = await fileRef.get();
  if (!fileSnap.exists) {
    throw new HttpsError("not-found", "File not found.");
  }

  const fileData = fileSnap.data();

  // Check if already indexed (unless force re-index)
  if (!force && fileData.indexingStatus === "indexed") {
    // Return existing job info
    const existingJobs = await db.collection("users").doc(email)
      .collection("ai_index_jobs")
      .where("fileId", "==", fileId)
      .where("status", "in", ["completed", "processing"])
      .orderBy("createdAt", "desc")
      .limit(1)
      .get();

    if (!existingJobs.empty) {
      const job = existingJobs.docs[0].data();
      return {
        jobId: existingJobs.docs[0].id,
        fileId,
        status: job.status,
        stages: job.stages,
        startedAt: job.startedAt,
        completedAt: job.completedAt,
        errorMessage: job.errorMessage || null,
      };
    }
  }

  // Check for already queued/processing job
  if (!force) {
    const pendingJobs = await db.collection("users").doc(email)
      .collection("ai_index_jobs")
      .where("fileId", "==", fileId)
      .where("status", "in", ["queued", "processing"])
      .limit(1)
      .get();

    if (!pendingJobs.empty) {
      const job = pendingJobs.docs[0].data();
      return {
        jobId: pendingJobs.docs[0].id,
        fileId,
        status: job.status,
        stages: job.stages,
        startedAt: job.startedAt,
        completedAt: job.completedAt || null,
        errorMessage: job.errorMessage || null,
      };
    }
  }

  // Create new IndexJob
  const now = new Date().toISOString();
  const defaultStage = { status: "pending" };
  const jobRef = db.collection("users").doc(email).collection("ai_index_jobs").doc();
  const jobData = {
    jobId: jobRef.id,
    fileId,
    tenantId: email,
    stages: {
      parse: { ...defaultStage },
      chunk: { ...defaultStage },
      embed_openai: modelTarget === "gemini" ? { status: "skipped" } : { ...defaultStage },
      embed_gemini: modelTarget === "openai" ? { status: "skipped" } : { ...defaultStage },
      keyword_index: { ...defaultStage },
      vector_index: { ...defaultStage },
    },
    status: "queued",
    modelTarget,
    startedAt: now,
    completedAt: null,
    errorMessage: null,
    createdAt: now,
    updatedAt: now,
  };

  const batch = db.batch();
  batch.set(jobRef, jobData);
  batch.update(fileRef, {
    indexingStatus: "queued",
    modelCompatibility: modelTarget,
    updatedAt: now,
  });
  await batch.commit();

  console.log(`[AI Storage] IndexJob created: ${jobRef.id} for file ${fileId} (model: ${modelTarget})`);

  return {
    jobId: jobRef.id,
    fileId,
    status: "queued",
    stages: jobData.stages,
    startedAt: now,
    completedAt: null,
    errorMessage: null,
  };
});

/**
 * aiGetIndexStatus - Get indexing status for a file
 * Returns the most recent IndexJob for the specified file.
 */
exports.aiGetIndexStatus = onCall({ cors: true, maxInstances: 10, timeoutSeconds: 10 }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { fileId } = request.data || {};

  if (!fileId) throw new HttpsError("invalid-argument", "fileId is required.");

  // Get most recent job for this file
  const jobsSnap = await db.collection("users").doc(email)
    .collection("ai_index_jobs")
    .where("fileId", "==", fileId)
    .orderBy("createdAt", "desc")
    .limit(1)
    .get();

  if (jobsSnap.empty) {
    // No job exists — check file's indexingStatus
    const fileRef = db.collection("users").doc(email).collection("disk_files").doc(fileId);
    const fileSnap = await fileRef.get();
    if (!fileSnap.exists) throw new HttpsError("not-found", "File not found.");

    return {
      jobId: null,
      fileId,
      status: "none",
      stages: null,
      startedAt: null,
      completedAt: null,
      errorMessage: null,
    };
  }

  const job = jobsSnap.docs[0].data();
  return {
    jobId: jobsSnap.docs[0].id,
    fileId,
    status: job.status,
    stages: job.stages,
    startedAt: job.startedAt,
    completedAt: job.completedAt || null,
    errorMessage: job.errorMessage || null,
  };
});

/**
 * aiProcessIngestion - Full ingestion pipeline for AI storage
 * Pipeline: parse → chunk → enrich → save
 *
 * Supports: PDF, TXT, MD, HTML, CSV, JSON, DOCX, code files
 * Enrichment: summary + keywords via DeepSeek API
 */
exports.aiProcessIngestion = onCall({ cors: true, maxInstances: 5, timeoutSeconds: 540, memory: "2GiB" }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { fileId, jobId, modelTarget = "both" } = request.data || {};

  if (!fileId) throw new HttpsError("invalid-argument", "fileId is required.");

  const fileRef = db.collection("users").doc(email).collection("disk_files").doc(fileId);
  const fileSnap = await fileRef.get();
  if (!fileSnap.exists) throw new HttpsError("not-found", "File not found.");
  const fileData = fileSnap.data();

  // Resolve or create IndexJob
  let jobRef;
  if (jobId) {
    jobRef = db.collection("users").doc(email).collection("ai_index_jobs").doc(jobId);
  } else {
    const existingJobs = await db.collection("users").doc(email)
      .collection("ai_index_jobs")
      .where("fileId", "==", fileId)
      .where("status", "in", ["queued", "processing"])
      .limit(1).get();
    if (!existingJobs.empty) {
      jobRef = existingJobs.docs[0].ref;
    } else {
      // Create one
      jobRef = db.collection("users").doc(email).collection("ai_index_jobs").doc();
      const now = new Date().toISOString();
      const defaultStage = { status: "pending" };
      await jobRef.set({
        jobId: jobRef.id, fileId, tenantId: email,
        stages: { parse: { ...defaultStage }, chunk: { ...defaultStage }, embed_openai: { ...defaultStage }, embed_gemini: { ...defaultStage }, keyword_index: { ...defaultStage }, vector_index: { ...defaultStage } },
        status: "queued", modelTarget, startedAt: now, createdAt: now, updatedAt: now,
      });
    }
  }

  const updateStage = async (stageName, stageData) => {
    const now = new Date().toISOString();
    await jobRef.update({ [`stages.${stageName}`]: { ...stageData, ...(stageData.status === "running" ? { startedAt: now } : {}), ...(["completed", "error"].includes(stageData.status) ? { completedAt: now } : {}) }, status: "processing", updatedAt: now });
  };

  try {
    await jobRef.update({ status: "processing", updatedAt: new Date().toISOString() });
    await fileRef.update({ indexingStatus: "processing" });

    // ── STAGE 1: PARSE ─────────────────────────────────────
    await updateStage("parse", { status: "running" });
    let rawText = "";
    const mimeType = fileData.type || "";
    const fileName = fileData.name || "";
    const ext = fileName.split(".").pop()?.toLowerCase() || "";

    // Get file buffer from storage
    let buffer;
    try {
      if (fileData.storagePath && fileData.storagePath.startsWith("distributed://")) {
        // Distributed storage: reassemble from chunks
        const chunkHashes = fileData.chunkHashes || [];
        if (chunkHashes.length === 0) throw new Error("No chunk data available");
        const chunks = [];
        for (const hash of chunkHashes) {
          const staging = await db.collection("staging_chunks").doc(hash).get();
          if (staging.exists && staging.data().data) {
            chunks.push(Buffer.from(staging.data().data, "base64"));
          }
        }
        buffer = Buffer.concat(chunks);
      } else if (fileData.storagePath) {
        const file = admin.storage().bucket().file(fileData.storagePath);
        const [data] = await file.download();
        buffer = data;
      } else if (fileData.downloadURL) {
        const axios = require("axios");
        const resp = await axios.get(fileData.downloadURL, { responseType: "arraybuffer", timeout: 30000 });
        buffer = Buffer.from(resp.data);
      }
    } catch (dlErr) {
      await updateStage("parse", { status: "error", errorMessage: "Failed to download file: " + dlErr.message });
      throw new HttpsError("internal", "Failed to download file for parsing.");
    }

    if (!buffer || buffer.length === 0) {
      await updateStage("parse", { status: "error", errorMessage: "Empty file buffer" });
      throw new HttpsError("internal", "Empty file buffer.");
    }

    // MIME-based parsing
    const textExts = ["txt", "md", "markdown", "csv", "json", "log", "yaml", "yml", "toml", "ini", "cfg", "env", "sh", "bash", "zsh", "fish", "ps1", "bat", "cmd"];
    const codeExts = ["js", "jsx", "ts", "tsx", "py", "rb", "go", "rs", "java", "kt", "swift", "c", "cpp", "h", "hpp", "cs", "php", "r", "sql", "sol", "vue", "svelte"];
    const isPdf = mimeType.includes("pdf") || ext === "pdf";
    const isHtml = mimeType.includes("html") || ["html", "htm"].includes(ext);
    const isDocx = mimeType.includes("wordprocessingml") || mimeType.includes("msword") || ext === "docx";
    const isText = mimeType.startsWith("text/") || textExts.includes(ext) || codeExts.includes(ext);

    if (isPdf) {
      try {
        const pdfParse = require("pdf-parse");
        const pdfData = await pdfParse(buffer);
        rawText = pdfData.text || "";
      } catch (pdfErr) {
        rawText = buffer.toString("utf8").replace(/[^\x20-\x7E\n\rㄱ-힣가-힣]/g, " ");
      }
    } else if (isHtml) {
      rawText = buffer.toString("utf8")
        .replace(/<script[\s\S]*?<\/script>/gi, "")
        .replace(/<style[\s\S]*?<\/style>/gi, "")
        .replace(/<[^>]+>/g, " ")
        .replace(/&nbsp;/g, " ")
        .replace(/&amp;/g, "&")
        .replace(/&lt;/g, "<")
        .replace(/&gt;/g, ">")
        .replace(/\s+/g, " ")
        .trim();
    } else if (isDocx) {
      // Extract text from DOCX XML
      try {
        const AdmZip = require("adm-zip");
        const zip = new AdmZip(buffer);
        const docXml = zip.readAsText("word/document.xml");
        rawText = docXml
          .replace(/<w:br[^>]*\/>/g, "\n")
          .replace(/<w:p[^>]*>/g, "\n")
          .replace(/<[^>]+>/g, "")
          .replace(/\s+/g, " ")
          .trim();
      } catch {
        rawText = buffer.toString("utf8").replace(/[^\x20-\x7E\n\rㄱ-힣가-힣]/g, " ");
      }
    } else if (isText) {
      rawText = buffer.toString("utf8");
    } else {
      // Unsupported type: try raw UTF-8 extraction
      rawText = buffer.toString("utf8").replace(/[^\x20-\x7E\n\rㄱ-힣가-힣]/g, " ").substring(0, 50000);
    }

    if (!rawText || rawText.trim().length < 10) {
      await updateStage("parse", { status: "completed", itemCount: 0 });
      await updateStage("chunk", { status: "skipped" });
      await jobRef.update({ status: "completed", completedAt: new Date().toISOString() });
      await fileRef.update({ indexingStatus: "indexed", parsedTextUri: "", indexedAt: new Date().toISOString() });
      return { jobId: jobRef.id, fileId, status: "completed", chunksCreated: 0, message: "No extractable text." };
    }

    // Detect language
    const koCount = (rawText.match(/[\uAC00-\uD7AF]/g) || []).length;
    const enCount = (rawText.match(/[a-zA-Z]/g) || []).length;
    const detectedLang = koCount > enCount * 0.3 ? "ko" : "en";

    await updateStage("parse", { status: "completed", itemCount: rawText.length });
    await fileRef.update({ language: detectedLang, parsedTextUri: `firestore://parsed` });

    // ── STAGE 2: CHUNK ─────────────────────────────────────
    await updateStage("chunk", { status: "running" });
    const MAX_CHUNK_CHARS = detectedLang === "ko" ? 2000 : 4000; // ~1000-1500 tokens
    const MIN_CHUNK_CHARS = 100;

    const semanticChunk = (text) => {
      const chunks = [];
      // Try heading-aware splitting first
      const headingPattern = /^(#{1,4}\s.+|[A-Z][A-Z\s]{5,}$)/gm;
      const sections = [];
      let lastIdx = 0;
      let match;
      while ((match = headingPattern.exec(text)) !== null) {
        if (match.index > lastIdx) {
          sections.push({ heading: "", text: text.substring(lastIdx, match.index) });
        }
        lastIdx = match.index;
      }
      if (lastIdx < text.length) {
        sections.push({ heading: "", text: text.substring(lastIdx) });
      }

      if (sections.length <= 1) {
        // Fallback: paragraph-based splitting
        const paragraphs = text.split(/\n\s*\n/);
        let currentChunk = "";
        for (const para of paragraphs) {
          if ((currentChunk + "\n\n" + para).length > MAX_CHUNK_CHARS && currentChunk.length >= MIN_CHUNK_CHARS) {
            chunks.push(currentChunk.trim());
            currentChunk = para;
          } else {
            currentChunk += (currentChunk ? "\n\n" : "") + para;
          }
        }
        if (currentChunk.trim().length >= MIN_CHUNK_CHARS) {
          chunks.push(currentChunk.trim());
        } else if (currentChunk.trim() && chunks.length > 0) {
          chunks[chunks.length - 1] += "\n\n" + currentChunk.trim();
        } else if (currentChunk.trim()) {
          chunks.push(currentChunk.trim());
        }
      } else {
        // Heading-aware: each section is a chunk candidate
        let currentChunk = "";
        for (const section of sections) {
          const sectionText = section.text.trim();
          if (!sectionText) continue;
          if ((currentChunk + "\n\n" + sectionText).length > MAX_CHUNK_CHARS && currentChunk.length >= MIN_CHUNK_CHARS) {
            chunks.push(currentChunk.trim());
            currentChunk = sectionText;
          } else {
            currentChunk += (currentChunk ? "\n\n" : "") + sectionText;
          }
        }
        if (currentChunk.trim()) chunks.push(currentChunk.trim());
      }

      // Safety: split any oversized chunks
      const finalChunks = [];
      for (const chunk of chunks) {
        if (chunk.length > MAX_CHUNK_CHARS * 1.5) {
          const words = chunk.split(/\s+/);
          let sub = "";
          for (const word of words) {
            if ((sub + " " + word).length > MAX_CHUNK_CHARS) {
              if (sub.trim()) finalChunks.push(sub.trim());
              sub = word;
            } else {
              sub += (sub ? " " : "") + word;
            }
          }
          if (sub.trim()) finalChunks.push(sub.trim());
        } else {
          finalChunks.push(chunk);
        }
      }

      return finalChunks;
    };

    const chunkTexts = semanticChunk(rawText);

    if (chunkTexts.length === 0) {
      await updateStage("chunk", { status: "completed", itemCount: 0 });
      await jobRef.update({ status: "completed", completedAt: new Date().toISOString() });
      await fileRef.update({ indexingStatus: "indexed", indexedAt: new Date().toISOString() });
      return { jobId: jobRef.id, fileId, status: "completed", chunksCreated: 0 };
    }

    const estimateTokens = (text) => {
      const koChars = (text.match(/[\uAC00-\uD7AF]/g) || []).length;
      const otherChars = text.length - koChars;
      return Math.ceil(koChars / 1.5 + otherChars / 4);
    };

    await updateStage("chunk", { status: "completed", itemCount: chunkTexts.length });

    // ── STAGE 3: ENRICH (summary + keywords via DeepSeek) ──
    await updateStage("embed_openai", { status: "skipped" }); // Phase 3
    await updateStage("embed_gemini", { status: "skipped" }); // Phase 3
    await updateStage("keyword_index", { status: "running" });

    const deepseekKey = process.env.DEEPSEEK_API_KEY || "";
    const axios = require("axios");
    const chunksCol = db.collection("users").doc(email).collection("ai_chunks");
    const now = new Date().toISOString();
    const savedChunks = [];

    // Process in batches of 5 to avoid API rate limits
    const ENRICH_BATCH = 5;
    for (let i = 0; i < chunkTexts.length; i += ENRICH_BATCH) {
      const batch = chunkTexts.slice(i, i + ENRICH_BATCH);
      const enrichResults = await Promise.all(batch.map(async (text, batchIdx) => {
        const chunkIndex = i + batchIdx;
        let summary = "";
        let keywords = [];

        // Enrich via DeepSeek (if key available and text is substantial)
        if (deepseekKey && text.length > 50) {
          try {
            const resp = await axios.post("https://api.deepseek.com/chat/completions", {
              model: "deepseek-chat",
              messages: [
                { role: "system", content: "You are a document analysis assistant. Given a text chunk, output JSON with exactly two fields: \"summary\" (a 1-2 sentence summary, max 200 chars) and \"keywords\" (array of 3-8 relevant keywords). Respond with ONLY valid JSON, nothing else." },
                { role: "user", content: text.substring(0, 3000) },
              ],
              temperature: 0.2,
              max_tokens: 300,
            }, {
              headers: { "Authorization": `Bearer ${deepseekKey}`, "Content-Type": "application/json" },
              timeout: 15000,
            });

            const content = resp.data?.choices?.[0]?.message?.content || "";
            try {
              const parsed = JSON.parse(content.replace(/```json\n?/g, "").replace(/```\n?/g, "").trim());
              summary = parsed.summary || "";
              keywords = Array.isArray(parsed.keywords) ? parsed.keywords : [];
            } catch {
              summary = content.substring(0, 200);
            }
          } catch (aiErr) {
            console.warn(`[AI Storage] Enrichment failed for chunk ${chunkIndex}:`, aiErr.message);
          }
        }

        // Determine chunk type
        let chunkType = "text";
        if (text.match(/^\|.*\|$/m)) chunkType = "table";
        else if (text.match(/^(#{1,4}\s)/m)) chunkType = "heading";
        else if (text.match(/^(\s*([-*]|\d+\.)\s)/m)) chunkType = "list";
        else if (codeExts.includes(ext) || text.match(/^(function |class |const |import |export |def |async )/m)) chunkType = "code";

        const sourceHash = require("crypto").createHash("sha256").update(text).digest("hex").substring(0, 16);

        return {
          chunkIndex,
          text,
          summary,
          keywords,
          chunkType,
          tokenCount: estimateTokens(text),
          sourceHash,
        };
      }));

      // Batch write to Firestore
      const writeBatch = db.batch();
      for (const result of enrichResults) {
        const chunkRef = chunksCol.doc();
        const chunkDoc = {
          chunkId: chunkRef.id,
          fileId,
          tenantId: email,
          chunkIndex: result.chunkIndex,
          chunkType: result.chunkType,
          text: result.text,
          summary: result.summary,
          keywords: result.keywords,
          tokenCount: result.tokenCount,
          sourceHash: result.sourceHash,
          embeddingOpenAiStatus: "pending",
          embeddingGeminiStatus: "pending",
          aclInheritance: true,
          createdAt: now,
        };
        writeBatch.set(chunkRef, chunkDoc);
        savedChunks.push(chunkDoc);
      }
      await writeBatch.commit();
    }

    await updateStage("keyword_index", { status: "completed", itemCount: savedChunks.length });
    await updateStage("vector_index", { status: "skipped" }); // Phase 3

    // ── FINALIZE ───────────────────────────────────────────
    const completedAt = new Date().toISOString();
    await jobRef.update({
      status: "completed",
      completedAt,
      updatedAt: completedAt,
    });
    await fileRef.update({
      indexingStatus: "indexed",
      indexedAt: completedAt,
      updatedAt: completedAt,
    });

    console.log(`[AI Storage] Ingestion complete: ${savedChunks.length} chunks for file ${fileId}`);

    return {
      jobId: jobRef.id,
      fileId,
      status: "completed",
      chunksCreated: savedChunks.length,
      language: detectedLang,
      totalTokens: savedChunks.reduce((sum, c) => sum + c.tokenCount, 0),
    };

  } catch (err) {
    console.error(`[AI Storage] Ingestion failed for ${fileId}:`, err);
    const errorMsg = err.message || "Unknown ingestion error";
    await jobRef.update({
      status: "error",
      errorMessage: errorMsg,
      updatedAt: new Date().toISOString(),
    }).catch(() => { });
    await fileRef.update({
      indexingStatus: "error",
      updatedAt: new Date().toISOString(),
    }).catch(() => { });
    if (err instanceof HttpsError) throw err;
    throw new HttpsError("internal", errorMsg);
  }
});

// ─── AI Memory Storage - Phase 3: Dual Index & Retrieval Layer ─────────────

/**
 * aiGenerateEmbeddings - Generate dual embeddings (OpenAI + Gemini) for file chunks
 * Reads chunks from ai_chunks, generates vectors, stores in ai_embeddings_openai/gemini
 */
exports.aiGenerateEmbeddings = onCall({ cors: true, maxInstances: 5, timeoutSeconds: 540, memory: "1GiB" }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { fileId, modelTarget = "both" } = request.data || {};
  if (!fileId) throw new HttpsError("invalid-argument", "fileId is required.");

  // Get chunks for this file
  const chunksSnap = await db.collection("users").doc(email)
    .collection("ai_chunks")
    .where("fileId", "==", fileId)
    .orderBy("chunkIndex")
    .get();

  if (chunksSnap.empty) {
    return { fileId, chunksProcessed: 0, openaiEmbeddings: 0, geminiEmbeddings: 0, errors: 0 };
  }

  const chunks = chunksSnap.docs.map(d => ({ id: d.id, ...d.data() }));
  const now = new Date().toISOString();
  let openaiCount = 0, geminiCount = 0, errorCount = 0;

  // Update IndexJob if exists
  const jobSnap = await db.collection("users").doc(email)
    .collection("ai_index_jobs")
    .where("fileId", "==", fileId)
    .orderBy("createdAt", "desc")
    .limit(1).get();
  const jobRef = jobSnap.empty ? null : jobSnap.docs[0].ref;

  // ── OpenAI Embeddings ──
  const doOpenai = modelTarget === "openai" || modelTarget === "both";
  if (doOpenai) {
    if (jobRef) await jobRef.update({ "stages.embed_openai": { status: "running", startedAt: now }, updatedAt: now });
    const openaiKey = process.env.OPENAI_API_KEY || "";
    if (openaiKey) {
      try {
        const OpenAI = require("openai");
        const openai = new OpenAI({ apiKey: openaiKey });
        const BATCH = 20; // OpenAI supports batch embedding
        for (let i = 0; i < chunks.length; i += BATCH) {
          const batch = chunks.slice(i, i + BATCH);
          const texts = batch.map(c => (c.text || "").substring(0, 8000));
          try {
            const resp = await openai.embeddings.create({
              model: "text-embedding-3-small",
              input: texts,
              dimensions: 1536,
            });
            const writeBatch = db.batch();
            for (let j = 0; j < resp.data.length; j++) {
              const embRef = db.collection("users").doc(email)
                .collection("ai_embeddings_openai").doc(batch[j].id);
              writeBatch.set(embRef, {
                chunkId: batch[j].id,
                fileId,
                vector: resp.data[j].embedding,
                model: "text-embedding-3-small",
                dimensions: 1536,
                createdAt: now,
              });
              // Update chunk status
              const chunkRef = db.collection("users").doc(email)
                .collection("ai_chunks").doc(batch[j].id);
              writeBatch.update(chunkRef, { embeddingOpenAiStatus: "completed" });
              openaiCount++;
            }
            await writeBatch.commit();
          } catch (batchErr) {
            console.warn(`[AI Storage] OpenAI embedding batch error:`, batchErr.message);
            errorCount += batch.length;
          }
        }
        if (jobRef) await jobRef.update({ "stages.embed_openai": { status: "completed", completedAt: new Date().toISOString(), itemCount: openaiCount }, updatedAt: new Date().toISOString() });
      } catch (err) {
        console.error("[AI Storage] OpenAI embedding error:", err.message);
        if (jobRef) await jobRef.update({ "stages.embed_openai": { status: "error", errorMessage: err.message, completedAt: new Date().toISOString() }, updatedAt: new Date().toISOString() });
        errorCount += chunks.length;
      }
    } else {
      console.warn("[AI Storage] OPENAI_API_KEY not set, skipping OpenAI embeddings");
      if (jobRef) await jobRef.update({ "stages.embed_openai": { status: "skipped" }, updatedAt: new Date().toISOString() });
    }
  } else {
    if (jobRef) await jobRef.update({ "stages.embed_openai": { status: "skipped" }, updatedAt: new Date().toISOString() });
  }

  // ── Gemini Embeddings ──
  const doGemini = modelTarget === "gemini" || modelTarget === "both";
  if (doGemini) {
    if (jobRef) await jobRef.update({ "stages.embed_gemini": { status: "running", startedAt: new Date().toISOString() }, updatedAt: new Date().toISOString() });
    const geminiKey = process.env.GEMINI_API_KEY || "";
    if (geminiKey) {
      try {
        const { GoogleGenerativeAI } = require("@google/generative-ai");
        const genAI = new GoogleGenerativeAI(geminiKey);
        const embModel = genAI.getGenerativeModel({ model: "text-embedding-004" });
        const BATCH = 10;
        for (let i = 0; i < chunks.length; i += BATCH) {
          const batch = chunks.slice(i, i + BATCH);
          const writeBatch = db.batch();
          for (const chunk of batch) {
            try {
              const result = await embModel.embedContent(chunk.text.substring(0, 8000));
              const vector = result.embedding.values;
              const embRef = db.collection("users").doc(email)
                .collection("ai_embeddings_gemini").doc(chunk.id);
              writeBatch.set(embRef, {
                chunkId: chunk.id,
                fileId,
                vector,
                model: "text-embedding-004",
                dimensions: vector.length,
                createdAt: now,
              });
              const chunkRef = db.collection("users").doc(email)
                .collection("ai_chunks").doc(chunk.id);
              writeBatch.update(chunkRef, { embeddingGeminiStatus: "completed" });
              geminiCount++;
            } catch (chunkErr) {
              console.warn(`[AI Storage] Gemini embedding error for chunk ${chunk.id}:`, chunkErr.message);
              errorCount++;
            }
          }
          await writeBatch.commit();
        }
        if (jobRef) await jobRef.update({ "stages.embed_gemini": { status: "completed", completedAt: new Date().toISOString(), itemCount: geminiCount }, updatedAt: new Date().toISOString() });
      } catch (err) {
        console.error("[AI Storage] Gemini embedding error:", err.message);
        if (jobRef) await jobRef.update({ "stages.embed_gemini": { status: "error", errorMessage: err.message, completedAt: new Date().toISOString() }, updatedAt: new Date().toISOString() });
        errorCount += chunks.length;
      }
    } else {
      console.warn("[AI Storage] GEMINI_API_KEY not set, skipping Gemini embeddings");
      if (jobRef) await jobRef.update({ "stages.embed_gemini": { status: "skipped" }, updatedAt: new Date().toISOString() });
    }
  } else {
    if (jobRef) await jobRef.update({ "stages.embed_gemini": { status: "skipped" }, updatedAt: new Date().toISOString() });
  }

  // Update vector_index stage
  if (jobRef) {
    await jobRef.update({
      "stages.vector_index": { status: "completed", completedAt: new Date().toISOString(), itemCount: openaiCount + geminiCount },
      updatedAt: new Date().toISOString(),
    });
  }

  console.log(`[AI Storage] Embeddings generated: ${openaiCount} OpenAI, ${geminiCount} Gemini for file ${fileId}`);
  return { fileId, chunksProcessed: chunks.length, openaiEmbeddings: openaiCount, geminiEmbeddings: geminiCount, errors: errorCount };
});

/**
 * aiRetrieve - Hybrid retrieval (vector + keyword + metadata filter)
 * Searches embeddings via cosine similarity + keyword matching in ai_chunks
 */
exports.aiRetrieve = onCall({ cors: true, maxInstances: 10, timeoutSeconds: 60, memory: "1GiB" }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { query: queryText, modelTarget = "openai", topK = 10, filters = {}, includeText = true } = request.data || {};
  if (!queryText) throw new HttpsError("invalid-argument", "query is required.");

  const startTime = Date.now();

  // ── 1. Generate query embedding ──
  let queryVector = null;
  let modelUsed = "";

  if (modelTarget === "gemini") {
    const geminiKey = process.env.GEMINI_API_KEY || "";
    if (geminiKey) {
      try {
        const { GoogleGenerativeAI } = require("@google/generative-ai");
        const genAI = new GoogleGenerativeAI(geminiKey);
        const embModel = genAI.getGenerativeModel({ model: "text-embedding-004" });
        const result = await embModel.embedContent(queryText.substring(0, 8000));
        queryVector = result.embedding.values;
        modelUsed = "text-embedding-004";
      } catch (err) { console.warn("[AI Retrieve] Gemini embedding failed:", err.message); }
    }
  } else {
    const openaiKey = process.env.OPENAI_API_KEY || "";
    if (openaiKey) {
      try {
        const OpenAI = require("openai");
        const openai = new OpenAI({ apiKey: openaiKey });
        const resp = await openai.embeddings.create({ model: "text-embedding-3-small", input: queryText.substring(0, 8000), dimensions: 1536 });
        queryVector = resp.data[0].embedding;
        modelUsed = "text-embedding-3-small";
      } catch (err) { console.warn("[AI Retrieve] OpenAI embedding failed:", err.message); }
    }
  }

  // ── 2. Get all chunks with metadata filters ──
  let chunksQuery = db.collection("users").doc(email).collection("ai_chunks");
  // Apply file filter if specified
  const fileFilter = filters.fileIds && filters.fileIds.length > 0;

  const chunksSnap = fileFilter
    ? await chunksQuery.where("fileId", "in", filters.fileIds.slice(0, 10)).get()
    : await chunksQuery.get();

  if (chunksSnap.empty) {
    return { results: [], query: queryText, modelUsed, totalChunksSearched: 0, searchTimeMs: Date.now() - startTime };
  }

  const allChunks = chunksSnap.docs.map(d => ({ id: d.id, ...d.data() }));

  // Apply additional metadata filters
  let filteredChunks = allChunks;
  if (filters.language) {
    // Need file metadata for language filter — batch lookup
    const fileIds = [...new Set(filteredChunks.map(c => c.fileId))];
    const fileLangs = {};
    await Promise.all(fileIds.map(async fid => {
      const fDoc = await db.collection("users").doc(email).collection("disk_files").doc(fid).get();
      if (fDoc.exists) fileLangs[fid] = fDoc.data().language || "";
    }));
    filteredChunks = filteredChunks.filter(c => fileLangs[c.fileId] === filters.language);
  }
  if (filters.tags && filters.tags.length > 0) {
    filteredChunks = filteredChunks.filter(c => {
      const ck = c.keywords || [];
      return filters.tags.some(t => ck.includes(t));
    });
  }

  // ── 3. Vector search (cosine similarity) ──
  const embCollection = modelTarget === "gemini" ? "ai_embeddings_gemini" : "ai_embeddings_openai";
  const vectorScores = {};

  if (queryVector) {
    const chunkIds = filteredChunks.map(c => c.id);
    // Batch load embeddings (Firestore getAll)
    const embRefs = chunkIds.map(id => db.collection("users").doc(email).collection(embCollection).doc(id));

    // Load in batches of 100
    for (let i = 0; i < embRefs.length; i += 100) {
      const batch = embRefs.slice(i, i + 100);
      const docs = await db.getAll(...batch);
      for (const embDoc of docs) {
        if (embDoc.exists) {
          const embData = embDoc.data();
          const similarity = cosineSimilarity(queryVector, embData.vector);
          vectorScores[embDoc.id] = similarity;
        }
      }
    }
  }

  // ── 4. Keyword search (BM25-like scoring) ──
  const queryTerms = queryText.toLowerCase().split(/\s+/).filter(t => t.length > 1);
  const keywordScores = {};

  for (const chunk of filteredChunks) {
    let score = 0;
    const chunkText = (chunk.text || "").toLowerCase();
    const chunkKeywords = (chunk.keywords || []).map(k => k.toLowerCase());

    for (const term of queryTerms) {
      // Keyword field match (high weight)
      if (chunkKeywords.some(k => k.includes(term))) score += 0.3;
      // Text match (lower weight, frequency-based)
      const matches = (chunkText.match(new RegExp(term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "g")) || []).length;
      if (matches > 0) score += Math.min(0.2, matches * 0.05);
      // Summary match
      if ((chunk.summary || "").toLowerCase().includes(term)) score += 0.15;
    }
    if (score > 0) keywordScores[chunk.id] = Math.min(1, score);
  }

  // ── 5. Merge & rerank ──
  const VECTOR_WEIGHT = 0.7;
  const KEYWORD_WEIGHT = 0.3;
  const scoredResults = [];

  for (const chunk of filteredChunks) {
    const vs = vectorScores[chunk.id] || 0;
    const ks = keywordScores[chunk.id] || 0;
    if (vs === 0 && ks === 0) continue;

    const combinedScore = (vs * VECTOR_WEIGHT) + (ks * KEYWORD_WEIGHT);
    const matchType = vs > 0 && ks > 0 ? "hybrid" : vs > 0 ? "vector" : "keyword";

    scoredResults.push({
      chunkId: chunk.id,
      fileId: chunk.fileId,
      score: Math.round(combinedScore * 10000) / 10000,
      vectorScore: Math.round(vs * 10000) / 10000,
      keywordScore: Math.round(ks * 10000) / 10000,
      text: includeText ? chunk.text : undefined,
      summary: chunk.summary || undefined,
      keywords: chunk.keywords || [],
      chunkType: chunk.chunkType || "text",
      chunkIndex: chunk.chunkIndex,
      matchType,
    });
  }

  // Sort by combined score descending
  scoredResults.sort((a, b) => b.score - a.score);
  const results = scoredResults.slice(0, topK);

  return {
    results,
    query: queryText,
    modelUsed,
    totalChunksSearched: filteredChunks.length,
    searchTimeMs: Date.now() - startTime,
  };
});

/** Cosine similarity between two vectors */
function cosineSimilarity(a, b) {
  if (!a || !b || a.length !== b.length) return 0;
  let dot = 0, magA = 0, magB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    magA += a[i] * a[i];
    magB += b[i] * b[i];
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  return denom === 0 ? 0 : dot / denom;
}

// ─── AI Memory Storage - Phase 4: Context Caching & Long-Term Memory ───────

/**
 * aiCreateContextCache - Create a Gemini context cache for files
 * Aggregates chunks from specified files and creates a Gemini cached content resource.
 */
exports.aiCreateContextCache = onCall({ cors: true, maxInstances: 5, timeoutSeconds: 120, memory: "1GiB" }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { fileIds, modelId = "gemini-2.0-flash", ttlSeconds = 3600, displayName } = request.data || {};

  if (!fileIds || !Array.isArray(fileIds) || fileIds.length === 0) {
    throw new HttpsError("invalid-argument", "fileIds array is required.");
  }

  // Collect all chunk texts for the specified files
  const allTexts = [];
  let totalTokens = 0;
  for (const fid of fileIds.slice(0, 20)) {
    const chunks = await db.collection("users").doc(email)
      .collection("ai_chunks")
      .where("fileId", "==", fid)
      .orderBy("chunkIndex")
      .get();
    chunks.docs.forEach(d => {
      const text = d.data().text || "";
      allTexts.push(text);
      totalTokens += d.data().tokenCount || Math.ceil(text.length / 4);
    });
  }

  if (allTexts.length === 0) {
    throw new HttpsError("failed-precondition", "No indexed chunks found for the specified files. Index files first.");
  }

  const now = new Date().toISOString();
  const expireAt = new Date(Date.now() + ttlSeconds * 1000).toISOString();
  let geminiCacheName = null;

  // Try to create Gemini cached content
  const geminiKey = process.env.GEMINI_API_KEY || "";
  if (geminiKey) {
    try {
      const axios = require("axios");
      const cacheContent = allTexts.join("\n\n---\n\n");
      const resp = await axios.post(
        `https://generativelanguage.googleapis.com/v1beta/cachedContents?key=${geminiKey}`,
        {
          model: `models/${modelId}`,
          displayName: displayName || `cache-${fileIds[0]}-${Date.now()}`,
          contents: [{ parts: [{ text: cacheContent.substring(0, 500000) }], role: "user" }],
          ttl: `${ttlSeconds}s`,
        },
        { headers: { "Content-Type": "application/json" }, timeout: 60000 }
      );
      geminiCacheName = resp.data?.name || null;
      totalTokens = resp.data?.usageMetadata?.totalTokenCount || totalTokens;
      console.log(`[AI Storage] Gemini cache created: ${geminiCacheName}`);
    } catch (err) {
      console.warn("[AI Storage] Gemini cache creation failed:", err.response?.data?.error?.message || err.message);
      // Continue without Gemini cache — store metadata anyway
    }
  }

  // Store cache metadata in Firestore
  const cacheRef = db.collection("users").doc(email).collection("ai_context_cache").doc();
  const cacheData = {
    cacheId: cacheRef.id,
    tenantId: email,
    displayName: displayName || `Cache for ${fileIds.length} files`,
    modelId,
    sourceFileIds: fileIds,
    tokenCount: totalTokens,
    ttlSeconds,
    geminiCacheName,
    status: geminiCacheName ? "active" : "error",
    createdAt: now,
    expireAt,
    lastUsedAt: null,
  };
  await cacheRef.set(cacheData);

  return cacheData;
});

/**
 * aiMemoryStore - CRUD for long-term memory entries
 * Supports: create, read, search, update, delete
 */
exports.aiMemoryStore = onCall({ cors: true, maxInstances: 10, timeoutSeconds: 60, memory: "512MiB" }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { action, ...params } = request.data || {};

  const memCol = db.collection("users").doc(email).collection("ai_memories");
  const now = new Date().toISOString();

  switch (action) {
    case "create": {
      const { content, type, importance, source, keywords, expiresAt } = params;
      if (!content) throw new HttpsError("invalid-argument", "content is required.");

      // Auto-classify memory type if not specified
      let memType = type || "semantic";
      let memImportance = importance ?? 0.5;
      let memKeywords = keywords || [];

      // Use DeepSeek for auto-classification and keyword extraction
      const deepseekKey = process.env.DEEPSEEK_API_KEY || "";
      if (deepseekKey && !type && content.length > 20) {
        try {
          const axios = require("axios");
          const resp = await axios.post("https://api.deepseek.com/chat/completions", {
            model: "deepseek-chat",
            messages: [
              { role: "system", content: 'Classify this memory. Output JSON: {"type":"episodic|semantic|procedural","importance":0.0-1.0,"keywords":["..."]}. episodic=conversation/event, semantic=fact/knowledge, procedural=preference/habit. Respond with ONLY valid JSON.' },
              { role: "user", content: content.substring(0, 1000) },
            ],
            temperature: 0.1, max_tokens: 150,
          }, {
            headers: { "Authorization": `Bearer ${deepseekKey}`, "Content-Type": "application/json" },
            timeout: 10000,
          });
          const parsed = JSON.parse(
            (resp.data?.choices?.[0]?.message?.content || "{}").replace(/```json\n?/g, "").replace(/```\n?/g, "").trim()
          );
          memType = parsed.type || memType;
          memImportance = parsed.importance ?? memImportance;
          memKeywords = parsed.keywords || memKeywords;
        } catch { /* keep defaults */ }
      }

      const memRef = memCol.doc();
      const memData = {
        memoryId: memRef.id,
        tenantId: email,
        type: memType,
        content,
        summary: content.length > 200 ? content.substring(0, 200) + "..." : content,
        importance: Math.max(0, Math.min(1, memImportance)),
        source: source || { type: "user_input" },
        keywords: memKeywords,
        accessCount: 0,
        lastAccessedAt: null,
        expiresAt: expiresAt || null,
        isConsolidated: false,
        consolidatedInto: null,
        createdAt: now,
        updatedAt: now,
      };
      await memRef.set(memData);
      return { success: true, memory: memData };
    }

    case "search": {
      const { query, type: searchType, topK = 10, minImportance = 0 } = params;
      if (!query) throw new HttpsError("invalid-argument", "query is required for search.");

      let q = memCol.where("isConsolidated", "==", false);
      if (searchType) q = q.where("type", "==", searchType);

      const snap = await q.orderBy("importance", "desc").limit(100).get();
      const memories = snap.docs.map(d => ({ memoryId: d.id, ...d.data() }));

      // Keyword matching for relevance
      const queryTerms = query.toLowerCase().split(/\s+/).filter(t => t.length > 1);
      const scored = memories
        .filter(m => m.importance >= minImportance)
        .map(m => {
          let score = 0;
          const content = (m.content || "").toLowerCase();
          const kws = (m.keywords || []).map(k => k.toLowerCase());
          for (const term of queryTerms) {
            if (kws.some(k => k.includes(term))) score += 0.4;
            if (content.includes(term)) score += 0.2;
            if ((m.summary || "").toLowerCase().includes(term)) score += 0.2;
          }
          score += m.importance * 0.2;
          return { ...m, relevanceScore: Math.round(score * 1000) / 1000 };
        })
        .filter(m => m.relevanceScore > 0)
        .sort((a, b) => b.relevanceScore - a.relevanceScore)
        .slice(0, topK);

      // Update access counts
      const batch = db.batch();
      for (const m of scored) {
        batch.update(memCol.doc(m.memoryId), { accessCount: (m.accessCount || 0) + 1, lastAccessedAt: now });
      }
      await batch.commit();

      return { success: true, results: scored, total: scored.length };
    }

    case "update": {
      const { memoryId, updates } = params;
      if (!memoryId) throw new HttpsError("invalid-argument", "memoryId is required.");
      const allowedFields = ["content", "type", "importance", "keywords", "expiresAt"];
      const safeUpdates = {};
      for (const key of allowedFields) {
        if (updates[key] !== undefined) safeUpdates[key] = updates[key];
      }
      safeUpdates.updatedAt = now;
      await memCol.doc(memoryId).update(safeUpdates);
      return { success: true, memoryId };
    }

    case "delete": {
      const { memoryId } = params;
      if (!memoryId) throw new HttpsError("invalid-argument", "memoryId is required.");
      await memCol.doc(memoryId).delete();
      return { success: true, memoryId };
    }

    case "list": {
      const { type: listType, limit: pageSize = 20 } = params;
      let q = memCol.where("isConsolidated", "==", false);
      if (listType) q = q.where("type", "==", listType);
      const snap = await q.orderBy("createdAt", "desc").limit(pageSize).get();
      return { success: true, memories: snap.docs.map(d => ({ memoryId: d.id, ...d.data() })), total: snap.docs.length };
    }

    default:
      throw new HttpsError("invalid-argument", "action must be one of: create, search, update, delete, list");
  }
});

/**
 * aiMemoryConsolidate - Consolidate old/duplicate memories
 * Merges low-importance and old memories into summarized entries.
 */
exports.aiMemoryConsolidate = onCall({ cors: true, maxInstances: 3, timeoutSeconds: 300, memory: "1GiB" }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { strategy = "summarize", maxAge = 30, minCount = 5, importanceThreshold = 0.3 } = request.data || {};

  const memCol = db.collection("users").doc(email).collection("ai_memories");
  const consCol = db.collection("users").doc(email).collection("ai_memory_consolidations");
  const now = new Date().toISOString();

  let candidateSnap;
  if (strategy === "importance_prune") {
    // Remove low-importance, unconsolidated memories
    candidateSnap = await memCol
      .where("isConsolidated", "==", false)
      .where("importance", "<", importanceThreshold)
      .orderBy("importance")
      .limit(50)
      .get();
  } else {
    // Get old, unconsolidated memories for summarization/dedup
    const cutoff = new Date(Date.now() - maxAge * 24 * 60 * 60 * 1000).toISOString();
    candidateSnap = await memCol
      .where("isConsolidated", "==", false)
      .where("createdAt", "<", cutoff)
      .orderBy("createdAt")
      .limit(50)
      .get();
  }

  if (candidateSnap.empty || candidateSnap.docs.length < minCount) {
    return { success: true, consolidated: 0, message: "Not enough memories to consolidate." };
  }

  const candidates = candidateSnap.docs.map(d => ({ id: d.id, ...d.data() }));

  // Group by type for better consolidation
  const grouped = {};
  for (const m of candidates) {
    const key = m.type || "semantic";
    if (!grouped[key]) grouped[key] = [];
    grouped[key].push(m);
  }

  let totalConsolidated = 0;
  const deepseekKey = process.env.DEEPSEEK_API_KEY || "";

  for (const [memType, memories] of Object.entries(grouped)) {
    if (memories.length < 2) continue;

    // Merge via DeepSeek
    let mergedContent = memories.map(m => m.content).join("\n---\n");

    if (deepseekKey) {
      try {
        const axios = require("axios");
        const resp = await axios.post("https://api.deepseek.com/chat/completions", {
          model: "deepseek-chat",
          messages: [
            { role: "system", content: "You are a memory consolidation assistant. Merge the following memory entries into a single, concise summary that preserves all important information. Output ONLY the merged text, nothing else." },
            { role: "user", content: mergedContent.substring(0, 5000) },
          ],
          temperature: 0.2, max_tokens: 500,
        }, {
          headers: { "Authorization": `Bearer ${deepseekKey}`, "Content-Type": "application/json" },
          timeout: 15000,
        });
        mergedContent = resp.data?.choices?.[0]?.message?.content || mergedContent.substring(0, 500);
      } catch { /* use raw concatenation */ }
    } else {
      mergedContent = mergedContent.substring(0, 1000);
    }

    // Create merged memory
    const newMemRef = memCol.doc();
    const maxImportance = Math.max(...memories.map(m => m.importance || 0));
    await newMemRef.set({
      memoryId: newMemRef.id,
      tenantId: email,
      type: memType,
      content: mergedContent,
      summary: mergedContent.substring(0, 200),
      importance: Math.min(1, maxImportance + 0.1), // Slightly boost consolidated memories
      source: { type: "consolidation" },
      keywords: [...new Set(memories.flatMap(m => m.keywords || []))].slice(0, 15),
      accessCount: 0,
      isConsolidated: false,
      createdAt: now,
      updatedAt: now,
    });

    // Mark source memories as consolidated
    const batch = db.batch();
    for (const m of memories) {
      batch.update(memCol.doc(m.id), {
        isConsolidated: true,
        consolidatedInto: newMemRef.id,
        updatedAt: now,
      });
    }
    await batch.commit();

    // Record consolidation
    await consCol.doc().set({
      tenantId: email,
      sourceMemoryIds: memories.map(m => m.id),
      mergedContent,
      mergedMemoryId: newMemRef.id,
      strategy,
      memoriesRemoved: memories.length,
      createdAt: now,
    });

    totalConsolidated += memories.length;
  }

  console.log(`[AI Storage] Memory consolidation: ${totalConsolidated} memories consolidated for ${email}`);
  return { success: true, consolidated: totalConsolidated, strategy };
});

// ─── AI Memory Storage - Phase 5: Multi-tenant Access Control & Workspace ──

/**
 * aiWorkspaceManage - Workspace CRUD + member management
 */
exports.aiWorkspaceManage = onCall({ cors: true, maxInstances: 10, timeoutSeconds: 30 }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { action, ...params } = request.data || {};
  const wsCol = db.collection("users").doc(email).collection("ai_workspaces");
  const now = new Date().toISOString();

  switch (action) {
    case "create": {
      const { name, description, settings } = params;
      if (!name) throw new HttpsError("invalid-argument", "name is required.");
      const wsRef = wsCol.doc();
      const wsData = {
        workspaceId: wsRef.id, name, description: description || "",
        ownerId: email,
        members: [{ email, role: "owner", invitedAt: now, acceptedAt: now }],
        settings: {
          defaultModelTarget: settings?.defaultModelTarget || "both",
          autoIndex: settings?.autoIndex ?? true,
          retentionDays: settings?.retentionDays || 365,
          maxStorageGb: settings?.maxStorageGb || 10,
        },
        fileCount: 0, totalSize: 0, createdAt: now, updatedAt: now,
      };
      await wsRef.set(wsData);
      // Audit
      await logAudit(db, email, { action: "workspace_invite", actor: email, resourceType: "workspace", resourceId: wsRef.id, details: { name } });
      return { success: true, workspace: wsData };
    }
    case "update": {
      const { workspaceId, name, description, settings } = params;
      if (!workspaceId) throw new HttpsError("invalid-argument", "workspaceId is required.");
      const wsDoc = await wsCol.doc(workspaceId).get();
      if (!wsDoc.exists) throw new HttpsError("not-found", "Workspace not found.");
      const ws = wsDoc.data();
      const member = ws.members.find(m => m.email === email);
      if (!member || !["owner", "admin"].includes(member.role)) throw new HttpsError("permission-denied", "Admin access required.");
      const updates = { updatedAt: now };
      if (name) updates.name = name;
      if (description !== undefined) updates.description = description;
      if (settings) updates.settings = { ...ws.settings, ...settings };
      await wsCol.doc(workspaceId).update(updates);
      return { success: true, workspaceId };
    }
    case "delete": {
      const { workspaceId } = params;
      if (!workspaceId) throw new HttpsError("invalid-argument", "workspaceId is required.");
      const wsDoc = await wsCol.doc(workspaceId).get();
      if (!wsDoc.exists) throw new HttpsError("not-found", "Workspace not found.");
      if (wsDoc.data().ownerId !== email) throw new HttpsError("permission-denied", "Owner access required.");
      await wsCol.doc(workspaceId).delete();
      return { success: true, workspaceId };
    }
    case "invite": {
      const { workspaceId, memberEmail, role = "viewer" } = params;
      if (!workspaceId || !memberEmail) throw new HttpsError("invalid-argument", "workspaceId and memberEmail required.");
      const wsDoc = await wsCol.doc(workspaceId).get();
      if (!wsDoc.exists) throw new HttpsError("not-found", "Workspace not found.");
      const ws = wsDoc.data();
      const actor = ws.members.find(m => m.email === email);
      if (!actor || !["owner", "admin"].includes(actor.role)) throw new HttpsError("permission-denied", "Admin access required.");
      if (ws.members.some(m => m.email === memberEmail.toLowerCase())) throw new HttpsError("already-exists", "Member already exists.");
      const newMember = { email: memberEmail.toLowerCase(), role, invitedAt: now };
      await wsCol.doc(workspaceId).update({ members: [...ws.members, newMember], updatedAt: now });
      await logAudit(db, email, { action: "workspace_invite", actor: email, resourceType: "workspace", resourceId: workspaceId, details: { memberEmail, role } });
      return { success: true, member: newMember };
    }
    case "remove": {
      const { workspaceId, memberEmail } = params;
      if (!workspaceId || !memberEmail) throw new HttpsError("invalid-argument", "workspaceId and memberEmail required.");
      const wsDoc = await wsCol.doc(workspaceId).get();
      if (!wsDoc.exists) throw new HttpsError("not-found", "Workspace not found.");
      const ws = wsDoc.data();
      const actor = ws.members.find(m => m.email === email);
      if (!actor || !["owner", "admin"].includes(actor.role)) throw new HttpsError("permission-denied", "Admin access required.");
      if (memberEmail.toLowerCase() === ws.ownerId) throw new HttpsError("failed-precondition", "Cannot remove owner.");
      const updated = ws.members.filter(m => m.email !== memberEmail.toLowerCase());
      await wsCol.doc(workspaceId).update({ members: updated, updatedAt: now });
      await logAudit(db, email, { action: "workspace_remove", actor: email, resourceType: "workspace", resourceId: workspaceId, details: { memberEmail } });
      return { success: true };
    }
    case "list": {
      const snap = await wsCol.orderBy("createdAt", "desc").limit(50).get();
      return { success: true, workspaces: snap.docs.map(d => ({ workspaceId: d.id, ...d.data() })) };
    }
    default:
      throw new HttpsError("invalid-argument", "action must be: create, update, delete, invite, remove, list");
  }
});

/**
 * aiDataShare - Data sharing link management
 */
exports.aiDataShare = onCall({ cors: true, maxInstances: 10, timeoutSeconds: 30 }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { action, ...params } = request.data || {};
  const shareCol = db.collection("users").doc(email).collection("ai_data_shares");
  const now = new Date().toISOString();

  switch (action) {
    case "create": {
      const { resourceType, resourceIds, permissions = ["read"], expireHours, maxAccessCount, password, workspaceId } = params;
      if (!resourceType || !resourceIds?.length) throw new HttpsError("invalid-argument", "resourceType and resourceIds required.");
      const shareRef = shareCol.doc();
      const shareData = {
        shareId: shareRef.id, creatorId: email, workspaceId: workspaceId || null,
        resourceType, resourceIds,
        permissions: permissions.filter(p => ["read", "write", "search"].includes(p)),
        accessCount: 0,
        maxAccessCount: maxAccessCount || null,
        password: password || null,
        expireAt: expireHours ? new Date(Date.now() + expireHours * 3600000).toISOString() : null,
        isActive: true, createdAt: now,
      };
      await shareRef.set(shareData);
      await logAudit(db, email, { action: "share_create", actor: email, resourceType, resourceId: resourceIds[0], details: { shareId: shareRef.id, permissions } });
      return { success: true, share: shareData };
    }
    case "access": {
      const { shareId, password: inputPassword } = params;
      if (!shareId) throw new HttpsError("invalid-argument", "shareId is required.");
      // Share links can be accessed across tenants — check global or owner's collection
      const shareDoc = await shareCol.doc(shareId).get();
      if (!shareDoc.exists) throw new HttpsError("not-found", "Share link not found.");
      const share = shareDoc.data();
      if (!share.isActive) throw new HttpsError("failed-precondition", "Share link is inactive.");
      if (share.expireAt && new Date(share.expireAt) < new Date()) {
        await shareCol.doc(shareId).update({ isActive: false });
        throw new HttpsError("failed-precondition", "Share link has expired.");
      }
      if (share.maxAccessCount && share.accessCount >= share.maxAccessCount) {
        await shareCol.doc(shareId).update({ isActive: false });
        throw new HttpsError("resource-exhausted", "Share link access limit reached.");
      }
      if (share.password && share.password !== inputPassword) {
        throw new HttpsError("permission-denied", "Invalid password.");
      }
      await shareCol.doc(shareId).update({ accessCount: share.accessCount + 1 });
      await logAudit(db, email, { action: "share_access", actor: email, resourceType: share.resourceType, resourceId: share.resourceIds[0], details: { shareId } });
      return { success: true, share: { ...share, password: undefined } };
    }
    case "revoke": {
      const { shareId } = params;
      if (!shareId) throw new HttpsError("invalid-argument", "shareId is required.");
      await shareCol.doc(shareId).update({ isActive: false });
      return { success: true, shareId };
    }
    case "list": {
      const snap = await shareCol.where("isActive", "==", true).orderBy("createdAt", "desc").limit(50).get();
      return { success: true, shares: snap.docs.map(d => ({ shareId: d.id, ...d.data(), password: undefined })) };
    }
    default:
      throw new HttpsError("invalid-argument", "action must be: create, access, revoke, list");
  }
});

/**
 * aiAuditLog - Audit log query
 */
exports.aiAuditLog = onCall({ cors: true, maxInstances: 10, timeoutSeconds: 30 }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { action: queryAction, startDate, endDate, actionFilter, resourceType, limit: pageSize = 50 } = request.data || {};

  const logCol = db.collection("users").doc(email).collection("ai_audit_logs");

  if (queryAction === "query") {
    let q = logCol.orderBy("timestamp", "desc");
    if (actionFilter) q = q.where("action", "==", actionFilter);
    if (startDate) q = q.where("timestamp", ">=", startDate);
    if (endDate) q = q.where("timestamp", "<=", endDate);
    const snap = await q.limit(Math.min(pageSize, 200)).get();
    return { success: true, logs: snap.docs.map(d => ({ logId: d.id, ...d.data() })), total: snap.docs.length };
  }

  // Default: get recent logs
  const snap = await logCol.orderBy("timestamp", "desc").limit(Math.min(pageSize, 100)).get();
  return { success: true, logs: snap.docs.map(d => ({ logId: d.id, ...d.data() })), total: snap.docs.length };
});

/** Helper: Write audit log entry */
async function logAudit(dbRef, tenantId, entry) {
  try {
    const logRef = dbRef.collection("users").doc(tenantId).collection("ai_audit_logs").doc();
    await logRef.set({
      logId: logRef.id,
      tenantId,
      ...entry,
      timestamp: new Date().toISOString(),
    });
  } catch (err) {
    console.warn("[AI Storage] Audit log write failed:", err.message);
  }
}

// ─── AI Memory Storage - Phase 6: Monitoring & Analytics ───────────────────

/**
 * aiAnalytics - Usage/cost/storage analytics
 */
exports.aiAnalytics = onCall({ cors: true, maxInstances: 10, timeoutSeconds: 60 }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { action, ...params } = request.data || {};

  switch (action) {
    case "getStorage": {
      const userRef = db.collection("users").doc(email);
      // Count collections in parallel
      const [chunksSnap, embOaiSnap, embGemSnap, memSnap, cacheSnap, wsSnap, shareSnap] = await Promise.all([
        userRef.collection("ai_chunks").count().get(),
        userRef.collection("ai_embeddings_openai").count().get(),
        userRef.collection("ai_embeddings_gemini").count().get(),
        userRef.collection("ai_memories").count().get(),
        userRef.collection("ai_context_cache").count().get(),
        userRef.collection("ai_workspaces").count().get(),
        userRef.collection("ai_data_shares").count().get(),
      ]);

      // Get memory type breakdown
      const [episodicSnap, semanticSnap, proceduralSnap, consolidatedSnap] = await Promise.all([
        userRef.collection("ai_memories").where("type", "==", "episodic").where("isConsolidated", "==", false).count().get(),
        userRef.collection("ai_memories").where("type", "==", "semantic").where("isConsolidated", "==", false).count().get(),
        userRef.collection("ai_memories").where("type", "==", "procedural").where("isConsolidated", "==", false).count().get(),
        userRef.collection("ai_memories").where("isConsolidated", "==", true).count().get(),
      ]);

      // Get cache status breakdown
      const [activeCacheSnap, expiredCacheSnap] = await Promise.all([
        userRef.collection("ai_context_cache").where("status", "==", "active").count().get(),
        userRef.collection("ai_context_cache").where("status", "==", "expired").count().get(),
      ]);

      // Get file indexing status
      const diskSnap = await userRef.collection("disk_files").count().get();
      const indexedSnap = await userRef.collection("disk_files").where("indexingStatus", "==", "indexed").count().get();
      const pendingSnap = await userRef.collection("disk_files").where("indexingStatus", "==", "queued").count().get();
      const errorSnap = await userRef.collection("disk_files").where("indexingStatus", "==", "error").count().get();

      // Active shares
      const activeShareSnap = await userRef.collection("ai_data_shares").where("isActive", "==", true).count().get();

      // Workspace member count
      const wsDocsSnap = await userRef.collection("ai_workspaces").get();
      let totalMembers = 0;
      wsDocsSnap.docs.forEach(d => { totalMembers += (d.data().members || []).length; });

      return {
        success: true,
        analytics: {
          tenantId: email,
          files: { total: diskSnap.data().count, indexed: indexedSnap.data().count, pending: pendingSnap.data().count, error: errorSnap.data().count },
          chunks: { total: chunksSnap.data().count, withOpenaiEmbedding: embOaiSnap.data().count, withGeminiEmbedding: embGemSnap.data().count },
          memories: { total: memSnap.data().count, episodic: episodicSnap.data().count, semantic: semanticSnap.data().count, procedural: proceduralSnap.data().count, consolidated: consolidatedSnap.data().count },
          caches: { total: cacheSnap.data().count, active: activeCacheSnap.data().count, expired: expiredCacheSnap.data().count },
          workspaces: { total: wsSnap.data().count, totalMembers },
          shares: { total: shareSnap.data().count, active: activeShareSnap.data().count },
          timestamp: new Date().toISOString(),
        },
      };
    }

    case "getUsage": {
      const { startDate, endDate, limit: pageSize = 30 } = params;
      let q = db.collection("users").doc(email).collection("ai_usage_metrics").orderBy("date", "desc");
      if (startDate) q = q.where("date", ">=", startDate);
      if (endDate) q = q.where("date", "<=", endDate);
      const snap = await q.limit(pageSize).get();
      return { success: true, metrics: snap.docs.map(d => d.data()) };
    }

    case "recordUsage": {
      const { category, count = 1, tokens = 0, model } = params;
      if (!category) throw new HttpsError("invalid-argument", "category required.");
      const today = new Date().toISOString().split("T")[0];
      const metricRef = db.collection("users").doc(email).collection("ai_usage_metrics").doc(today);
      const metricDoc = await metricRef.get();

      if (metricDoc.exists) {
        const data = metricDoc.data();
        const apiCalls = data.apiCalls || {};
        apiCalls[category] = (apiCalls[category] || 0) + count;
        apiCalls.total = (apiCalls.total || 0) + count;
        const tokenData = data.tokens || {};
        if (tokens > 0 && model) {
          const tokenKey = model.includes("openai") ? "embeddingOpenai" : model.includes("gemini") ? "embeddingGemini" : "enrichmentDeepseek";
          tokenData[tokenKey] = (tokenData[tokenKey] || 0) + tokens;
          tokenData.total = (tokenData.total || 0) + tokens;
        }
        await metricRef.update({ apiCalls, tokens: tokenData, updatedAt: new Date().toISOString() });
      } else {
        const apiCalls = { indexing: 0, embedding: 0, retrieval: 0, memory: 0, cache: 0, total: count };
        apiCalls[category] = count;
        const tokenData = { embeddingOpenai: 0, embeddingGemini: 0, enrichmentDeepseek: 0, cacheGemini: 0, total: tokens };
        if (tokens > 0 && model) {
          const tokenKey = model.includes("openai") ? "embeddingOpenai" : model.includes("gemini") ? "embeddingGemini" : "enrichmentDeepseek";
          tokenData[tokenKey] = tokens;
        }
        await metricRef.set({
          date: today, tenantId: email, apiCalls, tokens: tokenData,
          storage: { chunksCreated: 0, embeddingsCreated: 0, memoriesCreated: 0, filesIndexed: 0 },
          updatedAt: new Date().toISOString(),
        });
      }
      return { success: true };
    }

    case "getCost": {
      const { period } = params; // YYYY-MM
      const month = period || new Date().toISOString().substring(0, 7);
      const startDate = `${month}-01`;
      const endDate = `${month}-31`;
      const snap = await db.collection("users").doc(email).collection("ai_usage_metrics")
        .where("date", ">=", startDate).where("date", "<=", endDate).get();

      let oaiTokens = 0, gemTokens = 0, dsTokens = 0;
      snap.docs.forEach(d => {
        const t = d.data().tokens || {};
        oaiTokens += t.embeddingOpenai || 0;
        gemTokens += (t.embeddingGemini || 0) + (t.cacheGemini || 0);
        dsTokens += t.enrichmentDeepseek || 0;
      });

      // Estimated costs (per 1M tokens)
      const oaiCost = (oaiTokens / 1000000) * 0.02;   // text-embedding-3-small
      const gemCost = (gemTokens / 1000000) * 0.00;    // free tier for embedding
      const dsCost = (dsTokens / 1000000) * 0.14;      // deepseek-chat

      return {
        success: true,
        cost: {
          period: month, tenantId: email,
          byModel: {
            openai: { tokens: oaiTokens, estimatedCost: Math.round(oaiCost * 100) / 100 },
            gemini: { tokens: gemTokens, estimatedCost: Math.round(gemCost * 100) / 100 },
            deepseek: { tokens: dsTokens, estimatedCost: Math.round(dsCost * 100) / 100 },
          },
          totalEstimatedCost: Math.round((oaiCost + gemCost + dsCost) * 100) / 100,
        },
      };
    }

    default:
      throw new HttpsError("invalid-argument", "action must be: getStorage, getUsage, recordUsage, getCost");
  }
});

/**
 * aiHealthCheck - System health check
 */
exports.aiHealthCheck = onCall({ cors: true, maxInstances: 5, timeoutSeconds: 30 }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const now = new Date().toISOString();

  const components = {};
  const latencyMs = {};

  // 1. Firestore read check
  try {
    const start = Date.now();
    await db.collection("users").doc(email).get();
    latencyMs.firestoreRead = Date.now() - start;
    components.firestore = { status: latencyMs.firestoreRead < 1000 ? "healthy" : "degraded", latencyMs: latencyMs.firestoreRead, lastChecked: now };
  } catch (err) {
    latencyMs.firestoreRead = -1;
    components.firestore = { status: "down", message: err.message, lastChecked: now };
  }

  // 2. Firestore write check
  try {
    const start = Date.now();
    const healthRef = db.collection("users").doc(email).collection("ai_health_logs").doc();
    await healthRef.set({ type: "ping", timestamp: now });
    latencyMs.firestoreWrite = Date.now() - start;
    await healthRef.delete(); // Cleanup
  } catch {
    latencyMs.firestoreWrite = -1;
  }

  // 3. OpenAI API check
  const openaiKey = process.env.OPENAI_API_KEY || "";
  if (openaiKey) {
    try {
      const start = Date.now();
      const OpenAI = require("openai");
      const openai = new OpenAI({ apiKey: openaiKey });
      await openai.embeddings.create({ model: "text-embedding-3-small", input: "health check", dimensions: 1536 });
      latencyMs.embeddingOpenai = Date.now() - start;
      components.openaiApi = { status: latencyMs.embeddingOpenai < 5000 ? "healthy" : "degraded", latencyMs: latencyMs.embeddingOpenai, lastChecked: now };
    } catch (err) {
      latencyMs.embeddingOpenai = -1;
      components.openaiApi = { status: "down", message: err.message, lastChecked: now };
    }
  } else {
    latencyMs.embeddingOpenai = -1;
    components.openaiApi = { status: "unconfigured", message: "OPENAI_API_KEY not set", lastChecked: now };
  }

  // 4. Gemini API check
  const geminiKey = process.env.GEMINI_API_KEY || "";
  if (geminiKey) {
    try {
      const start = Date.now();
      const { GoogleGenerativeAI } = require("@google/generative-ai");
      const genAI = new GoogleGenerativeAI(geminiKey);
      const embModel = genAI.getGenerativeModel({ model: "text-embedding-004" });
      await embModel.embedContent("health check");
      latencyMs.embeddingGemini = Date.now() - start;
      components.geminiApi = { status: latencyMs.embeddingGemini < 5000 ? "healthy" : "degraded", latencyMs: latencyMs.embeddingGemini, lastChecked: now };
    } catch (err) {
      latencyMs.embeddingGemini = -1;
      components.geminiApi = { status: "down", message: err.message, lastChecked: now };
    }
  } else {
    latencyMs.embeddingGemini = -1;
    components.geminiApi = { status: "unconfigured", message: "GEMINI_API_KEY not set", lastChecked: now };
  }

  // 5. DeepSeek API check
  const deepseekKey = process.env.DEEPSEEK_API_KEY || "";
  if (deepseekKey) {
    try {
      const axios = require("axios");
      const start = Date.now();
      await axios.post("https://api.deepseek.com/chat/completions", {
        model: "deepseek-chat", messages: [{ role: "user", content: "ping" }], max_tokens: 5,
      }, { headers: { "Authorization": `Bearer ${deepseekKey}`, "Content-Type": "application/json" }, timeout: 10000 });
      const lat = Date.now() - start;
      components.deepseekApi = { status: lat < 5000 ? "healthy" : "degraded", latencyMs: lat, lastChecked: now };
    } catch (err) {
      components.deepseekApi = { status: "down", message: err.message, lastChecked: now };
    }
  } else {
    components.deepseekApi = { status: "unconfigured", message: "DEEPSEEK_API_KEY not set", lastChecked: now };
  }

  // 6. Context cache check
  const cacheSnap = await db.collection("users").doc(email).collection("ai_context_cache")
    .where("status", "==", "active").limit(1).get();
  components.contextCache = {
    status: cacheSnap.empty ? "healthy" : "healthy",
    message: cacheSnap.empty ? "No active caches" : "Active caches exist",
    lastChecked: now,
  };

  // Overall status
  const statuses = Object.values(components).map(c => c.status);
  const overall = statuses.includes("down") ? "down" : statuses.includes("degraded") ? "degraded" : "healthy";

  // Save health log
  await db.collection("users").doc(email).collection("ai_health_logs").doc().set({
    timestamp: now, overall, components, latencyMs,
  });

  return { success: true, health: { timestamp: now, overall, components, latencyMs } };
});

// ─── AI Memory Storage - Phase 7: Integration Orchestrator ─────────────────

/**
 * aiOrchestrate - Full pipeline: index -> ingest -> embed in a single call
 */
exports.aiOrchestrate = onCall({ cors: true, maxInstances: 3, timeoutSeconds: 540, memory: "2GiB" }, async (request) => {
  if (!request.auth) throw new HttpsError("unauthenticated", "Login required.");
  const email = request.auth.token.email.toLowerCase();
  const { fileId, modelTarget = "both" } = request.data || {};

  if (!fileId) throw new HttpsError("invalid-argument", "fileId is required.");

  const result = { fileId, steps: [], errors: [], startedAt: new Date().toISOString() };

  try {
    // Step 1: Check file exists
    const fileDoc = await db.collection("users").doc(email).collection("disk_files").doc(fileId).get();
    if (!fileDoc.exists) throw new HttpsError("not-found", "File not found.");
    result.steps.push("file_verified");

    // Step 2: Mark as indexing
    await db.collection("users").doc(email).collection("disk_files").doc(fileId).update({
      indexingStatus: "processing",
      indexingStartedAt: new Date().toISOString(),
    });

    // Step 3: Ingest — call aiProcessIngestion logic inline
    const fileData = fileDoc.data();
    const fileName = fileData.name || fileData.fileName || "";
    const ext = fileName.split(".").pop()?.toLowerCase() || "";
    let rawText = "";

    // Fetch content from Storage
    const { getStorage } = require("firebase-admin/storage");
    const storagePath = fileData.storagePath || fileData.path || `users/${email}/${fileId}/${fileName}`;
    try {
      const bucket = getStorage().bucket();
      const [buffer] = await bucket.file(storagePath).download();
      const textExts = ["txt", "md", "csv", "json", "html", "htm", "js", "ts", "jsx", "tsx", "py", "java", "c", "cpp", "go", "rs", "rb", "php", "yaml", "yml", "toml", "xml", "sql", "sh", "bat", "css", "scss"];
      if (ext === "pdf") {
        try { const pdfParse = require("pdf-parse"); const data = await pdfParse(buffer); rawText = data.text || ""; }
        catch { rawText = buffer.toString("utf-8").substring(0, 50000); }
      } else if (textExts.includes(ext)) {
        rawText = buffer.toString("utf-8");
      } else {
        rawText = buffer.toString("utf-8").substring(0, 50000);
      }
    } catch (err) { result.errors.push("download: " + err.message); }

    if (!rawText || rawText.trim().length < 10) {
      await db.collection("users").doc(email).collection("disk_files").doc(fileId).update({ indexingStatus: "error", indexingError: "No text extracted" });
      return { success: false, ...result, error: "No text content extracted" };
    }
    result.steps.push("text_extracted");

    // Step 4: Chunk
    const chunks = [];
    const lines = rawText.split("\n");
    let currentChunk = [];
    let currentTokens = 0;
    const MAX_TOKENS = 500;

    for (const line of lines) {
      const lineTokens = Math.ceil(line.length / 4);
      if (currentTokens + lineTokens > MAX_TOKENS && currentChunk.length > 0) {
        chunks.push(currentChunk.join("\n"));
        currentChunk = [line];
        currentTokens = lineTokens;
      } else {
        currentChunk.push(line);
        currentTokens += lineTokens;
      }
    }
    if (currentChunk.length > 0) chunks.push(currentChunk.join("\n"));
    result.steps.push(`chunked:${chunks.length}`);

    // Step 5: Save chunks
    const batch = db.batch();
    const chunkIds = [];
    for (let i = 0; i < chunks.length; i++) {
      const chunkRef = db.collection("users").doc(email).collection("ai_chunks").doc();
      chunkIds.push(chunkRef.id);
      batch.set(chunkRef, {
        chunkId: chunkRef.id, fileId, chunkIndex: i, text: chunks[i],
        tokenCount: Math.ceil(chunks[i].length / 4),
        createdAt: new Date().toISOString(),
      });
    }
    await batch.commit();
    result.steps.push("chunks_saved");

    // Step 6: Generate embeddings
    let oaiCount = 0, gemCount = 0;
    const openaiKey = process.env.OPENAI_API_KEY || "";
    const geminiKey = process.env.GEMINI_API_KEY || "";

    if ((modelTarget === "openai" || modelTarget === "both") && openaiKey) {
      try {
        const OpenAI = require("openai");
        const openai = new OpenAI({ apiKey: openaiKey });
        for (let i = 0; i < chunkIds.length; i++) {
          const resp = await openai.embeddings.create({ model: "text-embedding-3-small", input: chunks[i].substring(0, 8000), dimensions: 1536 });
          await db.collection("users").doc(email).collection("ai_embeddings_openai").doc(chunkIds[i]).set({
            chunkId: chunkIds[i], fileId, vector: resp.data[0].embedding,
            model: "text-embedding-3-small", dimensions: 1536, createdAt: new Date().toISOString(),
          });
          oaiCount++;
        }
        result.steps.push(`openai_embeddings:${oaiCount}`);
      } catch (err) { result.errors.push("openai: " + err.message); }
    }

    if ((modelTarget === "gemini" || modelTarget === "both") && geminiKey) {
      try {
        const { GoogleGenerativeAI } = require("@google/generative-ai");
        const genAI = new GoogleGenerativeAI(geminiKey);
        const embModel = genAI.getGenerativeModel({ model: "text-embedding-004" });
        for (let i = 0; i < chunkIds.length; i++) {
          const resp = await embModel.embedContent(chunks[i].substring(0, 8000));
          await db.collection("users").doc(email).collection("ai_embeddings_gemini").doc(chunkIds[i]).set({
            chunkId: chunkIds[i], fileId, vector: resp.embedding.values,
            model: "text-embedding-004", dimensions: 768, createdAt: new Date().toISOString(),
          });
          gemCount++;
        }
        result.steps.push(`gemini_embeddings:${gemCount}`);
      } catch (err) { result.errors.push("gemini: " + err.message); }
    }

    // Step 7: Update file status
    await db.collection("users").doc(email).collection("disk_files").doc(fileId).update({
      indexingStatus: "indexed",
      indexedAt: new Date().toISOString(),
      chunkCount: chunks.length,
      embeddingModels: modelTarget,
    });
    result.steps.push("completed");

    // Record usage
    try {
      const today = new Date().toISOString().split("T")[0];
      const metricRef = db.collection("users").doc(email).collection("ai_usage_metrics").doc(today);
      const metricDoc = await metricRef.get();
      if (metricDoc.exists) {
        const d = metricDoc.data();
        await metricRef.update({
          "apiCalls.indexing": (d.apiCalls?.indexing || 0) + 1,
          "apiCalls.embedding": (d.apiCalls?.embedding || 0) + 1,
          "apiCalls.total": (d.apiCalls?.total || 0) + 2,
          "storage.filesIndexed": (d.storage?.filesIndexed || 0) + 1,
          "storage.chunksCreated": (d.storage?.chunksCreated || 0) + chunks.length,
          "storage.embeddingsCreated": (d.storage?.embeddingsCreated || 0) + oaiCount + gemCount,
          updatedAt: new Date().toISOString(),
        });
      }
    } catch { /* non-critical */ }

    // Audit log
    await logAudit(db, email, { action: "index_request", actor: email, resourceType: "file", resourceId: fileId, details: { chunks: chunks.length, oaiCount, gemCount } });

    result.completedAt = new Date().toISOString();
    return { success: true, ...result };
  } catch (err) {
    result.errors.push(err.message);
    await db.collection("users").doc(email).collection("disk_files").doc(fileId).update({
      indexingStatus: "error", indexingError: err.message,
    }).catch(() => { });
    return { success: false, ...result };
  }
});

exports.configureStorageCors = onRequest({ cors: true, invoker: "public" }, async (req, res) => {
  try {
    const bucketNames = [
      "visionchain-d19ed.firebasestorage.app",
      "visionchain-d19ed.appspot.com",
      "visionchain-staging.firebasestorage.app",
      "visionchain-staging.appspot.com",
    ];

    const results = [];
    const corsConfig = [
      {
        origin: ["*"],
        method: ["GET", "PUT", "POST", "DELETE", "OPTIONS", "HEAD"],
        maxAgeSeconds: 3600,
        responseHeader: ["*"],
      },
    ];

    for (const name of bucketNames) {
      try {
        const bucket = admin.storage().bucket(name);
        await bucket.setCorsConfiguration(corsConfig);
        results.push(`Success: ${name}`);
      } catch (err) {
        results.push(`Failed: ${name} (${err.message})`);
      }
    }

    res.send(`CORS update results: ${results.join(" | ")}`);
  } catch (e) {
    res.status(500).send("Error: " + e.message);
  }
});

// --- Omni-Mint AI Generator using Gemini 2.5 Pro ---
exports.generateOmniMintContract = onCall({ cors: true, timeoutSeconds: 60 }, async (request) => {
  try {
    const {
      tokenType,
      tokenName,
      tokenSymbol,
      initialSupply,
      isMintable,
      isBurnable,
      isPausable,
      targetChains,
      aiPrompt,
    } = request.data || {};

    if (!tokenName || !tokenSymbol) {
      throw new HttpsError("invalid-argument", "Token name and symbol are required.");
    }

    const GEMINI_KEY = (await getApiKeyFromFirestore("gemini")) || process.env.GEMINI_API_KEY;
    if (!GEMINI_KEY) throw new HttpsError("internal", "GEMINI_API_KEY not configured");

    const systemPrompt = `You are a world-class smart contract engineer and AI code generator.
Your task is to generate smart contract code for Omni-Mint (Multi-chain).
You MUST output ONLY valid JSON containing the generated code for requested target chains.
Do not wrap it in markdown block quotes (NO \`\`\`json). Just return raw JSON.
Format:
{
  "contracts": {
    "vision": "solidity code here...",
    "base": "solidity code here...",
    "solana": "rust code here...",
    "ton": "tact code here..."
  },
  "explanation": "Brief explanation of the generated code."
}`;

    const userPromptText = `Generate the following ${tokenType || "VRC-20"} token contracts:
Name: ${tokenName}
Symbol: ${tokenSymbol}
Supply: ${initialSupply || "1000000"}
Features enabled: ${isMintable ? "Mintable," : ""} ${isBurnable ? "Burnable," : ""} ${isPausable ? "Pausable," : ""}
Target Chains: ${targetChains ? targetChains.join(", ") : "vision"}

Custom User Request / AI Prompt:
${aiPrompt || "None. Just generate the standard template."}
`;

    let axiosInstance;
    try {
      axiosInstance = require("axios");
    } catch (e) {
      axiosInstance = require("axios");
    }

    const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-pro:generateContent?key=${GEMINI_KEY}`;

    const response = await axiosInstance.post(
      url,
      {
        contents: [{ role: "user", parts: [{ text: userPromptText }] }],
        systemInstruction: { parts: [{ text: systemPrompt }] },
        generationConfig: {
          temperature: 0.2,
          responseMimeType: "application/json",
        },
      },
      { timeout: 60000 },
    );

    const candidate = response.data?.candidates?.[0];
    const textResp = candidate?.content?.parts?.[0]?.text || "{}";

    try {
      const parsed = JSON.parse(textResp);
      return parsed;
    } catch (e) {
      // Request might have returned code block markdown despite instruction
      const cleaned = textResp.replace(/```json/gi, "").replace(/```/g, "").trim();
      try {
        return JSON.parse(cleaned);
      } catch (innerE) {
        return { contracts: { vision: textResp }, explanation: "Failed to parse AI structure. Returning raw." };
      }
    }
  } catch (error) {
    console.error("OmniMint AI Generation error:", error);
    throw new HttpsError("internal", error.message);
  }
});

// ============================================================
// translateDailyTips - Translate tips to target locale via Gemini
// ============================================================
exports.translateDailyTips = onCall({ cors: true, timeoutSeconds: 30, memory: "256MiB" }, async (request) => {
  const { locale, tips } = request.data;
  if (!locale || !tips || !Array.isArray(tips) || tips.length === 0) {
    throw new HttpsError("invalid-argument", "locale and tips[] are required");
  }

  // Supported locales (extend as needed)
  const SUPPORTED = ["ko", "ja", "zh", "es", "fr", "de", "pt", "vi", "th", "id", "ar", "hi", "ru"];
  if (!SUPPORTED.includes(locale)) {
    throw new HttpsError("invalid-argument", `Unsupported locale: ${locale}. Supported: ${SUPPORTED.join(", ")}`);
  }

  const db = admin.firestore();
  const result = {};
  const toTranslate = [];

  // 1. Check Firestore cache for each tip
  for (const tip of tips) {
    try {
      const cached = await db.doc(`daily_tips/${tip.id}/translations/${locale}`).get();
      if (cached.exists) {
        const data = cached.data();
        // Only use cache if source hasn't been updated since translation
        if (data.sourceUpdatedAt >= (tip.updatedAt || 0)) {
          result[tip.id] = { title: data.title, body: data.body };
          continue;
        }
      }
    } catch (e) { /* cache miss, translate */ }
    toTranslate.push(tip);
  }

  // 2. Batch translate missing tips
  if (toTranslate.length > 0) {
    const LOCALE_NAMES = {
      ko: "Korean", ja: "Japanese", zh: "Chinese (Simplified)", es: "Spanish",
      fr: "French", de: "German", pt: "Portuguese", vi: "Vietnamese",
      th: "Thai", id: "Indonesian", ar: "Arabic", hi: "Hindi", ru: "Russian"
    };
    const langName = LOCALE_NAMES[locale] || locale;

    const tipsJson = toTranslate.map(t => ({
      id: t.id,
      title: t.title,
      body: t.body || ""
    }));

    const systemPrompt = `You are a professional translator for a crypto wallet application called Vision Chain. 
Translate the following JSON array of tips from English to ${langName}. 
Keep translations natural, concise, and appropriate for a mobile UI.
Maintain the same JSON structure. Do NOT translate proper nouns like "Vision Chain", "VCN", "RP", etc.
Output ONLY valid JSON array, no markdown, no explanation.`;

    const userInput = JSON.stringify(tipsJson);

    try {
      const translated = await callLLM("gemini-2.0-flash", systemPrompt, userInput);

      // Parse response
      let parsed;
      try {
        const cleaned = translated.replace(/```json\n?/g, "").replace(/```\n?/g, "").trim();
        parsed = JSON.parse(cleaned);
      } catch (parseErr) {
        console.error("[translateDailyTips] Failed to parse LLM response:", parseErr);
        // Return originals for untranslated tips
        for (const tip of toTranslate) {
          result[tip.id] = { title: tip.title, body: tip.body || "" };
        }
        return { translations: result, locale, fromCache: Object.keys(result).length - toTranslate.length };
      }

      // 3. Cache translations and add to result
      const batch = db.batch();
      for (const item of parsed) {
        if (item.id && item.title) {
          result[item.id] = { title: item.title, body: item.body || "" };
          const ref = db.doc(`daily_tips/${item.id}/translations/${locale}`);
          batch.set(ref, {
            title: item.title,
            body: item.body || "",
            locale,
            sourceUpdatedAt: toTranslate.find(t => t.id === item.id)?.updatedAt || Date.now(),
            translatedAt: Date.now()
          });
        }
      }
      await batch.commit();
    } catch (llmErr) {
      console.error("[translateDailyTips] LLM call failed:", llmErr);
      // Fallback: return originals
      for (const tip of toTranslate) {
        result[tip.id] = { title: tip.title, body: tip.body || "" };
      }
    }
  }

  return { translations: result, locale, fromCache: Object.keys(result).length - toTranslate.length };
});

